    /**
     * Try multiple selectors in order, return first match
     * @param {Array|String} selectors - Array of selectors or single selector
     * @param {Element} baseEl - Base element to query from (default: document)
     * @returns {Element|null}
     *
     * @example
     * // Single selector
     * const row = queryMultiple(SELECTORS.STUDIO.VIDEO_ROW);
     *
     * // Array of selectors (tries each until one matches)
     * const createBtn = queryMultiple(SELECTORS.UPLOADER.CREATE_BTN);
     *
     * // With custom base element
     * const checkbox = queryMultiple(SELECTORS.DRAFT_PUBLISHER.NOTIFY_CHECKBOX, modal);
     */
    function queryMultiple(selectors, baseEl = document) {
        if (!selectors) return null;
        if (typeof selectors === 'string') selectors = [selectors];

        for (const selector of selectors) {
            try {
                const el = baseEl.querySelector(selector);
                if (el) return el;
            } catch (e) {
                console.warn(`Invalid selector: ${selector}`, e);
            }
        }
        return null;
    }

    /**
     * Try multiple selectors in order, return all matches from first successful selector
     * @param {Array|String} selectors - Array of selectors or single selector
     * @param {Element} baseEl - Base element to query from (default: document)
     * @returns {NodeList|Array}
     *
     * @example
     * // Get all video rows
     * const rows = queryAllMultiple(SELECTORS.STUDIO.VIDEO_ROW);
     *
     * // Get all options buttons (tries multiple selectors)
     * const optionsBtns = queryAllMultiple(SELECTORS.STUDIO.OPTIONS_BTN);
     */
    function queryAllMultiple(selectors, baseEl = document) {
        if (!selectors) return [];
        if (typeof selectors === 'string') selectors = [selectors];

        for (const selector of selectors) {
            try {
                const elements = baseEl.querySelectorAll(selector);
                if (elements.length > 0) return elements;
            } catch (e) {
                console.warn(`Invalid selector: ${selector}`, e);
            }
        }
        return [];
    }

    /**
     * Wait for an element to appear using multiple selector fallbacks
     * @param {Array|String} selectors - Array of selectors or single selector
     * @param {Element} baseEl - Base element to query from (default: document)
     * @param {Number} timeoutMs - Timeout in milliseconds (default: 5000)
     * @returns {Promise<Element|null>}
     *
     * @example
     * // Wait for upload dialog to appear
     * const dialog = await waitForMultiple(SELECTORS.UPLOADER.UPLOAD_DIALOG, document, 5000);
     */
    /**
     * Wait for an interactive element using multiple selector fallbacks
     * Checks if element exists, is visible, enabled, and not in loading state
     * @param {Array|String} selectors - Array of selectors or single selector
     * @param {Element} baseEl - Base element to query from (default: document)
     * @param {number} timeoutMs - Timeout in milliseconds (default: 5000)
     * @returns {Promise<HTMLElement|null>} The interactive element or null if timeout
     */
    async function waitForInteractive(selectors, baseEl = document, timeoutMs = 5000) {
        if (!selectors) return null;
        if (typeof selectors === 'string') selectors = [selectors];

        const start = Date.now();

        while (Date.now() - start < timeoutMs) {
            for (const selector of selectors) {
                try {
                    const el = baseEl.querySelector(selector);
                    // Check if element exists, is visible, and is enabled
                    if (el && el.offsetParent !== null && !el.disabled) {
                        // Additional check for YouTube's loading states
                        if (!el.hasAttribute('aria-busy') || el.getAttribute('aria-busy') === 'false') {
                            return el;
                        }
                    }
                } catch (e) {
                    console.warn(`Invalid selector in waitForInteractive: ${selector}`, e);
                }
            }
            await new Promise(r => setTimeout(r, 100));
        }

        console.warn(`Timeout: No interactive element found for ${selectors.join(', ')}`);
        return null;
    }

    /**
     * @deprecated Use waitForInteractive instead. This function is kept for backward compatibility.
     * Wait for an element using multiple selector fallbacks (legacy version)
     */
    async function waitForMultiple(selectors, baseEl = document, timeoutMs = 5000) {
        // Delegate to waitForInteractive for better reliability
        return await waitForInteractive(selectors, baseEl, timeoutMs);
    }

    /**
     * Check if an element exists using multiple selector fallbacks
     * @param {Array|String} selectors - Array of selectors or single selector
     * @param {Element} baseEl - Base element to query from (default: document)
     * @returns {Boolean}
     *
     * @example
     * if (existsMultiple(SELECTORS.UPLOADER.UPLOAD_DIALOG)) {
     *     console.log('Upload dialog is present');
     * }
     */
    function existsMultiple(selectors, baseEl = document) {
        if (!selectors) return false;
        if (typeof selectors === 'string') selectors = [selectors];

        return selectors.some(selector => {
            try {
                return baseEl.querySelector(selector) !== null;
            } catch (e) {
                console.warn(`Invalid selector in existsMultiple: ${selector}`, e);
                return false;
            }
        });
    }

