    // --- GLOBAL: Check if there's any stored data to clear for downloader modals ---
    function hasStoredDataToClear() {
        try {
            // Check localStorage
            const hasHistory = localStorage.getItem('yss_downloader_history');
            const hasFailed = localStorage.getItem('yss_downloader_failed');
            const hasVideoStates = localStorage.getItem('yss_downloader_video_states');
            const hasImportedFiles = localStorage.getItem('yss_downloader_imported_files');
            const hasLastPrefetch = localStorage.getItem('yss_downloader_last_prefetch_data');
            const hasImportExport = localStorage.getItem('yss_downloader_import_export_data');

            // Check GM storage if available
            let hasGMData = false;
            if (typeof GM_getValue !== 'undefined') {
                try {
                    const gmVideoStates = GM_getValue('yss_downloader_video_states', null);
                    const gmLastPrefetch = bulkDownloaderState?.lastPrefetchDataKey ? GM_getValue(bulkDownloaderState.lastPrefetchDataKey, null) : null;
                    const gmImportExport = bulkDownloaderState?.importExportKey ? GM_getValue(bulkDownloaderState.importExportKey, null) : null;

                    hasGMData = gmVideoStates || gmLastPrefetch || gmImportExport;
                } catch (e) {
                    log(`[Downloader] Error checking GM storage for data: ${e.message}`, 'warn');
                }
            }

            // Check in-memory arrays
            const hasMemoryData = (typeof downloaderHistory !== 'undefined' && downloaderHistory && downloaderHistory.length > 0) ||
                (typeof downloaderFailedVideos !== 'undefined' && downloaderFailedVideos && downloaderFailedVideos.length > 0) ||
                (typeof downloaderVideoStates !== 'undefined' && downloaderVideoStates && Object.keys(downloaderVideoStates).length > 0) ||
                (typeof bulkDownloaderState !== 'undefined' && bulkDownloaderState && bulkDownloaderState.lastPrefetchData);

            // Check if any data exists
            const hasData = hasHistory || hasFailed || hasVideoStates || hasImportedFiles ||
                hasLastPrefetch || hasImportExport || hasGMData || hasMemoryData;


            return hasData;
        } catch (error) {
            if (typeof log === 'function') {
                log(`[Downloader] Error checking for stored data: ${error.message}`, 'error');
            }
            return false;
        }
    }
    // --- GLOBAL: log function ---
    function log(message, type = 'info') {
        const timestamp = new Date().toLocaleTimeString();
        const fullMessage = `[${timestamp}] ${message}`;
        switch (type) {
            case 'error':
                console.error(fullMessage);
                break;
            case 'warn':
                console.warn(fullMessage);
                break;
            //default: console.log(fullMessage);
        }
        if (logArea) {
            const entry = document.createElement('div');
            entry.className = `yss-log-entry yss-log-${type}`;
            entry.textContent = fullMessage;
            logArea.appendChild(entry);
            logArea.scrollTop = logArea.scrollHeight;
        }

        // Save to persistent log in GM storage
        saveToPersistentLog(message, type);
    }
    // --- GLOBAL: Persistent Log storage ---
    function saveToPersistentLog(message, type = 'info') {
        try {
            const logType = (typeof type === 'string' && type) ? type : 'info';
            // ✅ SECURITY FIX: Use YSS.storage with size limits
            const existingLog = YSS.storage.get('yss_persistent_log', '');
            const timestamp = new Date().toISOString();
            //const formattedMessage = `[${timestamp}] [${type.toUpperCase()}] ${message}\n`;
            const formattedMessage = `[${timestamp}] [${logType.toUpperCase()}] ${message}\n`;
            const newLog = existingLog + formattedMessage;

            // Keep only last 50000 characters to prevent storage overflow
            const maxLength = 50000;
            const trimmedLog = newLog.length > maxLength ? newLog.slice(-maxLength) : newLog;

            // ✅ SECURITY FIX: Check storage size before saving
            try {
                YSS.storage.set('yss_persistent_log', trimmedLog);
            } catch (e) {
                if (e.message && e.message.includes('exceeds limit')) {
                    // Trim log to half size if it exceeds limit
                    const halfLog = trimmedLog.slice(-Math.floor(trimmedLog.length / 2));
                    YSS.storage.set('yss_persistent_log', halfLog);
                    log('[Storage] Log trimmed due to size limit', 'warn');
                } else {
                    throw e;
                }
            }
        } catch (e) {
            console.error('Error saving to persistent log:', e);
        }
    }

    function loadPersistentLog() {
        try {
            const savedLog = YSS.storage.get('yss_persistent_log', '');
            if (savedLog) {
                const logDisplay = document.getElementById('yss-log');
                if (logDisplay) {
                    // Clear existing log
                    logDisplay.textContent = '';

                    // Parse and display saved log
                    const lines = savedLog.split('\n').filter(line => line.trim());
                    lines.forEach(line => {
                        const logEntry = document.createElement('div');
                        logEntry.className = 'yss-log-entry';

                        // Determine type from the log line
                        if (line.includes('[ERROR]')) {
                            logEntry.className += ' yss-log-error';
                        } else if (line.includes('[WARN]')) {
                            logEntry.className += ' yss-log-warn';
                        } else if (line.includes('[SUCCESS]')) {
                            logEntry.className += ' yss-log-success';
                        } else {
                            logEntry.className += ' yss-log-info';
                        }

                        logEntry.textContent = line;
                        logDisplay.appendChild(logEntry);
                    });
                    logDisplay.scrollTop = logDisplay.scrollHeight;
                }
            }
        } catch (e) {
            console.error('Error loading persistent log:', e);
        }
    }

    function clearPersistentLog() {
        try {
            YSS.storage.set('yss_persistent_log', '');
            const logDisplay = document.getElementById('yss-log-area');
            if (logDisplay) {
                logDisplay.textContent = '';
            }
            log("[System] Persistent log cleared", "success");
            alert("[System] Persistent log cleared", "success");
        } catch (e) {
            console.error('Error clearing persistent log:', e);
        }
    }



    // =================================================================================
    // YSS MODAL BUILDER - CENTRALIZED MODAL SYSTEM
    // =================================================================================

    class YSSModalBuilder {
        /**
         * Creates a back button with built-in functionality
         * @param {Function} [onBack] Optional callback when back is clicked
         * @returns {HTMLButtonElement} The configured back button
         */
        createBackButton(onBack) {
            const backBtn = document.createElement('button');
            backBtn.id = 'yss-modal-back';
            backBtn.className = 'yss-btn yss-btn-icon';
            //backBtn.title = 'Go Back';
            backBtn.setAttribute('data-tooltip', 'Return to previous view');

            const backIcon = createIcon('fa-solid fa-arrow-left');
            backBtn.appendChild(backIcon);

            backBtn.addEventListener('click', async () => {
                if (onBack) {
                    await onBack();
                }
                this.close();
            });

            return backBtn;
        }

        /**
         * Creates a toggle stats button with built-in functionality
         * @param {Object} options Configuration options for the toggle button
         * @param {string} options.statsSelector Selector for the stats container (default: '.yss-summary-table')
         * @param {string} options.listSelector Selector for the list container (default: '.yss-videolist-container')
         * @returns {HTMLButtonElement} The configured toggle button
         */
        createToggleStatsButton(options = {}) {
            const {
                statsSelector = '.yss-summary-table',
                listSelector = '.yss-videolist-container'
            } = options;

            const toggleBtn = document.createElement('button');
            toggleBtn.id = 'yss-modal-toggle-stats';
            toggleBtn.className = 'yss-btn yss-btn-secondary';
            //toggleBtn.title = 'Hide Statistics';
            toggleBtn.appendChild(createIcon('fa-solid fa-eye-slash'));

            toggleBtn.addEventListener('click', () => {
                const statsTable = this.elements.modal.querySelector(statsSelector);
                const listContainer = this.elements.modal.querySelector(listSelector);
                const isVisible = !statsTable.classList.contains('hide');

                if (isVisible) {
                    statsTable.classList.add('hide');
                    listContainer?.classList.add('fullview');
                    toggleBtn?.classList.add('yss-btn-clear');
                    toggleBtn.textContent = '';
                    toggleBtn.appendChild(createIcon('fa-solid fa-eye'));
                    //toggleBtn.title = 'Show Statistics';
                } else {
                    statsTable.classList.remove('hide');
                    listContainer?.classList.remove('fullview');
                    toggleBtn?.classList.remove('yss-btn-clear');
                    toggleBtn.textContent = '';
                    toggleBtn.appendChild(createIcon('fa-solid fa-eye-slash'));
                    //toggleBtn.title = 'Hide Statistics';
                }
            });

            return toggleBtn;
        }

        /**
         * Internal: Create a button element from config (copied from ModalBuilder for compatibility)
         * @param {object} config
         * @returns {HTMLButtonElement}
         */
        _createButton(config) {
            const button = document.createElement('button');
            button.className = config.classes ? config.classes.join(' ') : 'yss-btn';
            const buttonSpan = document.createElement('span');
            button.appendChild(buttonSpan);
            if (config.id) {
                button.id = config.id;
            }
            if (config.id && typeof setupButton === 'function') {
                try {
                    setupButton(button, config.id);
                } catch (e) { }
            }
            if (config.text) {
                buttonSpan.appendChild(document.createTextNode(' ' + config.text));
            }
            if (config.onClick) {
                button.onclick = (e) => config.onClick(e, this);
            }
            return button;
        }

        /**
         * Gets the view container element for content
         * @returns {HTMLElement} The modal's view container
         */
        getViewContainer() {
            return this.elements.contentArea;
        }

        /**
         * Updates the counter value in the title
         * @param {number} value The new counter value
         */
        updateCounter(value) {
            // Remove existing counter if value is empty/undefined/null
            if (value === undefined || value === null || value === '') {
                if (this.titleBarElements.counter) {
                    this.titleBarElements.counter.remove();
                    this.titleBarElements.counter = null;
                }
                this.options.counter = undefined;
                return;
            }

            // Update or create counter
            this.options.counter = value;
            if (this.titleBarElements.counter) {
                this.titleBarElements.counter.textContent = `(${value})`;
            } else {
                const counterSpan = document.createElement('span');
                counterSpan.className = 'yss-counter';
                counterSpan.textContent = `(${value})`;
                this.elements.titleH3.appendChild(counterSpan);
                this.titleBarElements.counter = counterSpan;
            }
        }

        /**
         * Gets the current counter value
         * @returns {number|undefined} The current counter value
         */
        getCounter() {
            return this.options.counter;
        }
        /**
         * Set the modal content (string, HTMLElement, or array of these)
         * @param {string|HTMLElement|Array} content
         * @returns {YSSModalBuilder}
         */
        setContent(content) {
            // Clear previous content
            while (this.elements.contentArea.firstChild) {
                this.elements.contentArea.removeChild(this.elements.contentArea.firstChild);
            }

            if (typeof content === 'string') {
                const p = document.createElement('div');
                p.className = 'yss-modal-text';
                p.appendChild(document.createTextNode(content));
                this.elements.contentArea.appendChild(p);
            } else if (Array.isArray(content)) {
                content.forEach(el => {
                    if (el instanceof HTMLElement) {
                        this.elements.contentArea.appendChild(el);
                    } else if (typeof el === 'string') {
                        const p = document.createElement('div');
                        p.className = 'yss-modal-text';
                        p.appendChild(document.createTextNode(el));
                        this.elements.contentArea.appendChild(p);
                    }
                });
            } else if (content instanceof HTMLElement) {
                this.elements.contentArea.appendChild(content);
            }
            return this;
        }
        /**
         * @param {string} title The main title for the modal header.
         * @param {object} [options={}] Configuration options for the modal.
         * @param {string} [options.id='yss-modal-overlay'] A unique ID for the modal.
         * @param {string} [options.maxWidth='600px'] The max-width for the modal content.
         * @param {boolean} [options.isSticky=true] Use the sticky header/footer modal style.
         * @param {boolean} [options.showCloseButton=true] Whether to show the close button.
         */
        constructor(title, options = {}) {
            this.titleText = title;
            this.options = {
                id: 'yss-modal-overlay',
                maxWidth: '600px',
                isSticky: true,
                showCloseButton: true,
                showBackButton: false,
                onBack: null,
                counter: undefined,
                closeOnOverlayClick: true,
                customClasses: null,
                isScrollable: false,
                linkInHeader: null,
                linkInHeaderBtn: null,
                linkInHeaderIcon: null,
                fullScreenBtn: false,
                ...options
            };

            if (typeof this.options.draggable !== 'boolean') {
                this.options.draggable = false;
            }

            // Track all observers for cleanup
            this.activeObservers = [];

            // Core structural elements
            this.elements = {
                overlay: document.createElement('div'),
                modal: document.createElement('div'),
                titleBar: document.createElement('div'),
                titleH3: document.createElement('h3'),
                contentArea: document.createElement('div'), // This is the .yss-modal-view
                actionsBar: document.createElement('div'),
                leftActions: document.createElement('div'),
                rightActions: document.createElement('div'),
            };

            this.onClose = null;
            this.hasBackButton = false;
            this.backButtonAction = null;
            this.counterValue = null;
            this.buttons = []; // Store button configurations

            // Initialize title bar elements
            this.titleBarElements = {
                backButton: null,
                title: null
            };

            this._createBaseStructure();
        }

        _createBaseStructure() {
            this.elements.overlay.id = this.options.id;
            this.elements.overlay.className = 'yss-modal-overlay';

            this.elements.modal.className = 'yss-modal-content';

            if (this.options.isSticky) {
                this.elements.modal.classList.add('yss-sticky-modal');
            }
            if (this.options.isScrollable) {
                this.elements.modal.classList.add('yss-scrollable-modal');
            }


            /*  if (GM_getValue(GM_KEYS.iconsOnlyEnabled, false)) {
                this.elements.modal.classList.add('yss-buttons-notext');
            } */
            // The check for 'yss-buttons-notext' has been moved to the .show() method.

            this.elements.modal.style.maxWidth = this.options.maxWidth;

            if (this.options.customClasses) {
                const classes = Array.isArray(this.options.customClasses) ?
                    this.options.customClasses :
                    this.options.customClasses.split(' '); // Allows 'class1 class2'

                // Use spread syntax to add all classes at once
                this.elements.modal.classList.add(...classes.filter(Boolean));
            }
            // Create title bar with all elements
            this.elements.titleBar.className = 'yss-modal-title';

            // Back button (if enabled)
            if (this.options.showBackButton) {
                const backBtn = document.createElement('button');
                backBtn.className = 'yss-btn yss-btn-icon yss-btn-back';
                const backIcon = document.createElement('i');
                backIcon.className = 'fa-solid fa-arrow-left';
                backBtn.appendChild(backIcon);
                backBtn.addEventListener('click', async () => {
                    if (this.options.onBack) {
                        await this.options.onBack();
                    }
                    this.close();
                });
                this.elements.titleBar.appendChild(backBtn);
                this.titleBarElements.backButton = backBtn;
            }
            if (this.options.fullScreenBtn) {
                this.isFullscreen = false; // ✅ internal state

                const fullScreenButton = document.createElement('button');
                fullScreenButton.className = 'yss-btn yss-btn-icon yss-btn-fullscreen';
                fullScreenButton.dataset.tooltip = 'Fullscreen Mode';
                const fullScreenIcon = createIcon('fa-solid fa-expand');
                fullScreenButton.appendChild(fullScreenIcon);

                fullScreenButton.addEventListener('click', (e) => {
                    e.stopPropagation();
                    this.toggleFullscreenMode();
                });

                // Insert fullscreen button before close button if it exists
                if (this.titleBarElements.closeButton) {
                    this.elements.titleBar.insertBefore(
                        fullScreenButton,
                        this.titleBarElements.closeButton
                    );
                } else {
                    this.elements.titleBar.appendChild(fullScreenButton);
                }

                this.titleBarElements.fullScreenBtn = fullScreenButton;
            }

            if (this.options.linkInHeader) {
                if (this.options.linkInHeaderBtn) {
                    // --- Render as a BUTTON ---
                    this.elements.titleH3.textContent = this.titleText; // Set the main title text first

                    const linkBtn = document.createElement('a');
                    linkBtn.href = this.options.linkInHeader;
                    linkBtn.className = 'yss-btn';
                    linkBtn.target = '_blank';
                    linkBtn.dataset.tooltip = this.options.linkInHeader; // Use the URL for the tooltip

                    if (this.options.linkInHeaderIcon) {
                        linkBtn.appendChild(createIcon(this.options.linkInHeaderIcon));
                    }

                    const btnSpan = document.createElement('span');
                    btnSpan.textContent = this.options.linkInHeaderBtn;
                    linkBtn.appendChild(btnSpan);

                    this.elements.titleH3.appendChild(linkBtn); // Append the button after the title text

                } else {
                    // --- Render as a simple WRAPPED LINK ---
                    const titleLink = document.createElement('a');
                    titleLink.href = this.options.linkInHeader;
                    titleLink.target = '_blank';
                    titleLink.textContent = this.titleText; // The link text IS the title

                    // Add default icon
                    titleLink.appendChild(document.createTextNode(' ')); // Add space before icon
                    titleLink.appendChild(createIcon('fa-solid fa-link'));

                    this.elements.titleH3.appendChild(titleLink); // The link is the only content of the H3
                }
            } else {
                // --- Default behavior: No link ---
                this.elements.titleH3.textContent = this.titleText;
            }

            // Handle counter (this logic can now run after the title/link is set)
            if (this.options.counter !== undefined && this.options.counter !== null && this.options.counter !== '') {
                const counterSpan = document.createElement('span');
                counterSpan.className = 'yss-counter';
                counterSpan.textContent = ` (${this.options.counter})`; // Add space for better looks
                this.elements.titleH3.appendChild(counterSpan);
                this.titleBarElements.counter = counterSpan;
            } else {
                this.titleBarElements.counter = null;
            }

            this.elements.titleBar.appendChild(this.elements.titleH3);

            // Close button (if enabled)
            if (this.options.showCloseButton) {
                const closeBtn = document.createElement('button');
                closeBtn.className = 'yss-btn yss-btn-icon yss-close-btn';
                const closeIcon = document.createElement('i');
                closeIcon.className = 'fa-solid fa-xmark';
                closeBtn.appendChild(closeIcon);
                closeBtn.addEventListener('click', () => this.close());
                this.elements.titleBar.appendChild(closeBtn);
                this.titleBarElements.closeButton = closeBtn;
            }

            this.elements.contentArea.className = 'yss-modal-view';

            this.elements.actionsBar.className = 'yss-modal-actions';
            this.elements.leftActions.className = 'yss-modal-actions-left';
            this.elements.rightActions.className = 'yss-modal-actions-right';

            this.elements.actionsBar.appendChild(this.elements.leftActions);
            this.elements.actionsBar.appendChild(this.elements.rightActions);

            this.elements.modal.appendChild(this.elements.titleBar);
            this.elements.modal.appendChild(this.elements.contentArea);
            this.elements.modal.appendChild(this.elements.actionsBar);
            this.elements.overlay.appendChild(this.elements.modal);

            // Optional draggable behavior
            if (this.options.draggable) {
                this.elements.modal.classList.add('draggable');
                this.elements.overlay.classList.add('transparent');
                this.elements.titleBar.style.cursor = 'move';
                const el = this.elements.modal;
                const handle = this.elements.titleBar;
                let pos1 = 0,
                    pos2 = 0,
                    pos3 = 0,
                    pos4 = 0;

                handle.onmousedown = (e) => {
                    if (e.target && e.target.tagName && e.target.tagName.toLowerCase() === 'button') {
                        return;
                    }
                    e.preventDefault();
                    pos3 = e.clientX;
                    pos4 = e.clientY;
                    document.onmouseup = closeDragElement;
                    document.onmousemove = elementDrag;
                };

                function elementDrag(e) {
                    e.preventDefault();
                    pos1 = pos3 - e.clientX;
                    pos2 = pos4 - e.clientY;
                    pos3 = e.clientX;
                    pos4 = e.clientY;
                    let newTop = el.offsetTop - pos2;
                    let newLeft = el.offsetLeft - pos1;
                    const viewportWidth = window.innerWidth;
                    const viewportHeight = window.innerHeight;
                    const panelWidth = el.offsetWidth;
                    const panelHeight = el.offsetHeight;
                    newLeft = Math.max(0, Math.min(newLeft, viewportWidth - panelWidth));
                    newTop = Math.max(0, Math.min(newTop, viewportHeight - panelHeight));
                    el.style.top = newTop + 'px';
                    el.style.left = newLeft + 'px';
                    el.style.right = 'auto';
                    el.style.bottom = 'auto';
                    el.style.transform = 'none';
                }

                function closeDragElement() {
                    document.onmouseup = null;
                    document.onmousemove = null;
                }
            }
        }
        /**
         * Toggle fullscreen mode for the modal
         */
        toggleFullscreenMode() {
            this.isFullscreen = !this.isFullscreen;

            const modal = this.elements.modal;
            const html = document.documentElement;
            const body = document.body;
            const btn = this.titleBarElements.fullScreenBtn;
            const icon = btn.querySelector('i');

            if (this.isFullscreen) {
                // --- Enter fullscreen ---
                modal.classList.add('yss-fullscreen');
                html.style.overflow = 'hidden';
                body.style.overflow = 'hidden';

                // Disable close on overlay click and ESC key
                this.prevCloseOnOverlayClick = this.options.closeOnOverlayClick;
                this.options.closeOnOverlayClick = false;
                this._removeEscapeHandler(); // temporarily remove ESC handler

                // Change icon and tooltip
                icon.className = 'fa-solid fa-compress';
                btn.dataset.tooltip = 'Normal Mode';

            } else {
                // --- Exit fullscreen ---
                modal.classList.remove('yss-fullscreen');
                html.style.overflow = '';
                body.style.overflow = '';

                // Restore previous close behaviors
                this.options.closeOnOverlayClick = this.prevCloseOnOverlayClick ?? true;
                this._addEscapeHandler(); // restore ESC handler

                icon.className = 'fa-solid fa-expand';
                btn.dataset.tooltip = 'Fullscreen Mode';
            }
        }

        /**
         * Remove escape key handler to prevent accidental close in fullscreen
         */
        _removeEscapeHandler() {
            if (this._escapeHandler) {
                document.removeEventListener('keydown', this._escapeHandler);
                this._escapeHandler = null;
            }
        }

        /**
         * Add escape key handler back when exiting fullscreen
         */
        _addEscapeHandler() {
            this._escapeHandler = (e) => {
                if (e.key === 'Escape' && this.options.closeOnOverlayClick) {
                    this.close(null);
                }
            };
            document.addEventListener('keydown', this._escapeHandler);
        }

        /**
         * Add a back button to the modal title bar
         * @param {Function} onClick The function to call when the back button is clicked
         * @returns {YSSModalBuilder} The modal builder instance for chaining
         */
        addBackButton(onClick) {
            this.hasBackButton = true;
            this.backButtonAction = onClick || (() => this.close('back'));
            return this;
        }

        /**
         * Set a counter value to display in the title
         * @param {number|string} value The counter value to display
         * @returns {YSSModalBuilder} The modal builder instance for chaining
         */
        setCounter(value) {
            this.counterValue = value;
            return this;
        }

        /**
         * Appends a content element or a list of elements to the modal's main view.
         * @param {HTMLElement|HTMLElement[]} content The content element(s) to add.
         * @returns {YSSModalBuilder} The modal builder instance for chaining
         */
        addContent(content) {
            if (Array.isArray(content)) {
                content.forEach(el => this.elements.contentArea.appendChild(el));
            } else if (content instanceof HTMLElement) {
                this.elements.contentArea.appendChild(content);
            }
            return this;
        }

        /**
         * Adds a button to the actions bar.
         * @param {object} config The button configuration.
         * @returns {HTMLButtonElement} The created button element.
         */
        // Method to add buttons to the modal (accepts array or single object)
        addButtons(buttons) {
            if (!Array.isArray(buttons)) buttons = [buttons];
            // Clear existing buttons safely
            while (this.elements.leftActions.firstChild) {
                this.elements.leftActions.removeChild(this.elements.leftActions.firstChild);
            }
            while (this.elements.rightActions.firstChild) {
                this.elements.rightActions.removeChild(this.elements.rightActions.firstChild);
            }

            // Add buttons according to the distribution logic
            buttons.forEach((buttonConfig, index) => {
                const button = this._createButton(buttonConfig);
                if (buttons.length <= 3) {
                    // All buttons go to the left
                    this.elements.leftActions.appendChild(button);
                } else {
                    // First 3 to left, rest to right
                    if (index < 3) {
                        this.elements.leftActions.appendChild(button);
                    } else {
                        this.elements.rightActions.appendChild(button);
                    }
                }
                document.body.appendChild(this.elements.overlay);
                if (typeof setupAllButtons === 'function') {
                    setupAllButtons();
                }
            });
            return this;
        }

        // Compatibility alias with other builder API
        addButton(buttons) {
            return this.addButtons(buttons);
        }

        /**
         * Show the modal and return a promise that resolves when the modal is closed
         * @returns {Promise} A promise that resolves with the close value
         */
        show() {
            return new Promise(resolve => {
                this.onClose = resolve;

                const existingModal = document.getElementById(this.options.id);
                if (existingModal) existingModal.remove();

                // Handle back button action if needed
                if (this.hasBackButton && this.titleBarElements.backButton) {
                    this.titleBarElements.backButton.onclick = (e) => {
                        if (this.backButtonAction) {
                            this.backButtonAction(e, this);
                        } else {
                            this.close('back');
                        }
                    };
                }

                // Update counter if needed
                if (this.counterValue !== null) {
                    this.updateCounter(this.counterValue);
                }

                // 1. Close modal on 'Escape' key press
                /*  const escapeHandler = (e) => {
                     if (e.key === 'Escape') {
                         this.close(null);
                         document.removeEventListener('keydown', escapeHandler);
                     }
                 };
                 document.addEventListener('keydown', escapeHandler); */
                // 1. Close modal on 'Escape' key press

                this._addEscapeHandler();

                // 2. Close modal on overlay click (if enabled)
                if (this.options.closeOnOverlayClick) {
                    this.elements.overlay.classList.add('closable');
                    this.elements.overlay.addEventListener('click', (e) => {
                        if (e.target === this.elements.overlay) {
                            this.close(null);
                        }
                    });
                }

                // 3. SYNC with panel state BEFORE appending to DOM
                const panel = document.getElementById('yss-panel');
                const shouldHaveClass = panel && panel.classList.contains('yss-buttons-notext');
                this.elements.modal.classList.toggle('yss-buttons-notext', shouldHaveClass);

                // 4. Append to DOM
                document.body.appendChild(this.elements.overlay);

                // 5. Setup buttons
                if (typeof setupAllButtons === 'function') {
                    setupAllButtons();
                }
            });
        }

        /**
         * Close the modal with an optional return value
         * @param {any} value The value to resolve the promise with
         */
        close(value = null) {
            // Disconnect all observers
            if (this.activeObservers && this.activeObservers.length > 0) {
                this.activeObservers.forEach(observer => {
                    try {
                        observer.disconnect();
                    } catch (e) {
                        console.warn('[YSSModalBuilder] Error disconnecting observer:', e);
                    }
                });
                this.activeObservers = [];
            }

            // Remove all event listeners
            if (this._escapeHandler) {
                document.removeEventListener('keydown', this._escapeHandler);
                this._escapeHandler = null;
            }

            // Remove overlay from DOM
            if (this.elements.overlay && this.elements.overlay.parentElement) {
                this.elements.overlay.remove();
            }

            // Call onClose callback
            if (this.onClose) {
                this.onClose(value);
            }
        }

        // Compatibility helpers with other builder API
        getModal() {
            return this.elements.modal;
        }

        getOverlay() {
            return this.elements.overlay;
        }
    }

    // Shared modal functions for reuse across all instances
    function closeModal() {
        const modal = document.getElementById('yss-modal-overlay');
        if (modal) {
            modal.remove();
        }
    }



    // ============================================================================
    // TABLE SORTER CLASS (v2.1 - Corrected Initialization and DOM logic)
    // ============================================================================

    class TableSorter {
        /**
         * @param {HTMLTableElement} table The table element to make sortable.
         * @param {object} [initialSort] Optional initial sort configuration.
         * @param {string} [initialSort.key] The key of the column to sort by initially.
         * @param {boolean} [initialSort.reverse=false] True for descending, false for ascending.
         */
        constructor(table, initialSort = {}) {
            this.table = table;
            this.thead = table.querySelector('thead');
            this.tbody = table.querySelector('tbody');
            this.sortableHeaders = [];

            this._initHeaders();
            if (initialSort.key) {
                this.sort(initialSort.key, initialSort.reverse);
            }
        }

        _initHeaders() {
            // *** FIX: Look for the data-sort-key attribute, then add the class and listener ***
            this.thead.querySelectorAll('th[data-sort-key]').forEach(th => {
                console.log('Tablesorting: Initializing...');
                th.classList.add('yss-sortable'); // Add the class for CSS styling
                this.sortableHeaders.push(th);
                th.addEventListener('click', () => {
                    const columnKey = th.dataset.sortKey;
                    // If the clicked header is already active, toggle reverse. Otherwise, don't reverse.
                    const isReversed = th.classList.contains('active') && !th.classList.contains('reverse');
                    this.sort(columnKey, isReversed);
                });
            });
        }

        /**
         * Sorts the table by a specific column.
         * @param {string} columnKey The data-sort-key of the header to sort by.
         * @param {boolean} [reverse=false] Whether to sort in reverse (descending) order.
         */
        sort(columnKey, reverse = false) {
            // Update header classes
            this.sortableHeaders.forEach(th => {
                th.classList.remove('active', 'reverse');
                if (th.dataset.sortKey === columnKey) {
                    th.classList.add('active');
                    if (reverse) {
                        th.classList.add('reverse');
                    }
                }
            });

            const rows = Array.from(this.tbody.querySelectorAll('tr'));

            // Find the actual header element to get its index in the row
            const targetHeader = this.sortableHeaders.find(th => th.dataset.sortKey === columnKey);
            if (!targetHeader) return;

            // *** FIX: Get the correct column index based on the header's position ***
            const columnIndex = Array.from(targetHeader.parentNode.children).indexOf(targetHeader);
            if (columnIndex === -1) return; // Header not found in its row

            rows.sort((a, b) => {
                // Ensure the cells exist before trying to access them
                const aCell = a.children[columnIndex];
                const bCell = b.children[columnIndex];
                if (!aCell || !bCell) return 0;

                // Prioritize data-value attribute for sorting if it exists, otherwise use textContent
                const aText = aCell.dataset.value || aCell.textContent.trim();
                const bText = bCell.dataset.value || bCell.textContent.trim();

                // Check for numeric values for proper numeric sorting
                const aNum = parseFloat(aText);
                const bNum = parseFloat(bText);

                let comparison = 0;
                if (!isNaN(aNum) && !isNaN(bNum)) {
                    comparison = aNum - bNum;
                } else {
                    comparison = aText.localeCompare(bText, undefined, {
                        sensitivity: 'base',
                        numeric: true
                    });
                }

                return reverse ? -comparison : comparison;
            });

            // Re-append the rows to the tbody in the new sorted order. This preserves the elements.
            this.tbody.append(...rows);
        }
    }

    // =================================================================================
    // MODAL PROCESS MANAGER - Manages button states within a running modal process
    // =================================================================================

    class ModalProcessManager {
        constructor(modal, processState, buttonMap, updateStatus) {
            this.modal = modal;
            this.processState = processState;
            this.buttons = buttonMap; // { start: SmartButton, pause: SmartButton, ... }
            this.updateStatus = updateStatus;
            this.updateUI(); // Initial setup
        }

        /**
         * Central UI update function for the modal. Reads the processState
         * and updates all associated buttons automatically.
         */
        updateUI() {
            const {
                isRunning,
                isPaused,
                stop
            } = this.processState;
            const {
                stop: stopBtn,
                pause,
                copy,
                clear
            } = this.buttons;

            // --- NEW, SIMPLER LOGIC ---

            if (isRunning && !stop) {
                // Case 1: Process is active (either running or paused).
                if (isPaused) {
                    this.updateStatus('paused', 'Paused');
                    if (pause) pause.setState('resume');
                } else {
                    this.updateStatus('running', 'Running');
                    if (pause) pause.setState('pause');
                }

                // Buttons state in this case:
                if (stopBtn) stopBtn.setState('stop');
                if (stopBtn) stopBtn.enable();
                if (pause) pause.enable();
                if (copy) copy.disable();
                if (clear) clear.disable();

            } else if (stop) {
                // Case 2: Process has been explicitly stopped by the user.
                this.updateStatus('stopped', 'Stopped');

                // Buttons state in this case:
                if (stopBtn) stopBtn.setState('restart');
                if (stopBtn) stopBtn.enable();
                if (pause) {
                    pause.setState('pause'); // Reset to default
                    pause.disable();
                }
                if (copy) copy.enable();
                if (clear) clear.enable();

            } else {
                // Case 3: Process has finished naturally (isRunning is false, stop is false).
                this.updateStatus('finished', 'Finished');

                // Buttons state in this case:
                if (stopBtn) stopBtn.setState('restart');
                if (stopBtn) stopBtn.enable();
                if (pause) {
                    pause.setState('pause');
                    pause.disable();
                }
                if (copy) copy.enable();
                if (clear) clear.enable();
            }
        }
    }

    // ============================================================================
    //      PROGRESS TRACKER CLASS v3.2 (Fully Self-Contained and Corrected)
    // ============================================================================

    class ProgressTracker {
        /**
         * @param {HTMLElement} button - The SmartButton's DOM element.
         * @param {object} config - The counter configuration object.
         */
        constructor(button, config) {
            if (!button || !button.smartButton) throw new Error("ProgressTracker requires a valid SmartButton element.");
            this.button = button;
            this.config = config;
            this.total = 0;
            this.current = 0;
            this.logListener = null;
        }

        // --- INTERNAL HELPER METHODS (MOVED INSIDE THE CLASS) ---
        _sleep(ms) { return new Promise(resolve => setTimeout(resolve, ms)); }

        async _waitForElement(selector, baseEl = document, timeoutMs = 5000) {
            let timeout = timeoutMs;
            while (timeout > 0) {
                const element = baseEl.querySelector(selector);
                if (element && element.offsetParent !== null) return element;
                await this._sleep(50);
                timeout -= 50;
            }
            return null;
        }

        _click(element) {
            if (!element) return;
            // Using simulateNaturalInteraction is more robust
            simulateNaturalInteraction(element);
        }

        /**
         * Starts the tracker. It will either pre-scan or use a manual total.
         */
        async start() {
            if (!this.config || !this.config.logKeyword) {
                log('[ProgressTracker] Counter not started: missing logKeyword.', 'warn');
                return;
            }

            if (typeof this.config.manualTotal === 'number') {
                this.total = this.config.manualTotal;
                log(`[ProgressTracker] Manual mode started with a total of ${this.total} items.`, 'info');
            } else if (this.config.itemSelector) {
                try {
                    await this.preScanTotal();
                } catch (error) {
                    log(`[ProgressTracker] Error during pre-scan: ${error.message}`, 'error');
                    return;
                }
            } else {
                log('[ProgressTracker] Counter config invalid: missing itemSelector or manualTotal.', 'warn');
                return;
            }

            if (this.total > 0) {
                this.listenForLog();
                this.button.smartButton.updateCounter(0, this.total);
            }
        }

        async preScanTotal() {
            log('[ProgressTracker] Pre-scanning all pages to determine total items...');
            let totalCount = 0;
            let hasNext = true;
            let isFirstPage = true; // Flag to know if we are on the first page

            while (hasNext) {
                // Wait for the current page's rows to be stable before counting
                await this._waitForElement(this.config.itemSelector, document, 5000);
                await this._sleep(500); // Extra pause for stability

                let itemsOnPage = Array.from(document.querySelectorAll(this.config.itemSelector));

                if (this.config.filterFunction) {
                    itemsOnPage = itemsOnPage.filter(this.config.filterFunction);
                }

                totalCount += itemsOnPage.length;
                log(`[ProgressTracker] Found ${itemsOnPage.length} items on this page. Total so far: ${totalCount}`);

                const nextPageButton = await this._waitForElement('ytcp-icon-button#navigate-after:not([disabled])', document, 1000);
                if (nextPageButton) {
                    this._click(nextPageButton);
                    isFirstPage = false; // We have navigated away from the first page
                    await this._sleep(3000);
                } else {
                    hasNext = false;
                }
            }

            log(`[ProgressTracker] Pre-scan complete. Found ${totalCount} total items. Returning to start page...`);

            // --- NEW ROBUST RETURN LOGIC ---
            // Only try to click "First Page" if we actually navigated away from it.
            if (!isFirstPage) {
                const firstPageBtn = await this._waitForElement('ytcp-icon-button#navigate-first:not([disabled])', document, 5000);
                if (firstPageBtn) {
                    this._click(firstPageBtn);
                    // Wait for the first page to be fully loaded and stable again
                    await this._waitForElement(this.config.itemSelector, document, 5000);
                    await this._sleep(2000);
                } else {
                    log('[ProgressTracker] Could not find "First Page" button to return. Manual navigation may be needed if process fails.', 'warn');
                }
            }

            this.total = totalCount;
            this.current = 0;
        }

        listenForLog() {
            if (!logArea || !this.config.logKeyword) return;

            this.logListener = new MutationObserver((mutations) => {
                for (const mutation of mutations) {
                    for (const node of mutation.addedNodes) {
                        if (node.nodeType === 1 && node.textContent && node.textContent.includes(this.config.logKeyword)) {
                            this.current++;
                            this.button.smartButton.updateCounter(this.current, this.total);
                        }
                    }
                }
            });
            this.logListener.observe(logArea, { childList: true });
        }

        flush() {
            if (!logArea || !this.config.logKeyword) return;
            if (this.logListener) this.logListener.disconnect();

            const allLogEntries = logArea.querySelectorAll('.yss-log-entry');
            let finalCount = 0;
            allLogEntries.forEach(entry => {
                if (entry.textContent.includes(this.config.logKeyword)) {
                    finalCount++;
                }
            });

            if (finalCount > this.current) {
                log(`[ProgressTracker] Flushing... Correcting count from ${this.current} to ${finalCount}.`, 'debug');
                this.current = finalCount;
                this.button.smartButton.updateCounter(this.current, this.total);
            }
        }

        stop() {
            if (this.logListener) {
                const mutations = this.logListener.takeRecords();
                this.logListener.disconnect();
                this.logListener = null;

                for (const mutation of mutations) {
                    for (const node of mutation.addedNodes) {
                        if (node.nodeType === 1 && node.textContent && node.textContent.includes(this.config.logKeyword)) {
                            this.current++;
                        }
                    }
                }
            }
            this.flush();

            setTimeout(() => {
                this.button.smartButton.hideCounter();
                this.total = 0;
                this.current = 0;
            }, 500); // Increased delay slightly
        }
    }

    // ============================================================================
    // SMART BUTTON SYSTEM - Centralized Button Management with State Handling
    // ============================================================================

    class SmartButton {
        constructor(config) {
            // Core properties
            this.id = config.id;
            this.text = config.text || '';
            this.icon = config.icon || '';
            this.classes = Array.isArray(config.classes) ? config.classes : ['yss-btn'];
            this.tooltip = config.tooltip || '';
            this.styles = config.styles || {};
            this.handlers = config.handlers || {};

            this.position = config.position || null;

            // State management (optional)
            this.states = config.states || null;
            this.currentState = null;

            // Element reference
            this.element = null;

            // +++ NEW: COUNTER PROPERTIES +++
            this.counterElement = null; // Reference to the <span> holding the counter
            this.showCounter = config.showCounter || false; // Option to enable/disable counter

            // Initialize
            this.initialize();
        }

        initialize() {
            this.element = this.createButtonElement();
            this.setupButton();
            this.setupEventHandlers();
            this.setupStates();

            // Store reference for easy access
            this.element.smartButton = this;
        }

        createButtonElement() {
            const button = document.createElement('button');
            button.id = this.id;
            button.className = this.classes.join(' ');

            // Add icon if specified
            if (this.icon) {
                const icon = document.createElement('i');
                icon.className = this.icon;
                button.appendChild(icon);
            }

            const textSpan = document.createElement('span');
            if (this.text) {
                // Trim the text to remove accidental leading/trailing spaces.
                // Let CSS handle the spacing between icon and text.
                textSpan.textContent = this.text.trim();
            }
            button.appendChild(textSpan);

            // +++ NEW: CREATE COUNTER ELEMENT +++
            if (this.showCounter) {
                this.counterElement = document.createElement('span');
                this.counterElement.className = 'yss-button-counter';
                this.counterElement.style.display = 'none'; // Initially hidden
                button.appendChild(this.counterElement);
            }

            Object.assign(button.style, this.styles);
            if (this.tooltip) {
                button.setAttribute('data-tooltip', this.tooltip);
                //button.title = this.tooltip;
            }
            return button;
        }

        // +++ NEW: COUNTER MANAGEMENT METHODS +++

        /**
         * Updates the button's progress counter.
         * @param {number} current - The current progress number.
         * @param {number} total - The total number of items.
         * @param {string} mode - 'numeric' (e.g., 5/10) or 'percent' (e.g., 50%).
         */
        updateCounter(current, total, mode = 'numeric') {
            if (!this.counterElement) return;

            this.counterElement.style.display = 'inline-block'; // Show the counter
            if (mode === 'percent') {
                const percentage = total > 0 ? Math.round((current / total) * 100) : 0;
                this.counterElement.textContent = `(${percentage}%)`;
            } else { // Default to 'numeric'
                this.counterElement.textContent = `(${current}/${total})`;
            }
        }

        /**
         * Hides the progress counter and clears its text.
         */
        hideCounter() {
            if (!this.counterElement) return;
            this.counterElement.style.display = 'none';
            this.counterElement.textContent = '';
        }

        setupButton() {
            // Apply any additional button-specific logic here
            if (this.handlers.onSetup) {
                this.handlers.onSetup(this.element);
            }
        }

        setupEventHandlers() {
            // Set up click handler
            if (this.handlers.onClick) {
                this.element.onclick = (e) => {
                    //console.log(`SmartButton ${this.id}: Click event triggered`);
                    this.handlers.onClick(e, this);
                };
            }

            // Set up other event handlers
            Object.keys(this.handlers).forEach(eventType => {
                if (eventType !== 'onClick' && eventType !== 'onSetup') {
                    const eventName = eventType.replace('on', '').toLowerCase();
                    this.element.addEventListener(eventName, (e) => {
                        this.handlers[eventType](e, this);
                    });
                }
            });
        }

        setupStates() {
            if (!this.states) return;

            // Set initial state
            const stateNames = Object.keys(this.states);
            if (stateNames.length > 0) {
                this.currentState = stateNames[0];
                this.setState(this.currentState);
            }
        }

        setState(newState) {
            if (!this.states || !this.states[newState]) return;

            const stateConfig = this.states[newState];
            this.currentState = newState;

            // Update icon
            if (stateConfig.icon) {
                const icon = this.element.querySelector('i');
                if (icon) icon.className = stateConfig.icon;
            }

            // Update text
            if (stateConfig.text) {
                const textSpan = this.element.querySelector('span');
                if (textSpan) textSpan.textContent = stateConfig.text;
            }

            // Update classes
            if (stateConfig.classes) {
                this.element.className = stateConfig.classes.join(' ');
            }

            // Update tooltip
            if (stateConfig.tooltip) {
                this.element.setAttribute('data-tooltip', stateConfig.tooltip);
                //this.element.title = stateConfig.tooltip;
            }

            // Update styles
            if (stateConfig.styles) {
                Object.assign(this.element.style, stateConfig.styles);
            }

            console.log(`SmartButton ${this.id}: State changed to ${newState}`);
        }

        nextState() {
            if (!this.states) return;

            const states = Object.keys(this.states);
            const currentIndex = states.indexOf(this.currentState);
            const nextIndex = (currentIndex + 1) % states.length;
            this.setState(states[nextIndex]);
        }


        getElement() { return this.element; }
        enable() { this.element.disabled = false; }
        disable() { this.element.disabled = true; }
        show() { this.element.style.display = ''; }
        hide() { this.element.style.display = 'none'; }
        addClass(className) { this.element.classList.add(className); }
        removeClass(className) { this.element.classList.remove(className); }
        setText(text) {
            const textSpan = this.element.querySelector('span:not(.yss-button-counter)'); // Target only the main text span
            const newText = text ? text.trim() : '';
            if (textSpan) {
                textSpan.textContent = newText;
            } else {
                // This is now a fallback, as the constructor should always create the span.
                const newTextSpan = document.createElement('span');
                newTextSpan.textContent = newText;
                this.element.appendChild(newTextSpan);
            }
        }
        setIcon(iconClass) {
            let icon = this.element.querySelector('i');
            if (!icon) {
                icon = document.createElement('i');
                this.element.insertBefore(icon, this.element.firstChild);
            }
            icon.className = iconClass;
        }
    }

    // Enhanced Smart Button Factory
    function createSmartButton(config) {
        return new SmartButton(config);
    }

    // Bulk Button Creation Helper
    function createSmartButtons(buttonConfigs) {
        const buttons = {};
        Object.keys(buttonConfigs).forEach(key => {
            buttons[key] = createSmartButton(buttonConfigs[key]);
        });
        return buttons;
    }

    // Modal Button Setup Helper - Merged with smart positioning
    function setupModalButtons(modal, buttonConfigs) {
        const buttons = {};
        let leftButtonCount = 0;
        let rightButtonCount = 0;

        Object.keys(buttonConfigs).forEach(key => {
            const config = buttonConfigs[key];
            const button = createSmartButton(config);
            buttons[key] = button;

            // Smart positioning logic with fallback
            if (config.position === 'right') {
                // Explicitly right-positioned buttons
                modal.elements.rightActions.appendChild(button.getElement());
                rightButtonCount++;
            } else if (config.position === 'left') {
                // Explicitly left-positioned buttons
                modal.elements.leftActions.appendChild(button.getElement());
                leftButtonCount++;
            } else {
                // No position specified - use smart fallback
                if (leftButtonCount >= 3) {
                    // If left has 3+ buttons, auto-append to right
                    modal.elements.rightActions.appendChild(button.getElement());
                    rightButtonCount++;
                } else {
                    // Default behavior: append to left
                    modal.elements.leftActions.appendChild(button.getElement());
                    leftButtonCount++;
                }
            }
        });

        return buttons;
    }

    // Enhanced button state management function
    function updateSmartButtonState(buttonId, newState, options = {}) {
        const button = document.getElementById(buttonId);
        if (!button) return;

        if (button.smartButton && button.smartButton.setState) {
            button.smartButton.setState(newState);

            if (options.disabled !== undefined) {
                options.disabled ? button.smartButton.disable() : button.smartButton.enable();
            }
            if (options.visible !== undefined) {
                options.visible ? button.smartButton.show() : button.smartButton.hide();
            }
        } else {
            updateButtonState(buttonId, newState);
        }
    }

    // Smart button state toggle
    function toggleSmartButtonState(buttonId) {
        const button = document.getElementById(buttonId);
        if (!button || !button.smartButton) return;
        button.smartButton.nextState();
    }

    // Helper to enhance number inputs with custom increment/decrement buttons
    function enhanceNumberInput(input) {
        // Check if input is valid and not already enhanced
        if (!input || !(input instanceof HTMLInputElement) || input.type !== 'number') {
            return input;
        }

        // Skip if already wrapped
        if (input.parentElement && input.parentElement.classList.contains('yss-number-input-wrapper')) {
            return input.parentElement;
        }

        // Create wrapper
        const wrapper = document.createElement('div');
        wrapper.className = 'yss-number-input-wrapper';

        // Insert wrapper before input and move input into wrapper
        if (input.parentNode) {
            input.parentNode.insertBefore(wrapper, input);
        }
        wrapper.appendChild(input);

        // Create controls container
        const controls = document.createElement('div');
        controls.className = 'yss-number-input-controls';

        // Create up button
        const upBtn = document.createElement('button');
        upBtn.type = 'button';
        upBtn.className = 'yss-number-btn';
        upBtn.setAttribute('aria-label', 'Increment');
        upBtn.appendChild(createIcon('fa-solid fa-chevron-up'));
        upBtn.addEventListener('click', (e) => {
            e.preventDefault();
            e.stopPropagation();
            input.stepUp();
            input.dispatchEvent(new Event('input', { bubbles: true }));
            input.dispatchEvent(new Event('change', { bubbles: true }));
        });

        // Create down button
        const downBtn = document.createElement('button');
        downBtn.type = 'button';
        downBtn.className = 'yss-number-btn';
        downBtn.setAttribute('aria-label', 'Decrement');
        downBtn.appendChild(createIcon('fa-solid fa-chevron-down'));
        downBtn.addEventListener('click', (e) => {
            e.preventDefault();
            e.stopPropagation();
            input.stepDown();
            input.dispatchEvent(new Event('input', { bubbles: true }));
            input.dispatchEvent(new Event('change', { bubbles: true }));
        });

        // Assemble controls
        controls.appendChild(upBtn);
        controls.appendChild(downBtn);
        wrapper.appendChild(controls);

        return wrapper;
    }

    // Global auto-enhancement system for number inputs
    (function initNumberInputEnhancement() {
        // Track enhanced inputs to avoid duplicates
        const enhancedInputs = new WeakSet();

        // Function to enhance a single input
        function enhanceIfNeeded(input) {
            if (!input || !(input instanceof HTMLInputElement) ||
                input.type !== 'number' ||
                enhancedInputs.has(input)) {
                return;
            }

            try {
                enhanceNumberInput(input);
                enhancedInputs.add(input);
            } catch (e) {
                console.warn('Failed to enhance number input:', e);
            }
        }

        // Enhance all existing number inputs
        function enhanceAllExisting() {
            const numberInputs = document.querySelectorAll('input[type="number"]:not(.yss-number-input-wrapper input)');
            numberInputs.forEach(enhanceIfNeeded);
        }

        // MutationObserver to watch for new number inputs
        const observer = new MutationObserver((mutations) => {
            mutations.forEach((mutation) => {
                mutation.addedNodes.forEach((node) => {
                    if (node.nodeType === Node.ELEMENT_NODE) {
                        // Check if the added node itself is a number input
                        if (node instanceof HTMLInputElement && node.type === 'number') {
                            enhanceIfNeeded(node);
                        }
                        // Check for number inputs within the added node
                        const numberInputs = node.querySelectorAll &&
                            node.querySelectorAll('input[type="number"]:not(.yss-number-input-wrapper input)');
                        if (numberInputs) {
                            numberInputs.forEach(enhanceIfNeeded);
                        }
                    }
                });
            });
        });

        // Store observer reference for cleanup (if needed in future)
        // Note: This observer is global and should remain active, but can be disconnected if needed
        window._yssNumberInputObserver = observer;

        // Re-enhance when modals are opened (watch for modal overlay)
        const modalObserver = new MutationObserver((mutations) => {
            mutations.forEach((mutation) => {
                mutation.addedNodes.forEach((node) => {
                    if (node.nodeType === Node.ELEMENT_NODE) {
                        // Check if a modal overlay was added
                        if (node.id === 'yss-modal-overlay' ||
                            (node.classList && node.classList.contains('yss-modal-overlay')) ||
                            (node.querySelector && node.querySelector('#yss-modal-overlay, .yss-modal-overlay'))) {
                            // Small delay to ensure modal content is fully rendered
                            setTimeout(() => {
                                const modal = node.id === 'yss-modal-overlay' ? node :
                                    node.querySelector('#yss-modal-overlay, .yss-modal-overlay') || node;
                                if (modal) {
                                    const numberInputs = modal.querySelectorAll('input[type="number"]:not(.yss-number-input-wrapper input)');
                                    numberInputs.forEach(enhanceIfNeeded);
                                }
                            }, 50);
                        }
                    }
                });
            });
        });

        // Function to start observers
        function startObservers() {
            const target = document.body || document.documentElement;
            if (!target) return;

            // Start main observer
            observer.observe(target, {
                childList: true,
                subtree: true
            });

            // Start modal observer
            modalObserver.observe(target, {
                childList: true,
                subtree: true
            });
        }

        // Initialize observers when DOM is ready
        if (document.readyState === 'loading') {
            document.addEventListener('DOMContentLoaded', () => {
                startObservers();
                enhanceAllExisting();
            });
        } else {
            // DOM already ready, but body might not exist yet
            if (document.body) {
                startObservers();
                enhanceAllExisting();
            } else {
                // Wait for body to be available
                const bodyCheck = setInterval(() => {
                    if (document.body) {
                        clearInterval(bodyCheck);
                        startObservers();
                        enhanceAllExisting();
                    }
                }, 10);
            }
        }

        // Also enhance on next tick to catch any inputs added during script execution
        setTimeout(enhanceAllExisting, 0);
    })();
    // ============================================================================
    // REFACTOR: UI MASTER BUILDER CLASS
    // ============================================================================
    class UIMasterBuilder {
        constructor(schema) {
            this.schema = schema;
        }

        render() {
            return this._createElement(this.schema);
        }

        _createElement(config) {
            const {
                type
            } = config;
            let element;

            switch (type) {
                case 'container':
                    element = this._createContainer(config);
                    break;
                case 'section':
                    element = this._createSection(config);
                    break;
                case 'button':
                    // We use createSmartButton which returns the DOM element directly
                    element = this._createSmartButton(config);
                    break;
                case 'checkbox':
                    element = this._createCheckbox(config);
                    break;
                case 'toggle':
                    element = this._createToggle(config);
                    break;
                case 'row':
                    element = this._createRow(config);
                    break;
                case 'text': // New type for simple text elements
                    element = this._createText(config);
                    break;
                case 'tabs':
                    element = this._createTabs(config);
                    break;
                case 'custom':
                    element = this._createCustom(config);
                    break;
                default:
                    element = document.createElement('div');
            }

            if (config.children && Array.isArray(config.children)) {
                config.children.forEach(childConfig => {
                    const childElement = this._createElement(childConfig);
                    if (childElement) {
                        element.appendChild(childElement);
                    }
                });
            }

            // Post-creation modifications
            if (config.disabled) {
                element.disabled = true;
            }

            return element;
        }

        _applyCommonProperties(element, config) {
            if (config.id) {
                element.id = config.id;
            }
            if (config.className) {
                element.className = config.className;
            }
            if (config.tooltip) {
                element.setAttribute('data-tooltip', config.tooltip);
            }
        }

        _createContainer(config) {
            const container = document.createElement('div');
            this._applyCommonProperties(container, config);
            return container;
        }

        _createRow(config) {
            const row = document.createElement('div');
            row.className = 'button_row'; // Base class
            if (config.className) { // Append additional classes
                row.className += ' ' + config.className;
            }
            // Apply other properties like ID
            this._applyCommonProperties(row, config);
            return row;
        }
        _createText(config) {
            // Creates a div with text content, applying common properties like id and class.
            const textElement = document.createElement('div');
            this._applyCommonProperties(textElement, config);
            if (config.label) {
                textElement.textContent = config.label;
            }
            return textElement;
        }

        _createSection(config) {
            const section = document.createElement('div');
            this._applyCommonProperties(section, config);
            if (config.title) {
                const title = document.createElement('h3');
                title.textContent = config.title;
                section.appendChild(title);
            }
            return section;
        }

        _createSmartButton(config) {
            const buttonConfig = {
                id: config.id,
                text: config.label,
                icon: config.icon,
                classes: config.className ? config.className.split(' ') : ['yss-btn'],
                tooltip: config.tooltip,
                handlers: {
                    onClick: config.onClick
                },
                states: config.states,
                initialState: config.initialState,
                showCounter: config.showCounter // Pass the option to the SmartButton constructor
            };
            const smartButton = createSmartButton(buttonConfig);
            return smartButton.getElement();
        }

        _createCheckbox(config) {
            // if no wrapper is requested
            const useWrapper = config.wrap !== false && config.noWrapper !== true;

            // Container may be optional
            const container = useWrapper ? document.createElement('div') : document.createDocumentFragment();
            if (useWrapper) {
                container.className = 'data-tooltip yss-button-option-item';
                if (config.className) container.className += ' ' + config.className;
                if (config.tooltip) container.setAttribute('data-tooltip', config.tooltip);
                if (config.tooltipAlign) container.setAttribute('data-tooltip-align', config.tooltipAlign);
            }

            // Label and checkbox
            const label = document.createElement('label');
            label.className = 'yss-checkbox-label';
            if (config.tooltip && !useWrapper) label.setAttribute('data-tooltip', config.tooltip);

            const checkbox = document.createElement('input');
            checkbox.type = 'checkbox';
            checkbox.id = config.id;
            if (config.onChange) checkbox.addEventListener('change', config.onChange);

            label.appendChild(checkbox);
            label.appendChild(document.createTextNode(config.label));

            // Append accordingly
            if (useWrapper) {
                container.appendChild(label);
                makeInputContainerClickable(container);
                return container;
            } else {
                container.appendChild(label);
                return container; // this is just the label (no div)
            }
        }

        /**
         * Creates a toggle switch component with comprehensive state management.
         * @param {Object} config - Configuration object for the toggle
         * @param {string} config.id - ID for the toggle input element
         * @param {string} [config.stateKey] - GM storage key for persisting state
         * @param {boolean} [config.initialState=false] - Initial toggle state (true = active/checked)
         * @param {string} [config.labelA='Off'] - Label for inactive state (shown in tooltip)
         * @param {string} [config.labelB='On'] - Label for active state (shown in tooltip)
         * @param {string} [config.className] - Additional CSS classes for the label container
         * @param {number} [config.size=30] - Size of the toggle in pixels
         * @param {string} [config.circleSize='100%'] - Size of the inner circle (CSS value)
         * @param {string} [config.activeColor] - Custom color for active state
         * @param {Function} [config.onChange] - Callback when toggle state changes (receives event, isChecked, toggleInstance)
         * @param {Function} [config.onActiveProcess] - Optional callback for active process handling
         * @param {string} [config.tooltip] - Base tooltip text (will be appended with state label)
         * @param {boolean} [config.wrap=true] - Whether to wrap in a container div
         * @returns {HTMLElement} The toggle element or container
         */
        _createToggle(config) {
            // Determine if wrapper is needed
            const useWrapper = config.wrap !== false && config.noWrapper !== true;

            // Create container or fragment
            const container = useWrapper ? document.createElement('div') : document.createDocumentFragment();
            if (useWrapper) {
                container.className = 'yss-toggle-container';
                if (config.className) container.className += ' ' + config.className;
            }

            // Create the label element (main toggle wrapper)
            const label = document.createElement('label');
            label.className = 'yss-toggle';
            if (!useWrapper && config.className) {
                label.className += ' ' + config.className;
            }

            // Apply custom sizing via CSS variables
            if (config.size) {
                label.style.setProperty('--yss-toggle-size', `${config.size}px`);
            }
            if (config.circleSize) {
                label.style.setProperty('--yss-toggle-circle-size', config.circleSize);
            }
            if (config.activeColor) {
                label.style.setProperty('--yss-accent-color', config.activeColor);
            }

            // Create the checkbox input
            const checkbox = document.createElement('input');
            checkbox.type = 'checkbox';
            checkbox.id = config.id || `toggle-${Date.now()}`;
            checkbox.name = checkbox.id;

            // Set initial state from GM storage or config
            let initialState = config.initialState || false;
            if (config.stateKey && typeof GM_getValue !== 'undefined') {
                initialState = GM_getValue(config.stateKey, initialState);
            }
            checkbox.checked = initialState;

            // Create the slider span
            const slider = document.createElement('span');
            slider.className = 'yss-toggle-slider';

            // Setup labels for states
            const labelA = config.labelA || 'Off';
            const labelB = config.labelB || 'On';

            // Update tooltip based on current state
            const updateTooltip = (isChecked) => {
                const stateLabel = isChecked ? labelB : labelA;
                const baseTooltip = config.tooltip || 'Toggle';
                const fullTooltip = `${baseTooltip}: ${stateLabel}`;

                const tooltipTarget = useWrapper ? container : label;
                tooltipTarget.setAttribute('data-tooltip', fullTooltip);
                tooltipTarget.setAttribute('alt', fullTooltip);
            };

            // Set initial tooltip
            updateTooltip(checkbox.checked);

            // Create toggle instance object for external access
            const toggleInstance = {
                element: useWrapper ? container : label,
                checkbox: checkbox,
                label: label,
                isChecked: () => checkbox.checked,
                setChecked: (value, triggerChange = false) => {
                    checkbox.checked = value;
                    updateTooltip(value);
                    if (triggerChange && config.onChange) {
                        config.onChange({ target: checkbox }, value, toggleInstance);
                    }
                    if (config.stateKey && typeof GM_setValue !== 'undefined') {
                        GM_setValue(config.stateKey, value);
                    }
                },
                toggle: (triggerChange = false) => {
                    toggleInstance.setChecked(!checkbox.checked, triggerChange);
                },
                enable: () => {
                    checkbox.disabled = false;
                    label.style.opacity = '1';
                    label.style.pointerEvents = 'auto';
                },
                disable: () => {
                    checkbox.disabled = true;
                    label.style.opacity = '0.5';
                    label.style.pointerEvents = 'none';
                },
                show: () => {
                    (useWrapper ? container : label).style.display = '';
                },
                hide: () => {
                    (useWrapper ? container : label).style.display = 'none';
                }
            };

            // Setup change event handler
            checkbox.addEventListener('change', (e) => {
                const isChecked = e.target.checked;

                // Update tooltip
                updateTooltip(isChecked);

                // Save to GM storage if stateKey is provided
                if (config.stateKey && typeof GM_setValue !== 'undefined') {
                    GM_setValue(config.stateKey, isChecked);
                }

                // Handle active process if provided
                if (config.onActiveProcess && typeof config.onActiveProcess === 'function') {
                    config.onActiveProcess(isChecked, toggleInstance);
                }

                // Call onChange callback
                if (config.onChange && typeof config.onChange === 'function') {
                    config.onChange(e, isChecked, toggleInstance);
                }
            });

            // Assemble the toggle structure
            label.appendChild(checkbox);
            label.appendChild(slider);

            // Store reference to toggle instance on the elements
            checkbox.toggleInstance = toggleInstance;
            label.toggleInstance = toggleInstance;
            if (useWrapper) {
                container.toggleInstance = toggleInstance;
            }

            // Append to container or fragment
            if (useWrapper) {
                container.appendChild(label);
                return container;
            } else {
                container.appendChild(label);
                return container;
            }
        }

        // Add this new method inside the UIMasterBuilder class
        _createTabs(config) {
            const mainContainer = document.createElement('div');
            mainContainer.className = 'yss-tabbed';
            if (config.theme) {
                mainContainer.className += ` yss-tabbed-${config.theme}-theme`;
            }

            const tabsWrapper = document.createElement('div');
            tabsWrapper.className = 'yss-tabs-wrapper';

            const tabsScroller = document.createElement('div');
            tabsScroller.className = 'yss-tabs-scroller';

            const tabsList = document.createElement('ul');
            tabsList.className = 'yss-tabs';

            const contentsContainer = document.createElement('div');
            contentsContainer.className = 'yss-tab-contents';

            const _switchTab = (index) => {
                // Deactivate all tabs and content panes within this specific instance
                tabsList.querySelectorAll('.yss-tab').forEach(t => t.classList.remove('active'));
                contentsContainer.querySelectorAll('.yss-tab-content').forEach(c => c.classList.remove('active'));

                // Activate the selected one
                const tabToActivate = tabsList.querySelector(`.yss-tab:nth-of-type(${index + 1})`);
                const contentToActivate = contentsContainer.querySelector(`.yss-tab-content:nth-of-type(${index + 1})`);
                if (tabToActivate) tabToActivate.classList.add('active');
                if (contentToActivate) contentToActivate.classList.add('active');
            };

            config.tabs.forEach((tabConfig, index) => {
                // Create tab label
                const tabLi = document.createElement('li');
                tabLi.className = 'yss-tab';

                const tabLabel = document.createElement('label');
                tabLabel.textContent = tabConfig.label;
                if (tabConfig.icon) tabLabel.prepend(createIcon(tabConfig.icon), ' ');
                tabLabel.addEventListener('click', () => _switchTab(index));

                tabLi.appendChild(tabLabel);
                tabsList.appendChild(tabLi);

                // Create tab content pane
                const contentPane = document.createElement('div');
                contentPane.className = 'yss-tab-content';

                // Recursively build content using the existing builder logic
                if (tabConfig.content && Array.isArray(tabConfig.content)) {
                    tabConfig.content.forEach(childConfig => {
                        contentPane.appendChild(this._createElement(childConfig));
                    });
                }
                contentsContainer.appendChild(contentPane);
            });

            tabsScroller.appendChild(tabsList);
            tabsWrapper.appendChild(tabsScroller);
            mainContainer.append(tabsWrapper, contentsContainer);

            // Set default active tab
            _switchTab(0);

            // --- Scroll Overflow Logic ---
            const leftBtn = createSmartButton({ icon: 'fa-solid fa-chevron-left', classes: ['yss-tabs-scroll-btn', 'left'] }).getElement();
            const rightBtn = createSmartButton({ icon: 'fa-solid fa-chevron-right', classes: ['yss-tabs-scroll-btn', 'right'] }).getElement();
            tabsWrapper.append(leftBtn, rightBtn);

            const checkOverflow = () => {
                const hasOverflow = tabsScroller.scrollWidth > tabsScroller.clientWidth;
                tabsWrapper.classList.toggle('is-scrollable', hasOverflow);
            };

            leftBtn.addEventListener('click', () => { tabsScroller.scrollBy({ left: -200, behavior: 'smooth' }); });
            rightBtn.addEventListener('click', () => { tabsScroller.scrollBy({ left: 200, behavior: 'smooth' }); });

            // Check on resize and after a slight delay for initial render
            new ResizeObserver(checkOverflow).observe(tabsList);
            setTimeout(checkOverflow, 100);

            return mainContainer;
        }


        _createCustom(config) {
            if (config.render && typeof config.render === 'function') {
                return config.render();
            }
            return document.createElement('div');
        }
    }


    // ============================================================================
    // CONTENT BUILDER - Declarative HTML structure creation
    // ============================================================================
    class ContentBuilder {
        constructor(schema) {
            this.schema = schema;
        }

        render() {
            if (Array.isArray(this.schema)) {
                const fragment = document.createDocumentFragment();
                this.schema.forEach(item => fragment.appendChild(this._createElement(item)));
                return fragment;
            }
            return this._createElement(this.schema);
        }

        _createElement(config) {
            const {
                tag = 'div', text, className, children, ...attrs
            } = config;
            const element = document.createElement(tag);

            if (className) {
                element.className = className;
            }
            if (text) {
                element.textContent = text;
            }

            // Set other HTML attributes like 'id', 'href', etc.
            for (const key in attrs) {
                element.setAttribute(key, attrs[key]);
            }

            if (children && Array.isArray(children)) {
                children.forEach(childConfig => {
                    element.appendChild(this._createElement(childConfig));
                });
            }
            return element;
        }
    }
    // ============================================================================
    // BUTTON ICONS AND TOOLTIPS MANAGEMENT SYSTEM
    // ============================================================================

    // Inject FontAwesome CSS
    function injectFontAwesome() {
        // Create a link element to load FontAwesome CSS
        const link = document.createElement('link');
        link.rel = 'stylesheet';
        link.href = 'https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css';
        link.integrity = 'sha512-iecdLmaskl7CVkqkXNQ/ZH/XLlvWZOJyj7Yy7tcenmpD1ypASozpmT/E0iPtmFIB46ZmdtAc9eNBvH0H/ZpiBw==';
        link.crossOrigin = 'anonymous';
        document.head.appendChild(link);
    }

    // Helper function to create FontAwesome icons
    function createIcon(iconClass, size = 'inherit', color = 'currentColor') {
        const icon = document.createElement('i');
        icon.className = iconClass;
        icon.style.fontSize = size;
        icon.style.color = color;
        return icon;
    }

    /**
     * Creates a reusable hamburger dropdown menu for any container element
     * @param {Object} options Configuration options
     * @param {HTMLElement} options.targetElement - The element to add dropdown menu class to (e.g., nav element)
     * @param {boolean} options.onlyInNoTextMode - If true, only show hamburger in no-text mode (yss-buttons-notext)
     * @param {Function} options.onToggle - Optional callback when menu toggles (receives isOpen boolean)
     * @returns {HTMLElement|null} The hamburger element, or null if conditions not met
     */
    function createHamburgerDropdownMenu(options = {}) {
        const { targetElement, onlyInNoTextMode = false, onToggle = null } = options;

        if (!targetElement) {
            console.warn('createHamburgerDropdownMenu: targetElement is required');
            return null;
        }

        // Create hamburger structure FIRST
        const hamburger = document.createElement('span');
        hamburger.className = 'yss-hamburger yss-hamburger--spin yss-js-hamburger';

        // Check initial visibility based on no-text mode
        if (onlyInNoTextMode) {
            const panel = document.getElementById('yss-panel');
            const isNoTextMode = panel && panel.classList.contains('yss-buttons-notext');
            if (!isNoTextMode) {
                hamburger.style.display = ''; // Hide it instead of returning null
            }
        }

        const hamburgerBox = document.createElement('span');
        hamburgerBox.className = 'yss-hamburger-box';

        const hamburgerInner = document.createElement('span');
        hamburgerInner.className = 'yss-hamburger-inner';

        const hamburgerText = document.createElement('strong');
        hamburgerText.textContent = 'Menu';

        hamburgerBox.appendChild(hamburgerInner);
        hamburgerBox.appendChild(hamburgerText);
        hamburger.appendChild(hamburgerBox);

        // State management
        let isOpen = false;
        let outsideClickHandler = null;

        // Function to setup/remove outside click handler
        const setupOutsideClickHandler = () => {
            if (outsideClickHandler) {
                document.removeEventListener('click', outsideClickHandler);
                outsideClickHandler = null;
            }

            if (isOpen) {
                outsideClickHandler = (e) => {
                    if (!hamburger.contains(e.target) && !targetElement.contains(e.target)) {
                        toggleMenu(false);
                    }
                };
                // Add listener after a short delay to avoid immediate closure
                setTimeout(() => {
                    document.addEventListener('click', outsideClickHandler);
                }, 100);
            }
        };

        const toggleMenu = (open) => {
            isOpen = open !== undefined ? open : !isOpen;

            if (isOpen) {
                hamburger.classList.add('is-active');
                targetElement.classList.add('yss-dropdown-menu');
            } else {
                hamburger.classList.remove('is-active');
                targetElement.classList.remove('yss-dropdown-menu');
                // Remove outside click handler when closing
                if (outsideClickHandler) {
                    document.removeEventListener('click', outsideClickHandler);
                    outsideClickHandler = null;
                }
            }

            // Setup outside click handler when opening
            setupOutsideClickHandler();

            if (onToggle && typeof onToggle === 'function') {
                onToggle(isOpen);
            }
        };

        // Click handler for hamburger
        hamburger.addEventListener('click', (e) => {
            e.stopPropagation();
            toggleMenu();
        });

        // Function to attach click handlers to child buttons
        const attachChildButtonHandlers = () => {
            const childButtons = targetElement.querySelectorAll('.yss-btn, button, a');
            childButtons.forEach(button => {
                // Use a data attribute to track if handler is attached
                if (!button.dataset.hamburgerHandlerAttached) {
                    const newHandler = () => {
                        if (isOpen) {
                            toggleMenu(false);
                        }
                    };
                    button.addEventListener('click', newHandler);
                    button.dataset.hamburgerHandlerAttached = 'true';
                }
            });
        };

        // Attach handlers initially
        attachChildButtonHandlers();

        // Observe for dynamically added buttons
        const buttonObserver = new MutationObserver(() => {
            attachChildButtonHandlers();
        });

        buttonObserver.observe(targetElement, {
            childList: true,
            subtree: true
        });

        // Handle no-text mode changes if onlyInNoTextMode is true
        if (onlyInNoTextMode) {
            const observer = new MutationObserver((mutations) => {
                mutations.forEach((mutation) => {
                    if (mutation.type === 'attributes' && mutation.attributeName === 'class') {
                        const panel = document.getElementById('yss-panel');
                        const isNoTextMode = panel && panel.classList.contains('yss-buttons-notext');
                        if (isNoTextMode) {
                            hamburger.style.display = '';
                        } else {
                            hamburger.style.display = '';
                            if (isOpen) {
                                toggleMenu(false);
                            }
                        }
                    }
                });
            });

            const panel = document.getElementById('yss-panel');
            if (panel) {
                observer.observe(panel, { attributes: true, attributeFilter: ['class'] });
            }
        }

        return hamburger;
    }

    /**
     * Updates a toggle icon by reading its state from data-* attributes.
     * The element MUST have 'data-icon-expanded' and 'data-icon-collapsed' attributes.
     * @param {HTMLElement} element The icon container element.
     * @param {boolean} isCollapsed The current state of the panel.
     */
    function updateCollapseIcon(element, isCollapsed) {
        // Get icons from the element's data attributes
        // Provide default fallbacks just in case
        const iconWhenExpanded = element.dataset.iconExpanded || 'fa-solid fa-minus';
        const iconWhenCollapsed = element.dataset.iconCollapsed || 'fa-solid fa-plus';

        element.textContent = '';

        const iconClass = isCollapsed ? iconWhenCollapsed : iconWhenExpanded;
        const icon = createIcon(iconClass);
        element.appendChild(icon);
    }


