    // Function to apply icons and tooltips to a button
    function setupButton(button, buttonId) {
        if (!button || !buttonId) return;

        const config = BUTTON_CONFIG[buttonId];
        if (!config) return;

        // Add tooltip if not already present
        if (!button.hasAttribute('data-tooltip')) {
            button.setAttribute('data-tooltip', config.tooltip);
        }

        // Add icon if not already present
        if (!button.querySelector('i') && config.icon) {
            const icon = createIcon(config.icon);
            button.prepend(icon);
        }
    }

    // Function to update button state (icon, text, classes) for multi-state buttons
    function updateButtonState(buttonId, state, customText = null) {
        const button = document.getElementById(buttonId);
        if (!button) return;

        const config = BUTTON_CONFIG[buttonId];
        if (!config || !config.states || !config.states[state]) return;

        const stateConfig = config.states[state];

        // Update icon
        const icon = button.querySelector('i');
        if (icon && stateConfig.icon) {
            icon.className = stateConfig.icon;
        }

        // Update text (preserve the span structure)
        const textSpan = button.querySelector('span');
        if (textSpan) {
            textSpan.textContent = customText || stateConfig.text;
        } else {
            // Fallback if no span exists
            button.textContent = customText || stateConfig.text;
        }

        // Update classes
        if (stateConfig.classes) {
            // Remove all yss-btn related classes first
            button.className = button.className.replace(/\byss-btn\S*/g, '').trim();
            // Add new classes
            button.className = (button.className + ' ' + stateConfig.classes.join(' ')).trim();
        }

        // Re-apply setupButton to ensure icon and tooltip are properly set
        setupButton(button, buttonId);
    }

    // Function to apply icons and tooltips to all buttons on the page
    function setupAllButtons() {
        // Apply to existing buttons
        Object.keys(BUTTON_CONFIG).forEach(buttonId => {
            const button = document.getElementById(buttonId);
            if (button) {
                setupButton(button, buttonId);
            }
        });

        // Apply to buttons with yss-btn class that might not have IDs
        const yssButtons = document.querySelectorAll('.yss-btn:not([id])');
        yssButtons.forEach(button => {
            // Try to find a matching config based on button text or context
            const buttonText = button.textContent.toLowerCase();
            const buttonClasses = button.className;

            // Match based on common patterns
            if (buttonText.includes('start') && buttonText.includes('navigation')) {
                setupButton(button, 'quick-nav-start');
            } else if (buttonText.includes('pause') && buttonText.includes('running')) {
                setupButton(button, 'quick-nav-pause');
            } else if (buttonText.includes('minimize')) {
                setupButton(button, 'yss-modal-minimize');
            } else if (buttonText.includes('cancel')) {
                setupButton(button, 'yss-modal-cancel');
            } else if (buttonText.includes('confirm')) {
                setupButton(button, 'yss-modal-confirm');
            } else if (buttonText.includes('export')) {
                setupButton(button, 'yss-modal-export');
            } else if (buttonText.includes('clear')) {
                setupButton(button, 'yss-modal-clear-btn');
            } else if (buttonText.includes('copy')) {
                setupButton(button, 'yss-modal-copy');
            } else if (buttonText.includes('view')) {
                setupButton(button, 'yss-modal-view-last-summary');
            } else if (buttonText.includes('summary')) {
                setupButton(button, 'yss-modal-summary');
            } else if (buttonText.includes('progress')) {
                setupButton(button, 'yss-modal-progress');
            } else if (buttonText.includes('import')) {
                setupButton(button, 'yss-import-btn');
            } else if (buttonText.includes('download')) {
                setupButton(button, 'yss-download-btn');
            } else if (buttonText.includes('skip')) {
                setupButton(button, 'yss-skip-btn');
            } else if (buttonText.includes('refresh')) {
                setupButton(button, 'yss-refresh-btn');
            } else if (buttonText.includes('return')) {
                setupButton(button, 'yss-return-btn');
            } else if (buttonText.includes('keep')) {
                setupButton(button, 'yss-keep-btn');
            } else if (buttonText.includes('disable')) {
                setupButton(button, 'yss-disable-btn');
            }
        });

        // Also check for buttons that might have been created but not caught by the above
        const allButtons = document.querySelectorAll('button');
        allButtons.forEach(button => {
            // Skip buttons that already have icons or tooltips
            if (button.querySelector('i') || button.hasAttribute('data-tooltip')) {
                return;
            }

            // Check if it's a yss button that might have been missed
            if (button.className.includes('yss-btn') || (button.id && button.id.startsWith('yss-'))) {
                const buttonText = button.textContent.toLowerCase();

                // Try to match with common patterns
                if (buttonText.includes('start') && buttonText.includes('download')) {
                    setupButton(button, 'yss-modal-start-downloading');
                } else if (buttonText.includes('start') && buttonText.includes('processing')) {
                    setupButton(button, 'yss-modal-start-processing');
                } else if (buttonText.includes('start') && buttonText.includes('replace')) {
                    setupButton(button, 'yss-replace-start-btn');
                } else if (buttonText.includes('clear') && buttonText.includes('history')) {
                    setupButton(button, 'yss-modal-clear-btn');
                } else if (buttonText.includes('copy') && buttonText.includes('summary')) {
                    setupButton(button, 'yss-modal-copy');
                } else if (buttonText.includes('export') && buttonText.includes('summary')) {
                    setupButton(button, 'yss-modal-export');
                } else if (buttonText.includes('export') && buttonText.includes('comparison')) {
                    setupButton(button, 'yss-modal-export');
                } else if (buttonText.includes('clear') && buttonText.includes('data')) {
                    setupButton(button, 'yss-modal-clear-all-data');
                } else if (buttonText.includes('run') && buttonText.includes('pages')) {
                    setupButton(button, 'yss-modal-run-pages');
                }
            }
        });
    }

    // Function to setup a specific button when created
    function setupNewButton(button, buttonId) {
        setupButton(button, buttonId);
    }

    // Function to add a new button configuration dynamically
    function addButtonConfig(buttonId, config) {
        if (buttonId && config && config.icon && config.tooltip) {
            BUTTON_CONFIG[buttonId] = config;

            // Apply to existing button if it exists
            const existingButton = document.getElementById(buttonId);
            if (existingButton) {
                setupButton(existingButton, buttonId);
            }

            return true;
        }
        return false;
    }

    // Function to remove a button configuration
    function removeButtonConfig(buttonId) {
        if (BUTTON_CONFIG[buttonId]) {
            delete BUTTON_CONFIG[buttonId];
            return true;
        }
        return false;
    }

    // Auto-setup buttons when DOM is ready
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', setupAllButtons);
    } else {
        setupAllButtons();
    }

    // --- START OF OPTIMIZATION 2: Reduced Styling Delays ---
    // Setup buttons after shorter delays. The long 2s and 5s delays are removed
    // as the MutationObserver below is more efficient for dynamic content.
    setTimeout(setupAllButtons, 500);
    setTimeout(setupAllButtons, 1200); // A final fallback for very slow elements.

    // Also run periodically to catch any missed buttons
    setInterval(setupAllButtons, 10000);
    // --- END OF OPTIMIZATION 2 ---

    // Use MutationObserver to watch for dynamically created buttons
    const observer = new MutationObserver((mutations) => {
        let shouldSetup = false;

        mutations.forEach((mutation) => {
            if (mutation.type === 'childList') {
                mutation.addedNodes.forEach((node) => {
                    if (node.nodeType === Node.ELEMENT_NODE) {
                        // Check if the added node is a button or contains buttons
                        if (node.tagName === 'BUTTON' || node.querySelector && node.querySelector('button')) {
                            shouldSetup = true;
                        }
                    }
                });
            }
        });

        if (shouldSetup) {
            // Small delay to ensure the DOM is fully updated
            setTimeout(setupAllButtons, 100);
        }
    });

    // Start observing
    observer.observe(document.body, {
        childList: true,
        subtree: true
    });

    // Smart Button System moved to earlier location for proper function availability

    // Global function for testing and manual button setup
    window.setupYSSButtons = setupAllButtons;
    window.setupYSSButton = setupButton;
    window.setupYSSNewButton = setupNewButton;
    window.addYSSButtonConfig = addButtonConfig;
    window.removeYSSButtonConfig = removeButtonConfig;
    window.YSS_BUTTON_CONFIG = BUTTON_CONFIG;

    // Helper function to add icon to button
    function addIconToButton(button, iconClass, position = 'start') {
        const icon = createIcon(iconClass);
        if (position === 'start') {
            button.insertBefore(icon, button.firstChild);
        } else {
            button.appendChild(icon);
        }
        return icon;
    }

    // Helper function to update schedule button with proper icon
    function updateScheduleButtonIcon(button, mode) {
        if (!button || !button.smartButton) return; // Safety check

        const modes = {
            schedule: {
                icon: 'fa-regular fa-calendar-check',
                text: 'Schedule'
            },
            stop: {
                icon: 'fa-solid fa-stop',
                text: 'Stop'
            },
            rename: {
                icon: 'fa-solid fa-pen-to-square',
                text: 'Rename'
            }
        };

        const config = modes[mode];
        if (config) {
            button.smartButton.setIcon(config.icon);
            button.smartButton.setText(config.text);
        }
    }

    // Helper function to update pause button with proper icon
    function updatePauseButtonIcon(button, isPaused) {
        if (!button || !button.smartButton) return; // Safety check

        if (isPaused) {
            button.smartButton.setIcon('fa-solid fa-play');
        } else {
            button.smartButton.setIcon('fa-solid fa-pause');
        }
    }

