    /**
     * A helper to safely update a SmartButton's icon and text.
     * @param {string} buttonId The ID of the button to update.
     * @param {string} iconClass The new FontAwesome icon class.
     * @param {string} text The new text for the button.
     */
    function updateButtonUI(buttonId, iconClass, text) {
        const button = document.getElementById(buttonId);
        if (button && button.smartButton) {
            if (iconClass) {
                button.smartButton.setIcon(iconClass);
            }
            if (text !== undefined) { // Allow setting empty text
                button.smartButton.setText(text);
            }
        }
    }

    // =================================================================================
    // LightBox Manager
    // =================================================================================


    class LightboxManager {
        constructor() {
            this.lightboxEl = null;
            this.overlayEl = null;
            this.imageEl = null;
            this.closeBtn = null;
            this.prevBtn = null;
            this.nextBtn = null;
            this.captionEl = null;
            this.counterEl = null;

            this.currentIndex = 0;
            this.images = [];
            this.isOpen = false;
            this.enabled = GM_getValue(GM_KEYS.lightboxEnabled, true);

            // Scope selectors (similar a TooltipManager)
            this.scopeSelectors = '.yss-readme-container, .yss-modal-overlay, #yss-panel';
            this.imageSelector = 'a.yss-lightbox';

            // Keyboard navigation
            this.boundKeyHandler = this._onKeyDown.bind(this);

            // Lazy initialization - only create elements when first needed
            this._elementsCreated = false;
            this._attachEventListeners();
        }

        enable() {
            this.enabled = true;
            GM_setValue(GM_KEYS.lightboxEnabled, true);
            console.log('Lightbox Enabled');
        }

        disable() {
            this.enabled = false;
            GM_setValue(GM_KEYS.lightboxEnabled, false);
            this.close();
            console.log('Lightbox Disabled');
        }

        toggle() {
            if (this.enabled) {
                this.disable();
            } else {
                this.enable();
            }
            return this.enabled;
        }

        _createLightboxElement() {
            // Check if lightbox already exists to prevent duplicates
            let existingOverlay = document.getElementById('yss-lightbox-overlay');
            if (existingOverlay) {
                this.overlayEl = existingOverlay;
                this.lightboxEl = existingOverlay.querySelector('#yss-lightbox-container');
                this.closeBtn = existingOverlay.querySelector('.yss-lightbox-close');
                this.prevBtn = existingOverlay.querySelector('.yss-lightbox-prev');
                this.nextBtn = existingOverlay.querySelector('.yss-lightbox-next');
                this.imageEl = existingOverlay.querySelector('.yss-lightbox-image');
                this.captionEl = existingOverlay.querySelector('.yss-lightbox-caption');
                this.counterEl = existingOverlay.querySelector('.yss-lightbox-counter');
                return;
            }

            // Overlay
            this.overlayEl = document.createElement('div');
            this.overlayEl.id = 'yss-lightbox-overlay';
            this.overlayEl.className = 'yss-lightbox-overlay';

            // Container
            this.lightboxEl = document.createElement('div');
            this.lightboxEl.id = 'yss-lightbox-container';
            this.lightboxEl.className = 'yss-lightbox-container';

            // Close button
            this.closeBtn = document.createElement('button');
            this.closeBtn.className = 'yss-lightbox-close';
            this.closeBtn.setAttribute('aria-label', 'Close');
            this.closeBtn.appendChild(createIcon('fa-solid fa-xmark'));

            // Previous button
            this.prevBtn = document.createElement('button');
            this.prevBtn.className = 'yss-lightbox-prev';
            this.prevBtn.setAttribute('aria-label', 'Previous');
            this.prevBtn.appendChild(createIcon('fa-solid fa-chevron-left'));

            // Next button
            this.nextBtn = document.createElement('button');
            this.nextBtn.className = 'yss-lightbox-next';
            this.nextBtn.setAttribute('aria-label', 'Next');
            this.nextBtn.appendChild(createIcon('fa-solid fa-chevron-right'));

            // Image element
            this.imageEl = document.createElement('img');
            this.imageEl.className = 'yss-lightbox-image';
            this.imageEl.alt = '';

            // Caption
            this.captionEl = document.createElement('div');
            this.captionEl.className = 'yss-lightbox-caption';

            // Counter
            this.counterEl = document.createElement('div');
            this.counterEl.className = 'yss-lightbox-counter';

            // Assemble
            this.lightboxEl.appendChild(this.closeBtn);
            this.lightboxEl.appendChild(this.prevBtn);
            this.lightboxEl.appendChild(this.nextBtn);
            this.lightboxEl.appendChild(this.imageEl);
            this.lightboxEl.appendChild(this.captionEl);
            this.lightboxEl.appendChild(this.counterEl);

            this.overlayEl.appendChild(this.lightboxEl);
            document.body.appendChild(this.overlayEl);
        }

        _attachEventListeners() {
            // Click handler para imágenes con clase yss-lightbox (delegación de eventos)
            document.body.addEventListener('click', (e) => {
                if (!this.enabled) return;

                const target = e.target.closest(this.imageSelector);
                if (!target) return;

                // Verificar que esté dentro del scope
                const scopedParent = target.closest(this.scopeSelectors);
                if (!scopedParent) return;

                e.preventDefault();
                e.stopPropagation();

                // Lazy initialization - create elements only when first image is clicked
                if (!this._elementsCreated) {
                    this._createLightboxElement();
                    this._attachLightboxEventListeners();
                    this._elementsCreated = true;
                }

                this._collectImagesFromScope(scopedParent);
                const clickedIndex = this.images.findIndex(img => img.element === target);
                this.open(clickedIndex >= 0 ? clickedIndex : 0);
            });
        }

        _attachLightboxEventListeners() {

            // Close button
            this.closeBtn.addEventListener('click', (e) => {
                e.stopPropagation();
                this.close();
            });

            // Navigation buttons
            this.prevBtn.addEventListener('click', (e) => {
                e.stopPropagation();
                this.previous();
            });

            this.nextBtn.addEventListener('click', (e) => {
                e.stopPropagation();
                this.next();
            });

            // Click en overlay para cerrar
            this.overlayEl.addEventListener('click', (e) => {
                if (e.target === this.overlayEl || e.target === this.lightboxEl) {
                    this.close();
                }
            });

            // Prevenir cierre al hacer click en la imagen
            this.imageEl.addEventListener('click', (e) => {
                e.stopPropagation();
            });

            // Touch swipe support
            let touchStartX = 0;
            let touchEndX = 0;

            this.lightboxEl.addEventListener('touchstart', (e) => {
                touchStartX = e.changedTouches[0].screenX;
            }, { passive: true });

            this.lightboxEl.addEventListener('touchend', (e) => {
                touchEndX = e.changedTouches[0].screenX;
                this._handleSwipe(touchStartX, touchEndX);
            }, { passive: true });
        }

        _handleSwipe(startX, endX) {
            const threshold = 50;
            const diff = startX - endX;

            if (Math.abs(diff) < threshold) return;

            if (diff > 0) {
                // Swipe left - next
                this.next();
            } else {
                // Swipe right - previous
                this.previous();
            }
        }

        _onKeyDown(e) {
            if (!this.isOpen) return;

            switch (e.key) {
                case 'Escape':
                    this.close();
                    break;
                case 'ArrowLeft':
                    this.previous();
                    break;
                case 'ArrowRight':
                    this.next();
                    break;
            }
        }

        _collectImagesFromScope(scopeContainer) {
            this.images = [];
            const imageLinks = scopeContainer.querySelectorAll(this.imageSelector);

            imageLinks.forEach(link => {
                const img = link.querySelector('img');
                if (!img) return;

                this.images.push({
                    element: link,
                    src: link.href,
                    alt: img.alt || '',
                    caption: img.alt || link.getAttribute('title') || ''
                });
            });
        }

        open(index = 0) {
            if (!this.enabled || this.images.length === 0) return;

            // Ensure elements are created (safety check)
            if (!this._elementsCreated || !this.overlayEl) {
                this._createLightboxElement();
                this._attachLightboxEventListeners();
                this._elementsCreated = true;
            }

            this.currentIndex = Math.max(0, Math.min(index, this.images.length - 1));
            this.isOpen = true;

            // Show overlay
            this.overlayEl.classList.add('yss-lightbox-visible');

            // Load image
            this._loadImage(this.currentIndex);

            // Update navigation
            this._updateNavigation();

            // Add keyboard listener
            document.addEventListener('keydown', this.boundKeyHandler);

            // Prevent body scroll
            document.body.style.overflow = 'hidden';
        }

        close() {
            if (!this.isOpen) return;

            this.isOpen = false;
            this.overlayEl.classList.remove('yss-lightbox-visible');

            // Remove keyboard listener
            document.removeEventListener('keydown', this.boundKeyHandler);

            // Restore body scroll
            document.body.style.overflow = '';

            // Clear image to free memory
            setTimeout(() => {
                if (!this.isOpen) {
                    this.imageEl.src = '';
                }
            }, 300);
        }

        next() {
            if (this.images.length <= 1) return;

            this.currentIndex = (this.currentIndex + 1) % this.images.length;
            this._loadImage(this.currentIndex);
            this._updateNavigation();
        }

        previous() {
            if (this.images.length <= 1) return;

            this.currentIndex = (this.currentIndex - 1 + this.images.length) % this.images.length;
            this._loadImage(this.currentIndex);
            this._updateNavigation();
        }

        _loadImage(index) {
            const imageData = this.images[index];
            if (!imageData) return;

            // Add loading class
            this.lightboxEl.classList.add('yss-lightbox-loading');

            // Create new image to preload
            const img = new Image();

            img.onload = () => {
                this.imageEl.src = imageData.src;
                this.imageEl.alt = imageData.alt;
                this.captionEl.textContent = imageData.caption;
                this.lightboxEl.classList.remove('yss-lightbox-loading');
            };

            img.onerror = () => {
                this.captionEl.textContent = 'Error loading image';
                this.lightboxEl.classList.remove('yss-lightbox-loading');
            };

            img.src = imageData.src;
        }

        _updateNavigation() {
            // Update counter
            this.counterEl.textContent = `${this.currentIndex + 1} / ${this.images.length}`;

            // Show/hide navigation buttons
            if (this.images.length <= 1) {
                this.prevBtn.style.display = 'none';
                this.nextBtn.style.display = 'none';
                this.counterEl.style.display = 'none';
            } else {
                this.prevBtn.style.display = '';
                this.nextBtn.style.display = '';
                this.counterEl.style.display = '';
            }
        }

        // Preload adjacent images for faster navigation
        preloadAdjacent() {
            if (this.images.length <= 1) return;

            const nextIndex = (this.currentIndex + 1) % this.images.length;
            const prevIndex = (this.currentIndex - 1 + this.images.length) % this.images.length;

            // Preload next
            const nextImg = new Image();
            nextImg.src = this.images[nextIndex].src;

            // Preload previous
            const prevImg = new Image();
            prevImg.src = this.images[prevIndex].src;
        }
    }




    class TooltipManager {
        constructor() {
            // Minimal state tracking
            this.tooltipEl = null;
            this.arrowEl = null;
            this.contentEl = null;
            this.currentTarget = null;
            this.enabled = GM_getValue(GM_KEYS.tooltipsEnabled, true);
            this.showTimeout = null;
            this.hideTimeout = null;
            this.isVisible = false;

            // Optimized configuration with delays
            this.CONFIG = {
                MAX_WIDTH: 300,
                MIN_WIDTH: 80,
                ARROW_SIZE: 8,
                SPACING: 10,
                PADDING: 10,
                SHOW_DELAY: 30, // Reduced delay for faster responsiveness
                HIDE_DELAY: 50   // Reduced hide delay for snappy UI
            };

            this.scopeSelectors = '#yss-panel, .yss-modal-overlay';

            this._createTooltip();
            this._attachEvents();
            if (this.enabled) {
                this._setupTitleConversion();
            }
        }

        // =========================================================================
        // INITIALIZATION
        // =========================================================================

        _createTooltip() {
            // Check if tooltip already exists to prevent duplicates
            let existingTooltip = document.getElementById('yss-tooltip-container');
            if (existingTooltip) {
                this.tooltipEl = existingTooltip;
                this.contentEl = existingTooltip.querySelector('#yss-tooltip-content');
                this.arrowEl = existingTooltip.querySelector('#yss-tooltip-arrow');
                return;
            }

            this.tooltipEl = document.createElement('div');
            this.tooltipEl.id = 'yss-tooltip-container';
            this.tooltipEl.className = 'custom-tooltip';
            this.tooltipEl.setAttribute('role', 'tooltip');
            this.tooltipEl.setAttribute('aria-live', 'polite');
            this.tooltipEl.setAttribute('aria-atomic', 'true');

            this.contentEl = document.createElement('div');
            this.contentEl.id = 'yss-tooltip-content';

            this.arrowEl = document.createElement('div');
            this.arrowEl.id = 'yss-tooltip-arrow';

            this.tooltipEl.append(this.contentEl, this.arrowEl);
            document.body.appendChild(this.tooltipEl);
        }

        _attachEvents() {
            let positionRaf = null;

            // Optimized event delegation with delays for better UX
            const handleMouseEnter = (e) => {
                if (!this.enabled) return;

                const target = e.target.closest('[data-tooltip], [data-tooltip-func]');
                if (!target || !target.closest(this.scopeSelectors)) return;

                // Clear any pending hide
                if (this.hideTimeout) {
                    clearTimeout(this.hideTimeout);
                    this.hideTimeout = null;
                }

                // Set show delay to reduce sensitivity
                if (this.showTimeout) clearTimeout(this.showTimeout);
                this.showTimeout = setTimeout(() => {
                    this._show(target);
                    this.showTimeout = null;
                }, this.CONFIG.SHOW_DELAY);
            };

            const handleMouseLeave = (e) => {
                if (!this.enabled || !this.currentTarget) return;

                const target = e.target.closest('[data-tooltip], [data-tooltip-func]');
                if (target === this.currentTarget) {
                    // Clear pending show
                    if (this.showTimeout) {
                        clearTimeout(this.showTimeout);
                        this.showTimeout = null;
                    }

                    // Set hide delay for smooth transitions
                    if (this.hideTimeout) clearTimeout(this.hideTimeout);
                    this.hideTimeout = setTimeout(() => {
                        this._hide();
                        this.hideTimeout = null;
                    }, this.CONFIG.HIDE_DELAY);
                }
            };

            // Keyboard accessibility support
            const handleFocus = (e) => {
                if (!this.enabled) return;

                const target = e.target.closest('[data-tooltip], [data-tooltip-func]');
                if (!target || !target.closest(this.scopeSelectors)) return;

                // Immediate show on focus for accessibility
                if (this.showTimeout) clearTimeout(this.showTimeout);
                this._show(target);
            };

            const handleBlur = (e) => {
                if (!this.enabled || !this.currentTarget) return;

                const target = e.target.closest('[data-tooltip], [data-tooltip-func]');
                if (target === this.currentTarget) {
                    // Immediate hide on blur
                    if (this.hideTimeout) clearTimeout(this.hideTimeout);
                    this._hide();
                }
            };

            // Global keyboard dismissal
            const handleKeyDown = (e) => {
                if (e.key === 'Escape' && this.isVisible) {
                    this._hide();
                    // Return focus to target if possible
                    if (this.currentTarget && this.currentTarget.focus) {
                        this.currentTarget.focus();
                    }
                }
            };

            // Use mouseover/mouseout with optimized handlers
            document.addEventListener('mouseover', handleMouseEnter, true);
            document.addEventListener('mouseout', handleMouseLeave, true);

            // Focus/blur for keyboard navigation
            document.addEventListener('focusin', handleFocus, true);
            document.addEventListener('focusout', handleBlur, true);

            // Global keyboard dismissal
            document.addEventListener('keydown', handleKeyDown);

            // Hide on scroll/click - prevents tooltip from staying visible during interactions
            document.addEventListener('scroll', () => this._hide(), { passive: true, capture: true });
            document.addEventListener('mousedown', (e) => {
                // Don't hide if clicking on tooltip itself (for persistent tooltips)
                if (!this.tooltipEl.contains(e.target)) {
                    this._hide();
                }
            }, { passive: true, capture: true });

            // Throttled reposition on window resize
            let resizeTimeout;
            window.addEventListener('resize', () => {
                clearTimeout(resizeTimeout);
                resizeTimeout = setTimeout(() => {
                    if (this.currentTarget && this.isVisible) {
                        if (positionRaf) cancelAnimationFrame(positionRaf);
                        positionRaf = requestAnimationFrame(() => {
                            this._position(this.currentTarget);
                        });
                    }
                }, 100);
            }, { passive: true });
        }

        _setupTitleConversion() {
            // Initial conversion - only within scope containers
            const containers = document.querySelectorAll(this.scopeSelectors);
            containers.forEach(container => {
                this._convertTitles(container);
            });

            // Optimized observer - only watches title attribute changes
            this.observer = new MutationObserver((mutations) => {
                for (const m of mutations) {
                    if (m.type === 'attributes' && m.target.title) {
                        this._convertTitle(m.target);
                    } else if (m.type === 'childList') {
                        m.addedNodes.forEach(node => {
                            if (node.nodeType === 1 && node.closest(this.scopeSelectors)) {
                                this._convertTitles(node);
                            }
                        });
                    }
                }
            });

            containers.forEach(container => {
                this.observer.observe(container, {
                    childList: true,
                    subtree: true,
                    attributes: true,
                    attributeFilter: ['title']
                });
            });
        }

        _convertTitles(root) {
            if (root.title) this._convertTitle(root);
            root.querySelectorAll('[title]').forEach(el => this._convertTitle(el));
        }

        _convertTitle(el) {
            if (el.title && !el.dataset.tooltip) {
                el.dataset.tooltip = el.title;
                el.removeAttribute('title');
                // Add ARIA attributes for accessibility
                el.setAttribute('aria-describedby', 'yss-tooltip-container');
            }
        }

        _restoreTitles() {
            document.querySelectorAll('[data-tooltip]').forEach(el => {
                if (el.dataset.tooltip && !el.dataset.tooltipFunc) {
                    el.title = el.dataset.tooltip;
                    delete el.dataset.tooltip;
                    el.removeAttribute('aria-describedby');
                }
            });
        }

        // =========================================================================
        // SHOW/HIDE
        // =========================================================================

        _show(target) {
            if (target === this.currentTarget && this.isVisible) return;

            this.currentTarget = target;

            // Get tooltip content
            const content = this._getContent(target);
            if (!content) {
                this._hide();
                return;
            }

            // Set content (string or HTMLElement)
            this.contentEl.textContent = '';
            if (typeof content === 'string') {
                this.contentEl.textContent = content;
            } else {
                this.contentEl.appendChild(content);
            }

            // Update ARIA label
            this.tooltipEl.setAttribute('aria-label', typeof content === 'string' ? content : content.textContent || '');

            // Position immediately for smooth animation
            this._position(target);

            // Use requestAnimationFrame for smooth class transition
            requestAnimationFrame(() => {
                this.tooltipEl.classList.add('yss-tooltip-visible');
                this.isVisible = true;
            });
        }

        _hide() {
            // Clear any pending timeouts
            if (this.showTimeout) {
                clearTimeout(this.showTimeout);
                this.showTimeout = null;
            }
            if (this.hideTimeout) {
                clearTimeout(this.hideTimeout);
                this.hideTimeout = null;
            }

            this.tooltipEl.classList.remove('yss-tooltip-visible');
            this.tooltipEl.removeAttribute('aria-label');
            this.currentTarget = null;
            this.isVisible = false;
        }

        _getContent(target) {
            // Try custom function first (data-tooltip-func)
            const funcName = target.dataset.tooltipFunc;
            if (funcName && typeof window[funcName] === 'function') {
                try {
                    const result = window[funcName](target);
                    if (result) return result;
                } catch (e) {
                    console.error('Tooltip function error:', e);
                }
            }

            // Fallback to simple text (data-tooltip)
            const text = target.dataset.tooltip;
            return text && text.trim() ? text : null;
        }

        // =========================================================================
        // OPTIMIZED POSITIONING
        // =========================================================================

        _position(target) {
            const tRect = target.getBoundingClientRect();

            // Minimize reflows by batching style reads
            const ttRect = this.tooltipEl.getBoundingClientRect();

            // Get interactive elements that tooltip should avoid
            const obstacles = this._getInteractiveObstacles(target);

            // Calculate available space in each direction
            const space = {
                top: tRect.top - this.CONFIG.PADDING,
                bottom: window.innerHeight - tRect.bottom - this.CONFIG.PADDING,
                left: tRect.left - this.CONFIG.PADDING,
                right: window.innerWidth - tRect.right - this.CONFIG.PADDING
            };

            // Determine optimal placement with collision avoidance
            let placement = this._findBestPlacement(tRect, ttRect, space, obstacles);

            // Calculate final position
            const pos = this._calculatePosition(placement, tRect, ttRect);

            // Final collision check and adjustment
            const adjustedPos = this._avoidCollisions(pos, ttRect, obstacles);

            // Apply rounded position with transform for better performance and to prevent blurriness
            const finalX = Math.round(adjustedPos.x);
            const finalY = Math.round(adjustedPos.y);
            this.tooltipEl.style.transform = `translate(${finalX}px, ${finalY}px)`;
            this.tooltipEl.className = `custom-tooltip yss-placement-${placement}`;

            // Position arrow pointing to target center
            this._positionArrow(placement, tRect, adjustedPos, ttRect);
        }

        _getInteractiveObstacles(target) {
            const obstacles = [];

            // Find parent button-with-dropdown container
            const container = target.closest('.yss-button-with-dropdown');
            if (!container) return obstacles;

            // Get the dropdown menu (.yss-button-options)
            const dropdown = container.querySelector('.yss-button-options');
            if (dropdown) {
                const dropdownRect = dropdown.getBoundingClientRect();
                // Only consider if visible
                if (dropdownRect.width > 0 && dropdownRect.height > 0) {
                    obstacles.push({
                        rect: dropdownRect,
                        priority: 'high' // High priority to avoid
                    });
                }
            }

            // Get sibling buttons and interactive elements
            const siblings = container.querySelectorAll('button, input, .yss-button-option-item');
            siblings.forEach(el => {
                if (el === target) return; // Skip self
                const rect = el.getBoundingClientRect();
                if (rect.width > 0 && rect.height > 0) {
                    obstacles.push({
                        rect: rect,
                        priority: 'medium'
                    });
                }
            });

            return obstacles;
        }

        _findBestPlacement(tRect, ttRect, space, obstacles) {
            // Try placements in priority order
            const placements = ['top', 'bottom', 'right', 'left'];
            const scores = {};

            for (const placement of placements) {
                // Check if fits in available space
                const fits = this._placementFits(placement, space, ttRect);
                if (!fits) {
                    scores[placement] = -1000;
                    continue;
                }

                // Calculate position for this placement
                const pos = this._calculatePosition(placement, tRect, ttRect);

                // Check collisions
                const collisionPenalty = this._calculateCollisionPenalty(pos, ttRect, obstacles);

                // Score based on space available and collisions
                const spaceScore = this._getSpaceScore(placement, space);
                scores[placement] = spaceScore - collisionPenalty;
            }

            // Return placement with highest score
            let bestPlacement = 'top';
            let bestScore = scores.top;
            for (const placement in scores) {
                if (scores[placement] > bestScore) {
                    bestScore = scores[placement];
                    bestPlacement = placement;
                }
            }

            return bestPlacement;
        }

        _placementFits(placement, space, ttRect) {
            if (placement === 'top') return space.top >= ttRect.height + this.CONFIG.SPACING;
            if (placement === 'bottom') return space.bottom >= ttRect.height + this.CONFIG.SPACING;
            if (placement === 'left') return space.left >= ttRect.width + this.CONFIG.SPACING;
            if (placement === 'right') return space.right >= ttRect.width + this.CONFIG.SPACING;
            return false;
        }

        _getSpaceScore(placement, space) {
            if (placement === 'top') return space.top;
            if (placement === 'bottom') return space.bottom;
            if (placement === 'left') return space.left;
            if (placement === 'right') return space.right;
            return 0;
        }

        _calculateCollisionPenalty(pos, ttRect, obstacles) {
            let penalty = 0;
            const tooltipBounds = {
                left: pos.x,
                right: pos.x + ttRect.width,
                top: pos.y,
                bottom: pos.y + ttRect.height
            };

            for (const obstacle of obstacles) {
                const overlap = this._calculateOverlap(tooltipBounds, obstacle.rect);
                if (overlap > 0) {
                    // Heavy penalty for overlapping
                    const multiplier = obstacle.priority === 'high' ? 500 : 200;
                    penalty += overlap * multiplier;
                }
            }

            return penalty;
        }

        _calculateOverlap(rect1, rect2) {
            const overlapX = Math.max(0, Math.min(rect1.right, rect2.right) - Math.max(rect1.left, rect2.left));
            const overlapY = Math.max(0, Math.min(rect1.bottom, rect2.bottom) - Math.max(rect1.top, rect2.top));
            return overlapX * overlapY;
        }

        _avoidCollisions(pos, ttRect, obstacles) {
            const adjustedPos = { ...pos };
            const tooltipBounds = {
                left: pos.x,
                right: pos.x + ttRect.width,
                top: pos.y,
                bottom: pos.y + ttRect.height
            };

            // Try to shift tooltip away from obstacles
            for (const obstacle of obstacles) {
                const overlap = this._calculateOverlap(tooltipBounds, obstacle.rect);
                if (overlap > 0) {
                    // Calculate best shift direction
                    const shifts = {
                        left: obstacle.rect.left - tooltipBounds.right - 5,
                        right: obstacle.rect.right - tooltipBounds.left + 5,
                        up: obstacle.rect.top - tooltipBounds.bottom - 5,
                        down: obstacle.rect.bottom - tooltipBounds.top + 5
                    };

                    // Choose smallest shift
                    const minShift = Object.entries(shifts).reduce((min, [dir, val]) => {
                        return Math.abs(val) < Math.abs(min.val) ? { dir, val } : min;
                    }, { dir: 'left', val: shifts.left });

                    // Apply shift
                    if (minShift.dir === 'left' || minShift.dir === 'right') {
                        adjustedPos.x += minShift.val;
                    } else {
                        adjustedPos.y += minShift.val;
                    }

                    // Update bounds for next iteration
                    tooltipBounds.left = adjustedPos.x;
                    tooltipBounds.right = adjustedPos.x + ttRect.width;
                    tooltipBounds.top = adjustedPos.y;
                    tooltipBounds.bottom = adjustedPos.y + ttRect.height;
                }
            }

            // Ensure still within viewport
            const minX = this.CONFIG.PADDING;
            const maxX = window.innerWidth - this.CONFIG.PADDING - ttRect.width;
            const minY = this.CONFIG.PADDING;
            const maxY = window.innerHeight - this.CONFIG.PADDING - ttRect.height;

            adjustedPos.x = Math.max(minX, Math.min(maxX, adjustedPos.x));
            adjustedPos.y = Math.max(minY, Math.min(maxY, adjustedPos.y));

            return adjustedPos;
        }

        _calculatePosition(placement, tRect, ttRect) {
            const pos = { x: 0, y: 0 };

            // Viewport boundaries with padding
            const minX = this.CONFIG.PADDING;
            const maxX = window.innerWidth - this.CONFIG.PADDING - ttRect.width;
            const minY = this.CONFIG.PADDING;
            const maxY = window.innerHeight - this.CONFIG.PADDING - ttRect.height;

            // Target center points
            const centerX = tRect.left + tRect.width / 2;
            const centerY = tRect.top + tRect.height / 2;

            if (placement === 'top' || placement === 'bottom') {
                // Vertical placement
                pos.y = placement === 'top'
                    ? tRect.top - ttRect.height - this.CONFIG.SPACING
                    : tRect.bottom + this.CONFIG.SPACING;

                // Clamp to viewport bounds
                pos.y = Math.max(minY, Math.min(maxY, pos.y));

                // Center horizontally relative to target
                pos.x = centerX - ttRect.width / 2;
                pos.x = Math.max(minX, Math.min(maxX, pos.x));

            } else {
                // Horizontal placement
                pos.x = placement === 'left'
                    ? tRect.left - ttRect.width - this.CONFIG.SPACING
                    : tRect.right + this.CONFIG.SPACING;

                // Clamp to viewport bounds
                pos.x = Math.max(minX, Math.min(maxX, pos.x));

                // Center vertically relative to target
                pos.y = centerY - ttRect.height / 2;
                pos.y = Math.max(minY, Math.min(maxY, pos.y));
            }

            return pos;
        }

        _positionArrow(placement, tRect, ttPos, ttRect) {
            // Calculate target center
            const centerX = tRect.left + tRect.width / 2;
            const centerY = tRect.top + tRect.height / 2;
            const arrow = this.CONFIG.ARROW_SIZE;

            if (placement === 'top' || placement === 'bottom') {
                // Arrow on horizontal axis - point to target horizontally
                let x = centerX - ttPos.x - arrow;
                // Clamp arrow within tooltip bounds
                x = Math.max(arrow, Math.min(ttRect.width - arrow * 3, x));
                this.arrowEl.style.left = `${Math.round(x)}px`; // Rounded for crispness
                this.arrowEl.style.top = '';
            } else {
                // Arrow on vertical axis - point to target vertically
                let y = centerY - ttPos.y - arrow;
                // Clamp arrow within tooltip bounds
                y = Math.max(arrow, Math.min(ttRect.height - arrow * 3, y));
                this.arrowEl.style.top = `${Math.round(y)}px`; // Rounded for crispness
                this.arrowEl.style.left = '';
            }
        }

        // =========================================================================
        // PUBLIC API
        // =========================================================================

        enable() {
            this.enabled = true;
            GM_setValue(GM_KEYS.tooltipsEnabled, true);
            this._setupTitleConversion();
        }

        disable() {
            this.enabled = false;
            GM_setValue(GM_KEYS.tooltipsEnabled, false);
            this._hide();
            this._restoreTitles();
            if (this.observer) {
                this.observer.disconnect();
                this.observer = null;
            }
        }

        toggle() {
            this.enabled ? this.disable() : this.enable();
            return this.enabled;
        }

        // For custom/programmatic tooltips
        showCustom(anchor, content, options = {}) {
            const tempTarget = anchor;
            tempTarget.dataset.tooltip = typeof content === 'string' ? content : '';

            // Clear any pending timeouts for immediate show
            if (this.showTimeout) {
                clearTimeout(this.showTimeout);
                this.showTimeout = null;
            }
            if (this.hideTimeout) {
                clearTimeout(this.hideTimeout);
                this.hideTimeout = null;
            }

            this._show(tempTarget);

            // If content is not a string, append it as HTMLElement
            if (typeof content !== 'string') {
                this.contentEl.textContent = '';
                this.contentEl.appendChild(content);
            }

            // Make tooltip interactive if persistent
            if (options.persistent) {
                this.tooltipEl.style.pointerEvents = 'auto';
            }

            // Add custom class if provided
            if (options.className) {
                this.tooltipEl.classList.add(options.className);
            }
        }

        hideCustom() {
            this.tooltipEl.style.pointerEvents = 'none';
            this.tooltipEl.className = 'custom-tooltip';
            this._hide();
        }
    }



    const originalTooltips = {
        schedule: 'Start/Stop Automated Scheduling of unlisted videos',
        rename: 'Start/Stop Automated Renaming of unlisted, Premiere and Draft videos',
        unlist: 'Bulk Change to Unlisted the Premiere/scheduled Videos',
        unDraft: 'Automatically publish all Draft videos as Unlisted'
    };
    // --- GLOBAL: Url Observer ---
    let urlObserverInitialized = false;

    function observeUrlChanges() {
        if (urlObserverInitialized) return;

        // The function to execute when a URL change is detected
        const onUrlChange = () => {
            // A small delay ensures that any DOM updates related to the navigation have a chance to complete.
            setTimeout(updateButtonStatesBasedOnURL, 200);

            // Check if we should run auto-check on edit pages (ONLY on Studio)
            if (window.location.hostname.includes('studio.youtube.com')) {
                const autoCheckEnabled = GM_getValue('yss_auto_check_enabled', true);
                if (autoCheckEnabled && window.location.pathname.includes('/video/') && window.location.pathname.includes('/edit')) {
                    log("[AutoCheck] URL changed to edit page. Starting automatic notification check...", "info");
                    // Small delay to ensure page is loaded
                    setTimeout(() => {
                        checkNotificationCheckboxOnEditPage();
                    }, 3000);
                }
            }
        };

        // Wrap history.pushState to detect programmatic navigation
        const originalPushState = history.pushState;
        history.pushState = function (...args) {
            const result = originalPushState.apply(this, args);
            onUrlChange();
            return result;
        };

        // Wrap history.replaceState as well, as it can also change the URL
        const originalReplaceState = history.replaceState;
        history.replaceState = function (...args) {
            const result = originalReplaceState.apply(this, args);
            onUrlChange();
            return result;
        };

        // Listen for the 'popstate' event, which fires on browser back/forward button clicks
        window.addEventListener('popstate', onUrlChange);

        urlObserverInitialized = true;
        //log('URL change observer initialized.', 'success');
    }

    function updateButtonStatesBasedOnURL() {
        if (!startStopBtn || !unlistBtn || !publishDraftsBtn) {
            // log('UI buttons not ready for state update.', 'warn');
            return;
        }

        const buttons = [{
            el: startStopBtn,
            key: 'schedule'
        },
        {
            el: unlistBtn,
            key: 'unlist'
        },
        {
            el: publishDraftsBtn,
            key: 'unDraft'
        }
        ];

        const disabledTooltips = {
            schedule: "Enable by filtering your content by 'Unlisted' visibility.",
            unlist: "Enable by filtering your content by 'Scheduled' visibility.",
            unDraft: "Enable by filtering your content by 'Draft' visibility."
        };

        const renameCb = document.getElementById('yss-rename-only-cb');
        const renameLabel = renameCb.closest('.yss-checkbox-label');

        const disableNotifCb = document.getElementById('yss-disable-notif-cb');
        const disableNotifLabel = disableNotifCb.closest('.yss-checkbox-label');

        const disableAllButtons = () => {
            buttons.forEach(btnInfo => {
                btnInfo.el.disabled = true;
                btnInfo.el.setAttribute('data-tooltip', disabledTooltips[btnInfo.key]);
            });
            if (renameCb) renameCb.disabled = true;
            if (renameLabel) renameLabel.style.opacity = '0.5';
            if (disableNotifCb) disableNotifCb.disabled = true;
            if (disableNotifLabel) disableNotifLabel.style.opacity = '0.5';
        };

        disableAllButtons();

        try {
            const urlParams = new URLSearchParams(window.location.search);
            const filterParam = urlParams.get('filter');
            if (!filterParam) return;

            const decodedFilter = decodeURIComponent(filterParam);
            const filterArray = JSON.parse(decodedFilter);
            const visibilityFilter = filterArray.find(f => f.name === 'VISIBILITY');
            if (!visibilityFilter || !visibilityFilter.value || visibilityFilter.value.length === 0) return;

            const visibilityValue = visibilityFilter.value[0];

            switch (visibilityValue) {
                case 'UNLISTED':
                    log("Content Filter active: UNLISTED");
                    startStopBtn.disabled = false;
                    updateScheduleButtonIcon(startStopBtn, 'schedule');
                    startStopBtn.setAttribute('data-tooltip', originalTooltips.schedule);
                    schedulerState.renameOnlyMode = false;
                    if (renameCb) renameCb.disabled = false;
                    if (renameCb) renameCb.checked = false;

                    if (renameLabel) renameLabel.style.opacity = '1';
                    if (disableAllNotifsBtn) disableAllNotifsBtn.disabled = false;
                    break;
                case 'DRAFT':
                    log("Content Filter active: DRAFT");
                    startStopBtn.disabled = false;
                    startStopBtn.setAttribute('data-tooltip', originalTooltips.rename);
                    updateScheduleButtonIcon(startStopBtn, 'rename');
                    if (renameCb) renameCb.disabled = true;
                    if (renameCb) renameCb.checked = true;
                    if (renameLabel) renameLabel.style.opacity = '1';
                    schedulerState.renameOnlyMode = true;
                    if (disableNotifCb) disableNotifCb.disabled = false;
                    if (disableNotifLabel) disableNotifLabel.style.opacity = '1';
                    //draftPublisherState.disableNotifMode = false;
                    publishDraftsBtn.disabled = false;
                    publishDraftsBtn.setAttribute('data-tooltip', originalTooltips.unDraft);
                    if (disableAllNotifsBtn) disableAllNotifsBtn.disabled = true;
                    break;
                case 'HAS_SCHEDULE':
                    log("Content Filter active: HAS_SCHEDULE");
                    unlistBtn.disabled = false;
                    unlistBtn.setAttribute('data-tooltip', originalTooltips.unlist);
                    startStopBtn.disabled = false;
                    startStopBtn.setAttribute('data-tooltip', originalTooltips.rename);
                    updateScheduleButtonIcon(startStopBtn, 'rename');
                    if (renameCb) renameCb.disabled = true;
                    if (renameCb) renameCb.checked = true;
                    if (renameLabel) renameLabel.style.opacity = '1';
                    schedulerState.renameOnlyMode = true;
                    if (disableNotifCb) disableNotifCb.disabled = true;
                    if (disableNotifCb) disableNotifCb.checked = false;
                    if (disableNotifLabel) disableNotifLabel.style.opacity = '0.5';
                    if (disableAllNotifsBtn) disableAllNotifsBtn.disabled = false;

                    //draftPublisherState.disableNotifMode = false;
                    break;
                case 'PRIVATE':
                    log("Content Filter active: PRIVATE");
                    startStopBtn.disabled = false;
                    startStopBtn.setAttribute('data-tooltip', originalTooltips.rename);
                    updateScheduleButtonIcon(startStopBtn, 'rename');
                    if (renameCb) renameCb.disabled = true;
                    if (renameCb) renameCb.checked = true;
                    if (renameLabel) renameLabel.style.opacity = '1';
                    schedulerState.renameOnlyMode = true;
                    publishDraftsBtn.disabled = false;
                    publishDraftsBtn.setAttribute('data-tooltip', originalTooltips.unDraft);
                    break;


            }

            const visibilitySelect = document.getElementById('yss-visibility-filter-select');

            if (visibilitySelect) {
                if (visibilityValue) {
                    // If a filter is active in the URL, set the dropdown to match it
                    visibilitySelect.value = visibilityValue;
                } else {
                    // If no filter is active, reset to the default placeholder
                    visibilitySelect.selectedIndex = 0;
                }
            }
        } catch (error) {

            disableAllButtons();
        }
    }

