    // =================================================================================

    /**
     * Sets up a show/hide toggle for a single password input field.
     * @param {HTMLInputElement} input The password input element.
     */
    function setupPasswordToggle(input) {
        // Prevent double-wrapping if the observer fires multiple times
        if (input.parentElement.classList.contains('yss-password-wrapper')) {
            return;
        }

        // Create wrapper
        const wrapper = document.createElement('div');
        wrapper.classList.add('yss-password-wrapper');

        // Insert wrapper and move the input inside it
        input.parentNode.insertBefore(wrapper, input);
        wrapper.appendChild(input);

        // Create the toggle button
        const button = document.createElement('button');
        button.type = 'button';
        button.className = 'yss-btn yss-btn-icon yss-password-toggle';
        button.setAttribute('aria-label', 'Show password');
        button.dataset.tooltip = 'Show/Hide Key';

        // Add Font Awesome icon using your existing helper
        const icon = createIcon('fa-solid fa-eye');
        button.appendChild(icon);

        // Append button to the wrapper
        wrapper.appendChild(button);

        // Add the toggle functionality
        button.addEventListener('click', (e) => {
            e.preventDefault();
            e.stopPropagation();
            const isPassword = input.type === 'password';
            input.type = isPassword ? 'text' : 'password';
            icon.className = `fa-solid ${isPassword ? 'fa-eye-slash' : 'fa-eye'}`;
            button.setAttribute('aria-label', isPassword ? 'Hide password' : 'Show password');
        });
    }

    /**
     * Scans a given DOM node and its children for password inputs and sets them up.
     * @param {Node} rootNode The element to scan within.
     */
    function scanForPasswordInputs(rootNode) {
        // Check if the root node itself is a password input
        if (rootNode.matches && rootNode.matches('input[type="password"]')) {
            setupPasswordToggle(rootNode);
        }
        // Find all password inputs within the root node
        const passwordInputs = rootNode.querySelectorAll('input[type="password"]');
        passwordInputs.forEach(setupPasswordToggle);
    }


    /**
     * Calculates the percentage of the slider's value and updates the background size
     * of the linear gradient defined in your CSS.
     * @param {HTMLInputElement} slider The range input element.
     */
    function updateRangeProgressBackground(slider) {
        const min = parseFloat(slider.min) || 0;
        const max = parseFloat(slider.max) || 100;
        const value = parseFloat(slider.value) || 0;

        // Calculate the percentage filled (e.g., 50%)
        const percentage = ((value - min) / (max - min)) * 100;

        // Update ONLY the background-size style property using the calculated percentage.
        // The rest of the gradient styling is handled by your existing CSS file.
        // We set the width of the *first part* of the gradient (the accent color part)
        // and let the second part (log-bg) fill the rest.
        slider.style.backgroundSize = `${percentage}% 100%`;
    }

    /**
     * Sets up dynamic background progress handling for a single range input field
     * matching your specific selector.
     * @param {HTMLInputElement} input The range input element.
     */
    function setupRangeSliderProgress(input) {
        // Check if the handler has already been initialized on this element
        if (input.classList.contains('yss-range-progress-initialized')) {
            return;
        }

        // Initial background update when the element is found
        updateRangeProgressBackground(input);

        // Add event listener for real-time updates when the value changes
        input.addEventListener('input', (e) => {
            updateRangeProgressBackground(e.target);
        });

        // Mark as initialized to prevent re-running setup
        input.classList.add('yss-range-progress-initialized');
    }

    /**
     * Scans a given DOM node and its children for the specific range inputs and sets them up.
     * @param {Node} rootNode The element to scan within.
     */
    function scanForRangeSlidersProgress(rootNode) {
        // Define the specific selector you already use in your CSS
        const selector = '.yss-modal-content.yss-batch .yss-form-block input[type="range"]';

        // Check if the root node itself matches the selector
        if (rootNode.matches && rootNode.matches(selector)) {
            setupRangeSliderProgress(rootNode);
        }

        // Find all matching inputs within the root node
        const rangeInputs = rootNode.querySelectorAll(selector);
        rangeInputs.forEach(setupRangeSliderProgress);
    }



