    // --- Panel Draggable Functionality (Optimized with Side-Sticking) ---
    function makeDraggable(el, handle, keyPosX, keyPosY) {
        let isDragging = false;
        let rafId = null;
        let initialRect = null;
        let initialMouseX = 0;
        let currentMouseX = 0;
        let initialMouseY = 0;
        let currentMouseY = 0;
        let isStuckToSide = false;
        let stuckSide = null; // 'left' or 'right'
        const SNAP_THRESHOLD = 50; // pixels from edge to trigger snap
        const STICK_ZONE = 30; // pixels from edge to consider "stuck"

        // Cache for panel dimensions (updated only when needed)
        let cachedPanelWidth = 0;
        let cachedPanelHeight = 0;
        let cachedViewportWidth = 0;
        let cachedViewportHeight = 0;
        let savedWidth = null; // Store original width when sticking
        let savedHeight = null; // Store original height when sticking

        // Function to update cached dimensions
        const updateCachedDimensions = () => {
            const rect = el.getBoundingClientRect();
            cachedPanelWidth = rect.width;
            cachedPanelHeight = rect.height;
            cachedViewportWidth = window.innerWidth;
            cachedViewportHeight = window.innerHeight;
        };

        // Function to check if panel should stick to side
        const checkSideStick = (left) => {
            // Update dimensions if needed
            if (cachedPanelWidth === 0) {
                updateCachedDimensions();
            }

            const distanceToLeft = left;
            const distanceToRight = cachedViewportWidth - left - cachedPanelWidth;

            // Check if close enough to left edge (within stick zone)
            if (distanceToLeft <= STICK_ZONE && distanceToLeft >= -10) {
                return 'left';
            }
            // Check if close enough to right edge (within stick zone)
            if (distanceToRight <= STICK_ZONE && distanceToRight >= -10) {
                return 'right';
            }
            return null;
        };

        // Function to apply side-sticking
        const applySideStick = (side) => {
            if (el.classList.contains('collapsed')) return; // Don't stick if collapsed

            isStuckToSide = true;
            stuckSide = side;

            // Save current dimensions if not already saved
            if (savedWidth === null) {
                savedWidth = cachedPanelWidth;
                savedHeight = cachedPanelHeight;
            }

            // Get appropriate width based on mode - use min-width to ensure content fits
            const isNoTextMode = el.classList.contains('yss-buttons-notext');
            const computedStyle = window.getComputedStyle(el);
            const minWidth = isNoTextMode ? '380px' : '650px';
            // Allow width to grow if content needs more space, but respect max-width from CSS
            const maxWidthFromCSS = computedStyle.maxWidth;
            const maxWidth = maxWidthFromCSS && maxWidthFromCSS !== 'none' ? maxWidthFromCSS : (isNoTextMode ? '500px' : '800px');

            // Apply side-stick styles
            el.style.top = '0px';
            el.style.bottom = '0px';
            el.style.height = '100vh';
            el.style.maxHeight = '100vh';
            el.style.minWidth = minWidth;
            el.style.width = 'auto'; // Allow width to be flexible
            el.style.maxWidth = maxWidth;
            el.style.transform = ''; // Clear any transform to prevent overflow
            el.style.willChange = 'auto'; // Reset will-change

            if (side === 'left') {
                el.style.left = '0px';
                el.style.right = 'auto';
            } else {
                el.style.right = '0px';
                el.style.left = 'auto';
            }

            el.classList.add('stuck-to-side', `stuck-${side}`);

            // Update cached dimensions after applying side-stick
            updateCachedDimensions();
        };

        // Function to release from side-sticking
        const releaseSideStick = () => {
            if (!isStuckToSide) return;

            isStuckToSide = false;
            stuckSide = null;

            // Restore saved dimensions or use defaults
            if (savedWidth !== null) {
                el.style.width = savedWidth + 'px';
                el.style.minWidth = '';
                savedWidth = null;
            } else {
                const isNoTextMode = el.classList.contains('yss-buttons-notext');
                el.style.width = isNoTextMode ? '380px' : '650px';
                el.style.minWidth = '';
            }

            if (savedHeight !== null) {
                el.style.height = savedHeight + 'px';
                savedHeight = null;
            } else {
                el.style.height = 'auto';
            }

            // Restore max-height from CSS (don't restrict resizing - only prevent overflow)
            // Remove inline max-height to allow CSS and user resizing
            el.style.maxHeight = '';
            el.style.maxWidth = '';
            el.style.bottom = 'auto';
            el.style.right = 'auto';

            el.classList.remove('stuck-to-side', 'stuck-left', 'stuck-right');

            // Clear stuck state from storage
            GM_setValue(keyPosX + '_stuck', '');
        };

        // Function to dynamically adjust panel height based on viewport position
        // Only called when NOT stuck to side and NOT dragging
        const adjustPanelHeight = (top, left) => {
            // Skip if stuck to side or collapsed
            if (isStuckToSide || el.classList.contains('collapsed')) return;

            // Get current dimensions
            const rect = el.getBoundingClientRect();
            const currentPanelHeight = rect.height;

            // Calculate available space from current position
            const availableHeight = cachedViewportHeight - top;

            // Get the panel's max-height from CSS (if set) - but don't restrict resizing
            const computedStyle = window.getComputedStyle(el);
            const maxHeightCSS = computedStyle.maxHeight;
            let maxHeight = cachedViewportHeight - 20; // Default: viewport - 20px margin

            // Parse CSS max-height if it's a calc() or percentage
            if (maxHeightCSS && maxHeightCSS !== 'none') {
                if (maxHeightCSS.includes('calc')) {
                    maxHeight = cachedViewportHeight - 20;
                } else if (maxHeightCSS.includes('vh')) {
                    const vhValue = parseFloat(maxHeightCSS);
                    maxHeight = (cachedViewportHeight * vhValue) / 100;
                } else if (maxHeightCSS.includes('px')) {
                    maxHeight = parseFloat(maxHeightCSS);
                }
            }

            // Only prevent overflow, don't restrict resizing
            // Only set max-height if panel would overflow viewport
            // This allows user to resize freely, but prevents overflow
            if (top + currentPanelHeight > cachedViewportHeight - 10) {
                // Panel would overflow, set max-height to prevent overflow only
                const constrainedHeight = Math.max(
                    availableHeight - 10,
                    200 // Minimum height
                );
                // Only set max-height if it's less than current height to prevent overflow
                // Don't restrict if user is resizing to make it larger
                if (currentPanelHeight > constrainedHeight) {
                    el.style.maxHeight = constrainedHeight + 'px';
                }
            } else {
                // Panel fits, remove inline max-height to allow free resizing
                // CSS max-height will still apply from stylesheet
                el.style.maxHeight = '';
            }
        };

        // Optimized drag function using requestAnimationFrame
        const performDrag = () => {
            if (!isDragging) return;

            const deltaX = currentMouseX - initialMouseX;
            const deltaY = currentMouseY - initialMouseY;

            // Calculate new position from initial rect
            let newLeft = initialRect.left + deltaX;
            let newTop = initialRect.top + deltaY;

            // Update cached dimensions if viewport might have changed
            if (cachedViewportWidth !== window.innerWidth || cachedViewportHeight !== window.innerHeight) {
                updateCachedDimensions();
            }

            // Check if we should stick to a side (only check, don't apply yet)
            const shouldStick = checkSideStick(newLeft);

            // If we're in the stick zone, snap to the edge for visual feedback
            if (shouldStick) {
                if (shouldStick === 'left') {
                    newLeft = 0;
                } else {
                    newLeft = cachedViewportWidth - cachedPanelWidth;
                }
            }

            // Constrain to viewport bounds - ALWAYS constrain to prevent overflow
            newLeft = Math.max(0, Math.min(newLeft, cachedViewportWidth - cachedPanelWidth));
            newTop = Math.max(0, Math.min(newTop, cachedViewportHeight - cachedPanelHeight));

            // Calculate transform deltas
            let deltaTransformX = newLeft - initialRect.left;
            let deltaTransformY = newTop - initialRect.top;

            // Ensure transform doesn't cause overflow - constrain transform itself
            const maxTransformX = cachedViewportWidth - initialRect.left;
            const maxTransformY = cachedViewportHeight - initialRect.top;
            const minTransformX = -initialRect.left;
            const minTransformY = -initialRect.top;

            deltaTransformX = Math.max(minTransformX, Math.min(deltaTransformX, maxTransformX));
            deltaTransformY = Math.max(minTransformY, Math.min(deltaTransformY, maxTransformY));

            // Apply position using transform for better performance (GPU accelerated)
            el.style.transform = `translate(${deltaTransformX}px, ${deltaTransformY}px)`;
            el.style.willChange = 'transform';

            // DO NOT adjust height during drag to prevent flickering
            // Height adjustments only happen after drag ends

            // Continue animation loop
            rafId = requestAnimationFrame(performDrag);
        };

        handle.onmousedown = (e) => {
            // Prevent dragging from input elements inside the header if any
            if (e.target !== handle && e.target !== handle.querySelector('.yss-header-title')) return;
            e.preventDefault();
            e.stopPropagation();

            // Initialize drag state
            isDragging = true;

            // Check if we're currently stuck to a side
            isStuckToSide = el.classList.contains('stuck-to-side');
            if (isStuckToSide) {
                stuckSide = el.classList.contains('stuck-left') ? 'left' : 'right';
            }

            // If stuck, release first to allow free dragging
            if (isStuckToSide) {
                releaseSideStick();
                // Update dimensions after releasing
                updateCachedDimensions();
            }

            initialRect = el.getBoundingClientRect();
            initialMouseX = e.clientX;
            initialMouseY = e.clientY;
            currentMouseX = e.clientX;
            currentMouseY = e.clientY;

            // Cache initial dimensions
            updateCachedDimensions();

            // Unset right/bottom styles if they exist (for initial positioning)
            if (el.style.right !== 'auto' || el.style.bottom !== 'auto') {
                el.style.right = 'auto';
                el.style.bottom = 'auto';
            }

            // Get current position (accounting for any existing transform)
            const currentRect = el.getBoundingClientRect();
            // Ensure position is within viewport before starting drag
            const constrainedTop = Math.max(0, Math.min(currentRect.top, cachedViewportHeight - cachedPanelHeight));
            const constrainedLeft = Math.max(0, Math.min(currentRect.left, cachedViewportWidth - cachedPanelWidth));

            el.style.top = constrainedTop + 'px';
            el.style.left = constrainedLeft + 'px';
            el.style.transform = '';

            // Update initialRect to the constrained position
            initialRect = el.getBoundingClientRect();

            // Add dragging class for CSS styling
            el.classList.add('dragging');

            // Use passive event listeners for better performance
            document.addEventListener('mousemove', handleMouseMove, { passive: false });
            document.addEventListener('mouseup', closeDragElement, { once: true });

            // Start animation loop
            rafId = requestAnimationFrame(performDrag);
        };

        const handleMouseMove = (e) => {
            if (!isDragging) return;
            e.preventDefault();
            currentMouseX = e.clientX;
            currentMouseY = e.clientY;
        };

        function closeDragElement() {
            if (!isDragging) return;

            isDragging = false;

            // Cancel animation frame
            if (rafId !== null) {
                cancelAnimationFrame(rafId);
                rafId = null;
            }

            // Remove event listeners
            document.removeEventListener('mousemove', handleMouseMove);
            document.removeEventListener('mouseup', closeDragElement);

            // Remove dragging class
            el.classList.remove('dragging');

            // Get final position (transform is still applied)
            const finalRect = el.getBoundingClientRect();
            // Constrain final position to viewport to prevent overflow
            const finalTop = Math.max(0, Math.min(finalRect.top, cachedViewportHeight - cachedPanelHeight));
            const finalLeft = Math.max(0, Math.min(finalRect.left, cachedViewportWidth - cachedPanelWidth));

            // Check if we should stick to side based on final position
            const shouldStick = checkSideStick(finalLeft);

            if (shouldStick) {
                // Apply side-stick with smooth transition
                requestAnimationFrame(() => {
                    applySideStick(shouldStick);
                    // Save position and stuck state
                    GM_setValue(keyPosX, el.style.left || '0px');
                    GM_setValue(keyPosY, el.style.top || '0px');
                    GM_setValue(keyPosX + '_stuck', shouldStick);
                });
            } else {
                // Release from side if we were stuck
                if (isStuckToSide) {
                    releaseSideStick();
                }

                // Convert transform back to top/left for persistence
                el.style.transform = '';
                el.style.willChange = 'auto';
                el.style.top = finalTop + 'px';
                el.style.left = finalLeft + 'px';

                // Final height adjustment (after position is set, only if not stuck)
                requestAnimationFrame(() => {
                    if (!isStuckToSide) {
                        const rect = el.getBoundingClientRect();
                        adjustPanelHeight(rect.top, rect.left);
                    }
                });

                // Save the final position using the provided GM keys
                GM_setValue(keyPosX, el.style.left);
                GM_setValue(keyPosY, el.style.top);
                // Clear stuck state
                GM_setValue(keyPosX + '_stuck', '');
            }
        }

        // Restore stuck state on initialization
        const restoreStuckState = () => {
            const savedStuckSide = GM_getValue(keyPosX + '_stuck', '');
            if (savedStuckSide === 'left' || savedStuckSide === 'right') {
                updateCachedDimensions();
                isStuckToSide = true;
                stuckSide = savedStuckSide;
                requestAnimationFrame(() => {
                    applySideStick(savedStuckSide);
                });
            }
        };

        // Restore stuck state after a short delay to ensure DOM is ready
        setTimeout(restoreStuckState, 100);

        // Handle panel resize (CSS resize property)
        let panelResizeObserver = null;
        let panelResizeTimeout = null;

        const handlePanelResize = () => {
            if (isDragging || isStuckToSide) return;

            clearTimeout(panelResizeTimeout);
            panelResizeTimeout = setTimeout(() => {
                updateCachedDimensions();
                const rect = el.getBoundingClientRect();
                // Only adjust max-height if it would overflow, don't restrict resizing
                adjustPanelHeight(rect.top, rect.left);
            }, 50);
        };

        // Use ResizeObserver to detect panel resize (from CSS resize property)
        if (window.ResizeObserver) {
            panelResizeObserver = new ResizeObserver(handlePanelResize);
            panelResizeObserver.observe(el);
        } else {
            // Fallback: listen to mouseup after potential resize
            let isResizing = false;
            el.addEventListener('mousedown', (e) => {
                // Check if click is on resize handle (bottom-right corner)
                const rect = el.getBoundingClientRect();
                const clickX = e.clientX - rect.left;
                const clickY = e.clientY - rect.top;
                const threshold = 20;
                if (clickX > rect.width - threshold && clickY > rect.height - threshold) {
                    isResizing = true;
                }
            });
            document.addEventListener('mouseup', () => {
                if (isResizing) {
                    isResizing = false;
                    handlePanelResize();
                }
            });
        }

        // Update cached dimensions on window resize
        let resizeTimeout;
        window.addEventListener('resize', () => {
            clearTimeout(resizeTimeout);
            resizeTimeout = setTimeout(() => {
                if (!isDragging) {
                    updateCachedDimensions();
                    if (isStuckToSide) {
                        // Reapply side-stick with new viewport dimensions
                        applySideStick(stuckSide);
                    } else {
                        const rect = el.getBoundingClientRect();
                        adjustPanelHeight(rect.top, rect.left);
                    }
                }
            }, 100);
        });
    }


    function downloadLog() {
        try {
            // Get persistent log from GM storage
            const persistentLog = GM_getValue('yss_persistent_log', '');

            if (!persistentLog && (!logArea || !logArea.innerText)) {
                log('Log is empty, nothing to download.', 'warn');
                return;
            }

            // Combine current log display with persistent log
            const currentLog = logArea ? logArea.innerText : '';
            const combinedLog = persistentLog + (currentLog ? '\n\n--- CURRENT SESSION ---\n' + currentLog : '');

            const blob = new Blob([combinedLog], {
                type: 'text/plain;charset=utf-8'
            });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `youtube-automation-log-${new Date().toISOString().replace(/:/g, '-')}.txt`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
            log('Log file downloaded with persistent history.', 'success');
        } catch (e) {
            log(`Error downloading log: ${e.message}`, 'error');
        }
    }

    // ADD THIS NEW, SAFE MARKDOWN PARSER FUNCTION


    /**
     * Parser seguro de Markdown a DOM sin innnerHTML.
     * Soporta: Headers, listas, bold, italic, links, imágenes, tablas, code blocks, blockquotes y HR.
     * @param {string} markdownText - Contenido Markdown del README
     * @returns {DocumentFragment} Fragment con elementos DOM parseados
     */
    function parseMarkdownToDOM(markdownText) {
        const fragment = document.createDocumentFragment();
        const lines = markdownText.replace(/\r\n/g, '\n').split('\n');

        let currentList = null;
        let currentTable = null;
        let currentTableBody = null;
        let tableColumnCount = 0;
        let inCodeBlock = false;
        let codeBlockLines = [];
        let currentCodeLang = '';

        /**
         * Parsea elementos inline: bold, italic, code, links con imágenes, imágenes, links
         */
        const parseInline = (text) => {
            const inlineFragment = document.createDocumentFragment();

            // Regex mejorado que captura links con imágenes: [![alt](img)](link)
            const regex = /\[!\[([^\]]*)\]\(([^)]+)\)\]\(([^)]+)\)|!\[([^\]]*)\]\(([^)]+)\)|\[([^\]]+)\]\(([^)]+)\)|(\*\*|__)([^*_]+?)\8|(\*|_)([^*_]+?)\10|`([^`]+)`/g;

            let lastIndex = 0;
            let match;

            while ((match = regex.exec(text)) !== null) {
                // Agregar texto previo al match
                if (match.index > lastIndex) {
                    inlineFragment.appendChild(
                        document.createTextNode(text.substring(lastIndex, match.index))
                    );
                }

                if (match[1] !== undefined) {
                    // Link con imagen dentro: [![alt](img)](link)
                    const a = document.createElement('a');
                    a.href = match[3];
                    a.target = '_blank';
                    a.rel = 'noopener noreferrer';
                    a.className = 'yss-lightbox';

                    const img = document.createElement('img');
                    img.alt = match[1];
                    img.src = match[2];
                    img.className = 'yss-image';
                    img.style.maxWidth = '100%';

                    a.appendChild(img);
                    inlineFragment.appendChild(a);
                } else if (match[4] !== undefined) {
                    // Imagen: ![alt](src)
                    const img = document.createElement('img');
                    img.alt = match[4];
                    img.src = match[5];
                    img.className = 'yss-image';
                    img.style.maxWidth = '100%';
                    inlineFragment.appendChild(img);
                } else if (match[6] !== undefined) {
                    // Link: [text](url)
                    const a = document.createElement('a');
                    a.textContent = match[6];
                    a.href = match[7];
                    a.target = '_blank';
                    a.rel = 'noopener noreferrer';
                    inlineFragment.appendChild(a);
                } else if (match[8] !== undefined) {
                    // Bold: **text** o __text__
                    const strong = document.createElement('strong');
                    strong.textContent = match[9];
                    inlineFragment.appendChild(strong);
                } else if (match[10] !== undefined) {
                    // Italic: *text* o _text_
                    const em = document.createElement('em');
                    em.textContent = match[11];
                    inlineFragment.appendChild(em);
                } else if (match[12] !== undefined) {
                    // Inline Code: `code`
                    const code = document.createElement('code');
                    code.textContent = match[12];
                    inlineFragment.appendChild(code);
                }

                lastIndex = regex.lastIndex;
            }

            // Agregar texto restante
            if (lastIndex < text.length) {
                inlineFragment.appendChild(
                    document.createTextNode(text.substring(lastIndex))
                );
            }

            return inlineFragment;
        };

        /**
         * Crea el botón de copiar para code blocks
         */
        const createCopyButton = (codeText) => {
            const container = document.createElement('div');
            container.className = 'zeroclipboard-container';

            const codelang_span = document.createElement('span');
            codelang_span.className = 'code-lang';

            if (currentCodeLang) {
                codelang_span.className = `code-lang language-${currentCodeLang}`;
                codelang_span.textContent = `Language: ${currentCodeLang}`;
            }

            const button = document.createElement('button');
            button.className = 'ClipboardButton btn';
            button.setAttribute('aria-label', 'Copy');
            button.setAttribute('tabindex', '0');
            button.setAttribute('role', 'button');

            // SVG del icono de copiar
            const copySvg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
            copySvg.setAttribute('aria-hidden', 'true');
            copySvg.setAttribute('height', '16');
            copySvg.setAttribute('viewBox', '0 0 16 16');
            copySvg.setAttribute('width', '16');
            copySvg.setAttribute('class', 'octicon octicon-copy js-clipboard-copy-icon m-2');

            const copyPath1 = document.createElementNS('http://www.w3.org/2000/svg', 'path');
            copyPath1.setAttribute('d', 'M0 6.75C0 5.784.784 5 1.75 5h1.5a.75.75 0 0 1 0 1.5h-1.5a.25.25 0 0 0-.25.25v7.5c0 .138.112.25.25.25h7.5a.25.25 0 0 0 .25-.25v-1.5a.75.75 0 0 1 1.5 0v1.5A1.75 1.75 0 0 1 9.25 16h-7.5A1.75 1.75 0 0 1 0 14.25Z');
            const copyPath2 = document.createElementNS('http://www.w3.org/2000/svg', 'path');
            copyPath2.setAttribute('d', 'M5 1.75C5 .784 5.784 0 6.75 0h7.5C15.216 0 16 .784 16 1.75v7.5A1.75 1.75 0 0 1 14.25 11h-7.5A1.75 1.75 0 0 1 5 9.25Zm1.75-.25a.25.25 0 0 0-.25.25v7.5c0 .138.112.25.25.25h7.5a.25.25 0 0 0 .25-.25v-7.5a.25.25 0 0 0-.25-.25Z');

            copySvg.appendChild(copyPath1);
            copySvg.appendChild(copyPath2);

            // SVG del icono de check (inicialmente oculto)
            const checkSvg = document.createElementNS('http://www.w3.org/2000/svg', 'svg');
            checkSvg.setAttribute('aria-hidden', 'true');
            checkSvg.setAttribute('height', '16');
            checkSvg.setAttribute('viewBox', '0 0 16 16');
            checkSvg.setAttribute('width', '16');
            checkSvg.setAttribute('class', 'octicon octicon-check js-clipboard-check-icon color-fg-success d-none m-2');

            const checkPath = document.createElementNS('http://www.w3.org/2000/svg', 'path');
            checkPath.setAttribute('d', 'M13.78 4.22a.75.75 0 0 1 0 1.06l-7.25 7.25a.75.75 0 0 1-1.06 0L2.22 9.28a.751.751 0 0 1 .018-1.042.751.751 0 0 1 1.042-.018L6 10.94l6.72-6.72a.75.75 0 0 1 1.06 0Z');
            checkSvg.appendChild(checkPath);

            // Tooltip
            const tooltip = document.createElement('span');
            tooltip.className = 'copy-tooltip';
            tooltip.textContent = 'Copied!';
            tooltip.style.cssText = 'opacity: 0;';

            button.appendChild(copySvg);
            button.appendChild(checkSvg);
            button.appendChild(tooltip);

            // Evento de click para copiar
            button.addEventListener('click', async (e) => {
                e.preventDefault();
                e.stopPropagation();

                try {
                    await navigator.clipboard.writeText(codeText);

                    copySvg.classList.add('d-none');
                    checkSvg.classList.remove('d-none');
                    tooltip.style.opacity = '1';

                    setTimeout(() => {
                        copySvg.classList.remove('d-none');
                        checkSvg.classList.add('d-none');
                        tooltip.style.opacity = '0';
                    }, 2000);
                } catch (err) {
                    console.error('Failed to copy code:', err);

                    const textarea = document.createElement('textarea');
                    textarea.value = codeText;
                    textarea.style.cssText = 'position: fixed; left: -9999px;';
                    document.body.appendChild(textarea);
                    textarea.select();

                    try {
                        document.execCommand('copy');

                        copySvg.classList.add('d-none');
                        checkSvg.classList.remove('d-none');
                        tooltip.style.opacity = '1';

                        setTimeout(() => {
                            copySvg.classList.remove('d-none');
                            checkSvg.classList.add('d-none');
                            tooltip.style.opacity = '0';
                        }, 2000);
                    } catch (e) {
                        console.error('Fallback copy failed:', e);
                    } finally {
                        document.body.removeChild(textarea);
                    }
                }
            });

            container.appendChild(codelang_span)
            container.appendChild(button);
            return container;
        };

        /**
         * Finaliza un code block acumulado
         */
        const finalizeCodeBlock = () => {
            if (codeBlockLines.length > 0) {
                const wrapper = document.createElement('div');
                wrapper.className = 'highlight-code';
                wrapper.style.position = 'relative';

                const pre = document.createElement('pre');
                const code = document.createElement('code');

                if (currentCodeLang) {
                    code.className = `language-${currentCodeLang}`;
                    code.setAttribute('code-lang', `language-${currentCodeLang}`);
                }

                const codeText = codeBlockLines.join('\n');
                code.textContent = codeText;
                pre.appendChild(code);

                const copyButton = createCopyButton(codeText);

                wrapper.appendChild(pre);
                wrapper.appendChild(copyButton);
                fragment.appendChild(wrapper);

                codeBlockLines = [];
                currentCodeLang = '';
            }
        };

        /**
         * Determina si una línea es un separador de tabla
         */
        const isTableSeparator = (line) => {
            const trimmed = line.trim();
            return trimmed.includes('|') &&
                trimmed.replace(/\|/g, '').replace(/[-:\s]/g, '') === '';
        };

        /**
         * Parsea una fila de tabla
         */
        const parseTableRow = (line) => {
            return line.split('|')
                .map(c => c.trim())
                .filter((c, idx, arr) => idx > 0 && idx < arr.length - 1);
        };

        for (let i = 0; i < lines.length; i++) {
            const line = lines[i];
            const trimmedLine = line.trim();

            // Manejo de code blocks
            if (trimmedLine.startsWith('```')) {
                if (inCodeBlock) {
                    finalizeCodeBlock();
                    inCodeBlock = false;
                } else {
                    inCodeBlock = true;
                    currentCodeLang = trimmedLine.substring(3).trim();
                }
                continue;
            }

            if (inCodeBlock) {
                codeBlockLines.push(line);
                continue;
            }

            // Reset de contextos
            if (!trimmedLine.match(/^(\*|\-|\+|\d+\.)\s/) && currentList) {
                currentList = null;
            }

            if (!trimmedLine.includes('|') && currentTable) {
                currentTable = null;
                currentTableBody = null;
            }

            // Headers
            if (trimmedLine.match(/^#{1,6}\s/)) {
                let level = 0;
                while (trimmedLine[level] === '#' && level < 6) {
                    level++;
                }
                const h = document.createElement(`h${level}`);
                h.appendChild(parseInline(trimmedLine.substring(level).trim()));
                fragment.appendChild(h);
            }
            // Blockquotes
            else if (trimmedLine.startsWith('>')) {
                const bq = document.createElement('blockquote');
                bq.appendChild(parseInline(trimmedLine.substring(1).trim()));
                fragment.appendChild(bq);
            }
            // Listas no ordenadas
            else if (trimmedLine.match(/^(\*|\-|\+)\s/)) {
                if (!currentList || currentList.tagName !== 'UL') {
                    currentList = document.createElement('ul');
                    fragment.appendChild(currentList);
                }
                const li = document.createElement('li');
                li.appendChild(parseInline(trimmedLine.substring(2).trim()));
                currentList.appendChild(li);
            }
            // Listas ordenadas
            else if (trimmedLine.match(/^\d+\.\s/)) {
                if (!currentList || currentList.tagName !== 'OL') {
                    currentList = document.createElement('ol');
                    fragment.appendChild(currentList);
                }
                const li = document.createElement('li');
                li.appendChild(parseInline(trimmedLine.replace(/^\d+\.\s/, '')));
                currentList.appendChild(li);
            }
            // Horizontal rules
            else if (trimmedLine.match(/^(-{3,}|\*{3,}|_{3,})$/)) {
                fragment.appendChild(document.createElement('hr'));
            }
            // Tablas
            else if (trimmedLine.includes('|') && trimmedLine.split('|').length > 2) {
                const cells = parseTableRow(trimmedLine);

                // Verificar si la siguiente línea es un separador de tabla
                if (i + 1 < lines.length && isTableSeparator(lines[i + 1])) {
                    // Crear nueva tabla
                    currentTable = document.createElement('table');
                    currentTable.setAttribute('cellpadding', '10');
                    currentTable.setAttribute('border', '1');
                    currentTable.setAttribute('bordercolor', '#333333');
                    currentTable.setAttribute('cellspacing', '0');
                    currentTable.setAttribute('bgcolor', '#111111');
                    currentTable.style.width = '100%';

                    const thead = document.createElement('thead');
                    const tr = document.createElement('tr');

                    tableColumnCount = cells.length;

                    cells.forEach(headerText => {
                        const th = document.createElement('th');
                        th.appendChild(parseInline(headerText));
                        tr.appendChild(th);
                    });

                    thead.appendChild(tr);
                    currentTable.appendChild(thead);
                    currentTableBody = document.createElement('tbody');
                    currentTable.appendChild(currentTableBody);
                    fragment.appendChild(currentTable);

                    i++; // Saltar línea separadora
                } else if (currentTableBody) {
                    // Body row
                    const tr = document.createElement('tr');

                    // Detectar si es una fila de descripción (texto sin imágenes/links complejos)
                    const isDescriptionRow = !trimmedLine.match(/!\[.*?\]\(.*?\)/);

                    if (isDescriptionRow) {
                        tr.setAttribute('bgcolor', '#0d0d0d');
                    }

                    cells.forEach((cellText, idx) => {
                        const td = document.createElement('td');
                        td.appendChild(parseInline(cellText));
                        tr.appendChild(td);
                    });

                    currentTableBody.appendChild(tr);
                }
            }
            // Líneas vacías
            else if (!trimmedLine) {
                continue;
            }
            // Párrafos normales (incluye badges e imágenes sueltas)
            else {
                const p = document.createElement('p');
                p.appendChild(parseInline(line));
                fragment.appendChild(p);
            }
        }

        // Finalizar code block si quedó abierto
        if (inCodeBlock) {
            finalizeCodeBlock();
        }

        return fragment;
    }

    /**
     * Fetch del README desde GitHub usando GM_xmlhttpRequest
     */
    function fetchGithubReadme(owner, repo) {
        return new Promise((resolve, reject) => {
            //const url = `https://raw.githubusercontent.com/${owner}/${repo}/main/README.md`;
            const url = "https://satsea.io/video-calendar/README.md";

            GM_xmlhttpRequest({
                method: 'GET',
                url: url,
                onload: function (response) {
                    if (response.status >= 200 && response.status < 300) {
                        resolve(response.responseText);
                    } else {
                        reject(new Error(`HTTP error! Status: ${response.status}`));
                    }
                },
                onerror: function (response) {
                    reject(new Error(`Network error. Status: ${response.status}`));
                }
            });
        });
    }


    // ADD THIS NEW FUNCTION to show the README in a modal.

    // This will render the button-style link
    async function showReadmeModal() {
        const owner = 'markmorbid';
        const repo = 'toolpanel-userscript';
        // Use the GitHub page URL for the button link, not the raw content URL
        const repoUrl = `https://github.com/${owner}/${repo}/blob/main/README.md`;

        const modal = new YSSModalBuilder('README from GitHub', {
            maxWidth: '700px',
            isSticky: true,
            isScrollable: true,
            linkInHeader: repoUrl,
            linkInHeaderBtn: 'View on GitHub',
            linkInHeaderIcon: 'fa-brands fa-github',
            closeOnOverlayClick: false,
            fullScreenBtn: true

        });


        // === Preloader ===

        const preLoader = document.createElement('div');
        preLoader.className = 'yss-preloader';

        const preLoaderSpinner = document.createElement('div');
        preLoaderSpinner.className = 'yss-preloader-spinner';

        const preLoaderText = document.createElement('p');
        preLoaderText.className = 'yss-preloader-text';
        preLoaderText.textContent = 'Fetching README.md from GitHub...';

        preLoader.appendChild(preLoaderSpinner);
        preLoader.appendChild(preLoaderText);

        // Show inside your modal
        modal.setContent([preLoader]);

        // Optional fade-out before removing
        function hidePreloader() {
            preLoader.style.animation = 'yss-preloader-fade-out 0.5s ease forwards';
            setTimeout(() => modal.clearContent(), 500);
        }

        modal.setContent([preLoader]);
        modal.show();

        try {
            const markdownContent = await fetchGithubReadme(owner, repo);
            const domContent = parseMarkdownToDOM(markdownContent);

            const readmeContainer = document.createElement('div');
            readmeContainer.className = 'yss-readme-container';
            readmeContainer.appendChild(domContent);

            modal.setContent([readmeContainer]);
        } catch (error) {
            console.error('[Help] Failed to display README:', error);
            const errorP = document.createElement('p');
            errorP.textContent = `Error: Could not load README.md - ${error.message}`;
            modal.setContent([errorP]);
        }
    }


