    /**
     * A curated list of CSS properties to capture. This prevents capturing all 300+ properties
     * from getComputedStyle, focusing on the ones relevant for styling UI components.
     * You can add or remove properties from this list as needed.
     */
    const PROPERTIES_TO_CAPTURE = [
        'color', 'background', 'background-color', 'background-image', 'background-position', 'background-size', 'background-repeat',
        'border', 'border-color', 'border-width', 'border-style', 'border-radius', 'border-top', 'border-right', 'border-bottom', 'border-left',
        'font-family', 'font-size', 'font-weight', 'font-style', 'line-height', 'letter-spacing', 'text-transform', 'text-align', 'text-decoration',
        'padding', 'padding-top', 'padding-right', 'padding-bottom', 'padding-left',
        'margin', 'margin-top', 'margin-right', 'margin-bottom', 'margin-left',
        'display', 'flex-direction', 'flex-wrap', 'align-items', 'justify-content', 'align-content', 'flex', 'flex-grow', 'flex-shrink', 'flex-basis',
        'gap', 'grid-template-columns', 'grid-template-rows', 'grid-gap',
        'box-shadow', 'opacity', 'transform', 'transition', 'transition-property', 'transition-duration', 'transition-timing-function',
        'accent-color', 'outline', 'outline-color', 'outline-width', 'outline-style',
        'height', 'width', 'min-height', 'min-width', 'max-height', 'max-width', 'aspect-ratio',
        'white-space', 'text-overflow', 'overflow', 'overflow-x', 'overflow-y', 'cursor',
        'backdrop-filter', 'filter', 'position', 'top', 'right', 'bottom', 'left', 'z-index',
        'visibility', 'pointer-events', 'user-select', 'resize', 'object-fit', 'object-position'
    ];

    /**
     * Advanced CSS Snapshot Tool - Captures full DOM tree with CSS variable resolution
     * and generates clean, hierarchical stylesheets
     */
    async function showCssSnapshotModal() {
        const modal = new YSSModalBuilder('CSS Snapshot Tool', {
            maxWidth: '800px',
            isSticky: true,
            customClasses: ['yss-snapshot-modal']
        });

        let outputTextarea;
        let viewModeSelect;

        // --- Advanced CSS Resolution Functions ---

        // Cache for stylesheet rules to avoid re-parsing
        let stylesheetRulesCache = null;

        /**
         * Gets all CSS rules from stylesheets (cached)
         */
        function getAllStylesheetRules() {
            if (stylesheetRulesCache) return stylesheetRulesCache;

            const allRules = [];
            const allSheets = Array.from(document.styleSheets);

            for (const sheet of allSheets) {
                try {
                    const sheetRules = Array.from(sheet.cssRules || []);
                    for (const rule of sheetRules) {
                        if (rule instanceof CSSStyleRule) {
                            allRules.push(rule);
                        }
                    }
                } catch (e) {
                    // Cross-origin stylesheet, skip
                }
            }

            stylesheetRulesCache = allRules;
            return allRules;
        }

        /**
         * Checks if a selector requires classes that the element doesn't have
         */
        function selectorRequiresMissingClasses(selector, elementClasses) {
            // Extract all class requirements from selector (e.g., .collapsed, .flat-theme)
            const classMatches = selector.match(/\.([a-zA-Z0-9_-]+)/g);
            if (!classMatches) return false;

            // Get required classes (remove the dot)
            const requiredClasses = classMatches.map(m => m.substring(1));

            // Check if all required classes are present
            return requiredClasses.some(reqClass => !elementClasses.includes(reqClass));
        }

        /**
         * Gets all CSS rules from stylesheets that match a given element's CURRENT state
         * Only includes rules that match the element as it currently is (with current classes)
         */
        function getStylesheetRulesForElement(element, targetStateClasses = null) {
            const rules = [];
            const allRules = getAllStylesheetRules();
            const elementClasses = Array.from(element.classList);

            // If targetStateClasses is provided, use those instead of current classes
            const activeClasses = targetStateClasses ? targetStateClasses.split(' ').filter(Boolean) : elementClasses;

            for (const rule of allRules) {
                try {
                    const selector = rule.selectorText;

                    // Skip selectors that require classes the element doesn't have
                    // (unless we're specifically targeting those classes)
                    if (targetStateClasses === null) {
                        // Base state: only include rules that don't require state classes
                        // State classes are: collapsed, flat-theme, yss-buttons-notext, yss-gradient-btn, color-hover
                        const stateClasses = ['collapsed', 'flat-theme', 'yss-buttons-notext', 'yss-gradient-btn', 'color-hover'];
                        const selectorHasStateClass = stateClasses.some(sc => selector.includes(`.${sc}`));

                        if (selectorHasStateClass) {
                            // This selector requires a state class, skip it for base state
                            continue;
                        }
                    } else {
                        // Specific state: check if selector requires classes we don't have
                        if (selectorRequiresMissingClasses(selector, activeClasses)) {
                            continue;
                        }
                    }

                    // Try matches - this checks if element matches the selector
                    // For base state (targetStateClasses === null), element should already have no state classes
                    // For specific state, element should have those classes applied
                    let shouldMatch = false;
                    try {
                        // Use element.matches which will check against current element state
                        shouldMatch = element.matches && element.matches(selector);
                    } catch (e) {
                        // Invalid selector or matches failed
                        shouldMatch = false;
                    }

                    if (shouldMatch) {
                        rules.push(rule);
                        continue;
                    }

                } catch (e) {
                    // Invalid selector or matches failed, skip
                }
            }

            return rules;
        }

        /**
         * Gets CSS property value from stylesheet rules (preserves var() references)
         * Checks rules in order of specificity
         */
        function getStylesheetValue(element, property, allRules) {
            // Sort rules by specificity (more specific first)
            const sortedRules = allRules.sort((a, b) => {
                // Simple specificity check - more selectors = more specific
                const aSpecificity = (a.selectorText.match(/[#.:\[]/g) || []).length;
                const bSpecificity = (b.selectorText.match(/[#.:\[]/g) || []).length;
                return bSpecificity - aSpecificity;
            });

            for (const rule of sortedRules) {
                const value = rule.style.getPropertyValue(property);
                if (value) {
                    const priority = rule.style.getPropertyPriority(property);
                    return {
                        value: value.trim(),
                        important: priority === 'important',
                        selector: rule.selectorText
                    };
                }
            }
            return null;
        }

        /**
         * Gets all CSS custom properties (variables) from :root in stylesheets
         */
        function getAllCSSVariables() {
            const variables = {};
            const allSheets = Array.from(document.styleSheets);

            for (const sheet of allSheets) {
                try {
                    const rules = Array.from(sheet.cssRules || []);
                    for (const rule of rules) {
                        if (rule instanceof CSSStyleRule &&
                            (rule.selectorText === ':root' || rule.selectorText === 'html' || rule.selectorText === 'body')) {
                            for (let i = 0; i < rule.style.length; i++) {
                                const prop = rule.style[i];
                                if (prop.startsWith('--')) {
                                    variables[prop] = rule.style.getPropertyValue(prop).trim();
                                }
                            }
                        }
                    }
                } catch (e) {
                    // Cross-origin, skip
                }
            }
            return variables;
        }

        /**
         * Checks if a CSS property value is effective (not default/empty/ineffective)
         */
        function isPropertyEffective(prop, value, element) {
            if (!value || value.trim() === '') return false;

            // Properties that are valid with 'none', 'normal', 'auto'
            const validWithDefaults = {
                'display': ['none', 'block', 'flex', 'grid', 'inline', 'inline-block', 'inline-flex'],
                'position': ['static', 'relative', 'absolute', 'fixed', 'sticky'],
                'overflow': ['visible', 'hidden', 'scroll', 'auto'],
                'visibility': ['visible', 'hidden', 'collapse'],
                'pointer-events': ['auto', 'none', 'visiblePainted', 'visibleFill', 'visibleStroke', 'painted', 'fill', 'stroke', 'all'],
                'white-space': ['normal', 'nowrap', 'pre', 'pre-wrap', 'pre-line'],
                'text-transform': ['none', 'uppercase', 'lowercase', 'capitalize'],
                'text-align': ['left', 'right', 'center', 'justify', 'start', 'end'],
                'flex-direction': ['row', 'row-reverse', 'column', 'column-reverse'],
                'align-items': ['stretch', 'flex-start', 'flex-end', 'center', 'baseline'],
                'justify-content': ['flex-start', 'flex-end', 'center', 'space-between', 'space-around', 'space-evenly']
            };

            // Check if property accepts this value as valid
            if (validWithDefaults[prop] && validWithDefaults[prop].includes(value)) {
                return true;
            }

            // Filter out clearly ineffective values
            const ineffectiveValues = ['0px', '0', 'rgba(0, 0, 0, 0)', 'transparent', 'none', 'normal', 'auto'];
            if (ineffectiveValues.includes(value)) {
                // But keep if it's a CSS variable (might resolve to something meaningful)
                if (value.includes('var(')) return true;
                // Check if this is explicitly set (different from browser default)
                const computed = window.getComputedStyle(element);
                const computedValue = computed.getPropertyValue(prop).trim();
                // If computed is same as value, it might be default - but we'll include it if it's in our capture list
                return false;
            }

            // Keep CSS variables
            if (value.includes('var(')) return true;

            // Keep everything else that has a value
            return true;
        }

        /**
         * Gets effective styles for an element from stylesheet (preserves CSS variables)
         * This is much faster and preserves var() references instead of resolving to rgba
         */
        function getEffectiveStyles(element, elementRules = null, targetStateClasses = null) {
            const styles = {};

            // Get matching rules if not provided
            if (!elementRules) {
                elementRules = getStylesheetRulesForElement(element, targetStateClasses);
            }

            // Get values from stylesheet rules (preserves var() references)
            for (const prop of PROPERTIES_TO_CAPTURE) {
                const styleData = getStylesheetValue(element, prop, elementRules);
                if (styleData && styleData.value) {
                    // Check if property is effective
                    if (isPropertyEffective(prop, styleData.value, element)) {
                        styles[prop] = {
                            value: styleData.value,
                            important: styleData.important
                        };
                    }
                }
            }

            // Also capture CSS custom properties from stylesheet
            for (const rule of elementRules) {
                for (let i = 0; i < rule.style.length; i++) {
                    const prop = rule.style[i];
                    if (prop.startsWith('--')) {
                        const value = rule.style.getPropertyValue(prop).trim();
                        const priority = rule.style.getPropertyPriority(prop);
                        if (value) {
                            styles[prop] = {
                                value: value,
                                important: priority === 'important'
                            };
                        }
                    }
                }
            }

            return styles;
        }

        /**
         * Generates a unique selector for an element
         */
        function generateSelector(element, rootElement) {
            if (element === rootElement) {
                return rootElement.id ? `#${rootElement.id}` :
                    rootElement.className ? `.${rootElement.className.split(' ').join('.')}` :
                        rootElement.tagName.toLowerCase();
            }

            // Try ID first
            if (element.id) {
                return `#${element.id}`;
            }

            // Build class selector
            const classes = Array.from(element.classList).filter(c => c.startsWith('yss-') || c.startsWith('yt-'));
            if (classes.length > 0) {
                return `.${classes.join('.')}`;
            }

            // Fallback to tag name with nth-child if needed
            const tag = element.tagName.toLowerCase();
            const parent = element.parentElement;
            if (parent) {
                const siblings = Array.from(parent.children).filter(c => c.tagName === element.tagName);
                if (siblings.length > 1) {
                    const index = siblings.indexOf(element) + 1;
                    return `${tag}:nth-of-type(${index})`;
                }
            }
            return tag;
        }

        /**
         * Recursively captures styles from element tree (optimized to prevent hangs)
         */
        function captureElementTree(element, rootElement, depth = 0, maxDepth = 5, processed = new WeakSet(), targetStateClasses = null) {
            if (depth > maxDepth || !element || processed.has(element)) return null;

            // Mark as processed to avoid infinite loops
            processed.add(element);

            const selector = generateSelector(element, rootElement);
            const elementRules = getStylesheetRulesForElement(element, targetStateClasses);
            const styles = getEffectiveStyles(element, elementRules, targetStateClasses);

            const result = {
                element: element,
                selector: selector,
                tagName: element.tagName.toLowerCase(),
                classes: Array.from(element.classList),
                styles: styles,
                children: []
            };

            // Limit children processing to prevent performance issues
            if (depth < maxDepth) {
                const children = Array.from(element.children)
                    .filter(child => {
                        const tag = child.tagName.toLowerCase();
                        // Filter out non-visual elements
                        if (['script', 'style', 'noscript', 'template', 'svg', 'iframe'].includes(tag)) return false;
                        // Only process elements with yss- or yt- classes, or direct important children
                        const hasRelevantClass = Array.from(child.classList).some(c => c.startsWith('yss-') || c.startsWith('yt-'));
                        return hasRelevantClass || depth < 2; // Process all children at shallow levels
                    })
                    .slice(0, 50); // Limit to 50 children max per element

                for (const child of children) {
                    const childResult = captureElementTree(child, rootElement, depth + 1, maxDepth, processed, targetStateClasses);
                    if (childResult && (Object.keys(childResult.styles).length > 0 || childResult.children.length > 0)) {
                        result.children.push(childResult);
                    }
                }
            }

            return result;
        }

        /**
         * Generates CSS from captured element tree
         */
        function generateCSSFromTree(tree, rootSelector = '', indent = 0) {
            if (!tree) return '';

            let css = '';
            const indentStr = '    '.repeat(indent);

            // Build selector
            let selector = tree.selector;
            if (rootSelector && !tree.selector.startsWith(rootSelector)) {
                selector = `${rootSelector} ${tree.selector}`;
            }

            // Generate styles for this element
            if (Object.keys(tree.styles).length > 0) {
                css += `${indentStr}${selector} {\n`;
                for (const [prop, styleData] of Object.entries(tree.styles)) {
                    const important = styleData.important ? ' !important' : '';
                    css += `${indentStr}    ${prop}: ${styleData.value}${important};\n`;
                }
                css += `${indentStr}}\n\n`;
            }

            // Generate styles for children
            for (const child of tree.children) {
                css += generateCSSFromTree(child, rootSelector, indent);
            }

            return css;
        }

        // --- Core Snapshot Function (Optimized) ---
        const snapshotStyles = async () => {
            const viewMode = viewModeSelect.value;
            const rootSelector = document.getElementById('snapshot-root-selector').value.trim() || '#yss-panel';
            const statesInput = document.getElementById('snapshot-states').value.trim();

            outputTextarea.value = 'Initializing...\nParsing stylesheets...';

            // Clear cache to ensure fresh parsing
            stylesheetRulesCache = null;

            // Find root element
            let rootElement = document.querySelector(rootSelector);
            if (!rootElement) {
                alert(`Root element not found: ${rootSelector}`);
                return;
            }

            const states = statesInput.split('\n').map(s => s.trim()).filter(Boolean);
            const originalClasses = rootElement.className;
            const results = {};

            try {
                // Pre-cache stylesheet rules and CSS variables once
                outputTextarea.value = 'Loading stylesheets...';
                getAllStylesheetRules(); // Build cache
                await new Promise(resolve => setTimeout(resolve, 100));

                outputTextarea.value = 'Loading CSS variables...';
                const allVariables = getAllCSSVariables();
                await new Promise(resolve => setTimeout(resolve, 50));

                let targetElements = [];

                if (viewMode === 'panel') {
                    targetElements = [document.querySelector('#yss-panel')].filter(Boolean);
                } else if (viewMode === 'modal') {
                    targetElements = [document.querySelector('.yss-modal-overlay')].filter(Boolean);
                } else if (viewMode === 'batch') {
                    targetElements = [document.querySelector('.yt-batch-controls-wrapper.yss-modal-content.yss-batch')].filter(Boolean);
                } else if (viewMode === 'all') {
                    targetElements = [
                        document.querySelector('#yss-panel'),
                        document.querySelector('.yss-modal-overlay'),
                        document.querySelector('.yt-batch-controls-wrapper.yss-modal-content.yss-batch')
                    ].filter(Boolean);
                } else {
                    // Custom selector
                    const customSelector = document.getElementById('snapshot-custom-selector')?.value.trim();
                    if (customSelector) {
                        targetElements = Array.from(document.querySelectorAll(customSelector)).slice(0, 3); // Limit custom to 3 elements
                    }
                }

                if (targetElements.length === 0) {
                    alert(`No elements found for view mode: ${viewMode}`);
                    return;
                }

                // Capture base state with progress updates (no state classes)
                outputTextarea.value = `Capturing base styles (no state classes)...\nProcessing ${targetElements.length} element(s)...`;
                await new Promise(resolve => setTimeout(resolve, 100));

                // Remove any state classes temporarily to capture true base state
                const originalElementClasses = targetElements.map(el => el.className);
                targetElements.forEach(el => {
                    // Remove state classes for base capture
                    el.className = el.className
                        .split(' ')
                        .filter(c => !['collapsed', 'flat-theme', 'yss-buttons-notext', 'yss-gradient-btn', 'color-hover'].includes(c))
                        .join(' ');
                });

                for (let i = 0; i < targetElements.length; i++) {
                    outputTextarea.value = `Capturing base styles...\nElement ${i + 1}/${targetElements.length}`;
                    await new Promise(resolve => setTimeout(resolve, 50)); // Yield to browser

                    const targetElement = targetElements[i];
                    const tree = captureElementTree(targetElement, rootElement, 0, 4, new WeakSet(), null); // null = base state
                    if (tree) {
                        results['base'] = results['base'] || [];
                        results['base'].push(tree);
                    }
                }

                // Restore original classes
                targetElements.forEach((el, idx) => {
                    el.className = originalElementClasses[idx];
                });

                // Capture state variations with progress
                for (let stateIdx = 0; stateIdx < states.length; stateIdx++) {
                    const stateClasses = states[stateIdx];
                    outputTextarea.value = `Capturing state: ${stateClasses}\n${stateIdx + 1}/${states.length}`;

                    // Apply state classes to root and target elements
                    rootElement.className = `${originalClasses} ${stateClasses}`;
                    targetElements.forEach(el => {
                        const baseClasses = el.className
                            .split(' ')
                            .filter(c => !['collapsed', 'flat-theme', 'yss-buttons-notext', 'yss-gradient-btn', 'color-hover'].includes(c))
                            .join(' ');
                        el.className = `${baseClasses} ${stateClasses}`;
                    });

                    await new Promise(resolve => setTimeout(resolve, 150)); // Wait for styles to apply

                    const stateTrees = [];
                    for (let i = 0; i < targetElements.length; i++) {
                        await new Promise(resolve => setTimeout(resolve, 30)); // Yield between elements
                        const targetElement = targetElements[i];
                        const tree = captureElementTree(targetElement, rootElement, 0, 4, new WeakSet(), stateClasses);
                        if (tree) stateTrees.push(tree);
                    }

                    if (stateTrees.length > 0) {
                        results[stateClasses] = stateTrees;
                    }

                    // Restore original classes
                    rootElement.className = originalClasses;
                    targetElements.forEach((el, idx) => {
                        el.className = originalElementClasses[idx];
                    });
                    await new Promise(resolve => setTimeout(resolve, 50));
                }

            } finally {
                rootElement.className = originalClasses;
            }

            // Generate CSS output
            outputTextarea.value = 'Generating CSS output...';
            await new Promise(resolve => setTimeout(resolve, 50));

            let cssOutput = `/* CSS Snapshot Generated: ${new Date().toLocaleString()} */\n`;
            cssOutput += `/* View Mode: ${viewMode} */\n`;
            cssOutput += `/* Root Selector: ${rootSelector} */\n`;
            cssOutput += `/* Values from stylesheet (preserves CSS variables) */\n\n`;

            // Generate base styles
            if (results['base']) {
                cssOutput += `/* ===== BASE STYLES ===== */\n\n`;
                for (const tree of results['base']) {
                    cssOutput += generateCSSFromTree(tree, rootSelector, 0);
                }
            }

            // Generate state-specific styles
            for (const stateClasses of states) {
                if (results[stateClasses]) {
                    cssOutput += `/* ===== STATE: ${stateClasses} ===== */\n\n`;
                    const stateSelector = stateClasses.split(' ').map(c => `.${c}`).join('');
                    const fullRootSelector = `${rootSelector}${stateSelector}`;

                    for (const tree of results[stateClasses]) {
                        cssOutput += generateCSSFromTree(tree, fullRootSelector, 0);
                    }
                }
            }

            outputTextarea.value = cssOutput.trim();
            log('[Snapshot] CSS generation complete.', 'success');
        };


        // --- UI Schema for the Modal Content ---
        const modalSchema = [
            {
                type: 'section',
                title: 'Instructions',
                children: [
                    {
                        type: 'custom', render: () => {
                            const container = document.createElement('div');
                            container.className = 'yss-form-group';
                            container.style.fontSize = '13px';

                            const title = document.createElement('h4');
                            title.textContent = 'CSS Snapshot Tool';
                            title.style.marginTop = '0';
                            title.style.marginBottom = '10px';
                            container.appendChild(title);

                            const desc = document.createElement('p');
                            desc.textContent = 'This tool extracts CSS directly from your stylesheet, preserving CSS variables (var()) instead of resolving them to rgba values.';
                            desc.style.marginBottom = '15px';
                            container.appendChild(desc);

                            const ol = document.createElement('ol');
                            ol.style.paddingLeft = '20px';
                            ol.style.marginBottom = '15px';

                            const steps = [
                                'Select a view mode (Panel, Modal, Batch, All, or Custom).',
                                'Set the root selector where state classes will be applied (default: #yss-panel).',
                                'Define states to capture - each line is a class combination (e.g., flat-theme color-hover).',
                                'Click "Generate CSS" to extract styles from your stylesheet with CSS variables preserved.'
                            ];

                            steps.forEach(stepText => {
                                const li = document.createElement('li');
                                li.textContent = stepText;
                                li.style.marginBottom = '8px';
                                ol.appendChild(li);
                            });

                            container.appendChild(ol);

                            const features = document.createElement('p');
                            features.style.fontSize = '12px';
                            features.style.color = 'var(--yss-log-info, #888)';
                            features.textContent = 'Features: Stylesheet parsing (not computed styles), CSS variable preservation, filters ineffective properties, preserves !important flags, optimized performance.';
                            container.appendChild(features);

                            return container;
                        }
                    }
                ]
            },
            {
                type: 'row',
                className: 'yss-form-groups-row',
                children: [
                    {
                        type: 'custom', render: () => new UIMasterBuilder({
                            type: 'container', className: 'yss-form-group', children: [
                                { type: 'custom', render: () => { const l = document.createElement('label'); l.textContent = 'View Mode'; return l; } },
                                {
                                    type: 'custom', render: () => {
                                        viewModeSelect = document.createElement('select');
                                        viewModeSelect.id = 'snapshot-view-mode';
                                        viewModeSelect.className = 'yss-select';

                                        const options = [
                                            { value: 'panel', text: 'Panel (#yss-panel)' },
                                            { value: 'modal', text: 'Modal (.yss-modal-overlay)' },
                                            { value: 'batch', text: 'Batch Panel (.yt-batch-controls-wrapper)' },
                                            { value: 'all', text: 'All Views' },
                                            { value: 'custom', text: 'Custom Selector' }
                                        ];

                                        options.forEach(opt => {
                                            const option = document.createElement('option');
                                            option.value = opt.value;
                                            option.textContent = opt.text;
                                            viewModeSelect.appendChild(option);
                                        });

                                        return viewModeSelect;
                                    }
                                }
                            ]
                        }).render()
                    },
                    {
                        type: 'custom', render: () => new UIMasterBuilder({
                            type: 'container', className: 'yss-form-group', children: [
                                { type: 'custom', render: () => { const l = document.createElement('label'); l.textContent = 'Root Selector (for state classes)'; return l; } },
                                { type: 'custom', render: () => { const i = document.createElement('input'); i.id = 'snapshot-root-selector'; i.className = 'yss-input'; i.value = '#yss-panel'; return i; } }
                            ]
                        }).render()
                    }
                ]
            },
            {
                type: 'custom', render: () => new UIMasterBuilder({
                    type: 'container', className: 'yss-form-group', children: [
                        { type: 'custom', render: () => { const l = document.createElement('label'); l.textContent = 'Custom Selector (only used if View Mode = Custom)'; return l; } },
                        { type: 'custom', render: () => { const i = document.createElement('input'); i.id = 'snapshot-custom-selector'; i.className = 'yss-input'; i.placeholder = 'e.g., .yss-btn, #yss-panel .yss-controls'; return i; } }
                    ]
                }).render()
            },
            {
                type: 'custom', render: () => new UIMasterBuilder({
                    type: 'container', className: 'yss-form-group', children: [
                        { type: 'custom', render: () => { const l = document.createElement('label'); l.textContent = 'States to Capture (one class combination per line)'; return l; } },
                        {
                            type: 'custom', render: () => {
                                const t = document.createElement('textarea');
                                t.id = 'snapshot-states';
                                t.className = 'yss-input';
                                t.style.height = '100px';
                                t.value = 'flat-theme\nflat-theme yss-gradient-btn\nflat-theme color-hover\nflat-theme color-hover yss-gradient-btn\ncollapsed\nyss-buttons-notext';
                                return t;
                            }
                        }
                    ]
                }).render()
            },
            {
                type: 'custom', render: () => new UIMasterBuilder({
                    type: 'container', className: 'yss-form-group', children: [
                        { type: 'custom', render: () => { const l = document.createElement('label'); l.textContent = 'Generated CSS Output'; return l; } },
                        {
                            type: 'custom', render: () => {
                                outputTextarea = document.createElement('textarea');
                                outputTextarea.id = 'snapshot-output';
                                outputTextarea.className = 'yss-input';
                                outputTextarea.readOnly = true;
                                outputTextarea.style.height = '400px';
                                outputTextarea.style.fontFamily = 'monospace, "Courier New"';
                                outputTextarea.style.fontSize = '11px';
                                outputTextarea.style.lineHeight = '1.4';
                                return outputTextarea;
                            }
                        }
                    ]
                }).render()
            }
        ];

        const modalContent = new UIMasterBuilder({ type: 'container', children: modalSchema }).render();
        modal.setContent([modalContent]);

        setupModalButtons(modal, {
            copy: {
                id: 'snapshot-copy', text: 'Copy CSS', icon: 'fa-solid fa-copy', classes: ['yss-btn', 'yss-btn-secondary'], position: 'left',
                handlers: { onClick: () => { navigator.clipboard.writeText(outputTextarea.value); alert('CSS copied to clipboard!'); } }
            },
            generate: {
                id: 'snapshot-generate', text: 'Generate CSS', icon: 'fa-solid fa-magic-wand-sparkles', classes: ['yss-btn', 'yss-btn-primary'], position: 'right',
                handlers: { onClick: snapshotStyles }
            }
        });

        await modal.show();
    }
