    // Helper function to safely parse JSON from GM storage
    function safeJsonParse(jsonString, defaultValue = []) {
        try {
            const parsed = JSON.parse(jsonString);
            return Array.isArray(parsed) ? parsed : defaultValue;
        } catch (e) {
            return defaultValue;
        }
    }

    // Helper function to safely parse JSON from GM storage into an object
    function safeJsonParseObject(jsonString, defaultValue = {}) {
        try {
            const parsed = JSON.parse(jsonString);
            // Ensure it's an object and not null or an array
            return (typeof parsed === 'object' && parsed !== null && !Array.isArray(parsed)) ? parsed : defaultValue;
        } catch (e) {
            return defaultValue;
        }
    }

    // Helper function to get video title from GM storage and optionally remove it
    function getVideoTitleFromStorage(videoUrl, removeAfterRetrieval = false) {
        try {
            const storedTitles = safeJsonParseObject(GM_getValue('yss_video_titles', '{}'), {});
            const title = storedTitles[videoUrl];
            if (title && title !== 'Unknown Title') {
                log(`[AllNotifs] Retrieved title from storage for ${videoUrl}: "${title}"`, "debug");

                // Remove the title from storage after retrieving it to prevent accumulation
                if (removeAfterRetrieval) {
                    delete storedTitles[videoUrl];
                    GM_setValue('yss_video_titles', JSON.stringify(storedTitles));
                    log(`[AllNotifs] Removed title from storage for ${videoUrl}`, "debug");
                }

                return title;
            }

            // Fallback: try to get from in-memory cache
            if (window.yssVideoTitles && window.yssVideoTitles.has(videoUrl)) {
                const memoryTitle = window.yssVideoTitles.get(videoUrl);
                log(`[AllNotifs] Retrieved title from memory for ${videoUrl}: "${memoryTitle}"`, "debug");

                // Also remove from memory cache
                if (removeAfterRetrieval) {
                    window.yssVideoTitles.delete(videoUrl);
                    log(`[AllNotifs] Removed title from memory cache for ${videoUrl}`, "debug");
                }

                return memoryTitle;
            }

            // Final fallback: use video ID
            const videoId = videoUrl.split('/video/')[1]?.split('/edit')[0];
            if (videoId) {
                const fallbackTitle = `Video ${videoId}`;
                log(`[AllNotifs] Using fallback title for ${videoUrl}: "${fallbackTitle}"`, "debug");
                return fallbackTitle;
            }

            return 'Unknown Title';
        } catch (error) {
            log(`[AllNotifs] Error getting title from storage: ${error.message}`, "error");
            return 'Unknown Title';
        }
    }

    // Function to store summary in history
    function storeSummaryInHistory(summaryData) {
        const summaryHistoryRaw = GM_getValue('yss_summary_history', '[]');
        const summaryHistory = safeJsonParse(summaryHistoryRaw, []);
        const timestamp = new Date().toISOString();

        const historyEntry = {
            timestamp: timestamp,
            data: summaryData
        };

        // Keep only last 10 summaries
        summaryHistory.push(historyEntry);
        if (summaryHistory.length > 10) {
            summaryHistory.shift();
        }

        GM_setValue('yss_summary_history', JSON.stringify(summaryHistory));
        log(`[AllNotifs] Stored summary in history. Total history entries: ${summaryHistory.length}`, "info");
    }

    // Function to show summary from data
    function showSummaryFromData(summaryData) {
        return new Promise((resolve) => {
            if (document.getElementById('yss-modal-overlay')) return;

            // Handle both old and new data structures first
            let videos = [];
            let totalProcessed = 0;
            let summaryDate = new Date();

            if (summaryData.videos && Array.isArray(summaryData.videos)) {
                // New structure
                videos = summaryData.videos;
                totalProcessed = summaryData.totalProcessed || videos.length;
                summaryDate = summaryData.date ? new Date(summaryData.date) : new Date();
            } else if (summaryData.processedVideos && Array.isArray(summaryData.processedVideos)) {
                // Old structure - convert to new format
                const processedVideos = summaryData.processedVideos;
                const persistentLog = summaryData.persistentLog || '';
                const logLines = persistentLog.split('\n');

                videos = processedVideos.map((videoUrl, index) => {
                    const videoId = videoUrl.split('/video/')[1]?.split('/edit')[0] || 'Unknown';

                    // Get title from storage
                    let title = ensureVideoTitleStored(videoUrl);
                    if (!title || title === 'Unknown Title') {
                        title = 'Video ' + videoId;
                    }

                    // Determine status from logs
                    let status = '✅ Processed';
                    let details = 'Notification checkbox was unchecked';

                    // Look for status in logs
                    for (let i = logLines.length - 1; i >= 0; i--) {
                        const line = logLines[i];
                        if (line.includes(videoId) && line.includes('Processing video:')) {
                            // Look for checkbox state
                            for (let j = i; j < Math.min(i + 10, logLines.length); j++) {
                                const checkLine = logLines[j];
                                if (checkLine.includes('Checkbox state:')) {
                                    if (checkLine.includes('checked=true')) {
                                        status = 'Edited (Unchecked)';
                                        details = 'Notification checkbox was unchecked';
                                    } else if (checkLine.includes('checked=false')) {
                                        status = 'Already Unchecked';
                                        details = 'Notification checkbox was already unchecked';
                                    }
                                    break;
                                }
                            }
                            break;
                        }
                    }

                    return {
                        index: index + 1,
                        videoId: videoId,
                        url: videoUrl,
                        title: title,
                        status: status,
                        details: details
                    };
                });

                totalProcessed = videos.length;
                summaryDate = summaryData.timestamp ? new Date(summaryData.timestamp) : new Date();
            }
            const createFormGroup = (label, child) => {
                const group = document.createElement('div');
                group.className = 'yss-form-group';
                const labelEl = document.createElement('label');
                labelEl.className = 'yss-group-title-label';
                labelEl.textContent = label;
                group.appendChild(labelEl);
                group.appendChild(child);
                return group;
            };
            // 2. Create modal with proper configuration
            const modal = new YSSModalBuilder('Processing Summary (Historical)', {
                isSticky: true,
                showBackButton: true,
                onBack: () => {
                    // Optionally show the previous modal again
                    showProcessingOptionsModal();
                }
            });
            // Summary stats
            const statsContainer = document.createElement('div');
            statsContainer.className = "yss-summary-table";

            const statsTitle = document.createElement('div');
            statsTitle.textContent = '📊 Processing Statistics';
            statsTitle.className = "yss-summary-title";

            const statsList = document.createElement('div');
            statsList.className = "yss-summary-rows";

            const totalProcessedDiv = document.createElement('div');
            totalProcessedDiv.textContent = '✅ Total videos processed: ';
            const totalProcessedStrong = document.createElement('strong');
            totalProcessedStrong.textContent = totalProcessed.toString();
            totalProcessedDiv.appendChild(totalProcessedStrong);

            const dateDiv = document.createElement('div');
            dateDiv.textContent = '📅 Date: ';
            const dateStrong = document.createElement('strong');
            dateStrong.textContent = summaryDate.toLocaleDateString();
            dateDiv.appendChild(dateStrong);

            const timeDiv = document.createElement('div');
            timeDiv.textContent = '⏰ Time: ';
            const timeStrong = document.createElement('strong');
            timeStrong.textContent = summaryDate.toLocaleTimeString();
            timeDiv.appendChild(timeStrong);

            statsList.appendChild(totalProcessedDiv);
            statsList.appendChild(dateDiv);
            statsList.appendChild(timeDiv);

            statsContainer.appendChild(statsTitle);
            statsContainer.appendChild(statsList);

            // Video list container
            const videoListContainer = document.createElement('div');
            videoListContainer.className = "yss-videolist-container";

            const toggleStatsBtn = modal.createToggleStatsButton();
            statsTitle.appendChild(toggleStatsBtn);
            // Create table for video details
            const table = document.createElement('table');

            // Table header
            const thead = document.createElement('thead');
            const headerRow = document.createElement('tr');

            const headers = ['#', 'Status', 'Video Title', 'Edit Link'];
            headers.forEach(headerText => {
                const th = document.createElement('th');
                th.textContent = headerText;
                th.setAttribute('alt', headerText);
                headerRow.appendChild(th);
            });
            thead.appendChild(headerRow);
            table.appendChild(thead);

            // Table body
            const tbody = document.createElement('tbody');

            // Display videos from summary data
            videos.forEach((video, index) => {
                const row = document.createElement('tr');

                // Create cells
                const cells = [{
                    text: (index + 1).toString(),
                    type: 'index',
                    style: 'font-size: 11px; text-align: center;'
                },
                {
                    text: video.status || '✅ Processed',
                    type: 'status',
                    style: 'font-size: 11px; color: #28a745; font-weight: bold;'
                },
                {
                    text: video.title || `Video ${video.videoId}`,
                    type: 'title',
                    style: 'font-size: 11px; max-width: 200px; overflow: hidden; text-overflow: ellipsis;'
                },
                {
                    type: 'button',
                    text: 'Edit',
                    url: video.url,
                    style: 'width: 30px;'
                }
                ];

                cells.forEach(cellData => {
                    const td = document.createElement('td');
                    td.style.cssText = `padding: 8px; ${cellData.style}`;

                    if (cellData.type === 'button') {
                        td.className = "yss-button-cell";

                        const button = document.createElement('button');
                        button.className = "yss-btn yss-btn-primary";
                        //button.style.cssText = cellData.style;
                        //button.textContent = cellData.text;
                        const editBtnIcon = createIcon('fa-solid fa-pen-to-square');
                        button.appendChild(editBtnIcon);
                        button.onclick = () => window.open(cellData.url, '_blank');
                        td.appendChild(button);

                    } else if (cellData.type === 'status') {
                        td.textContent = cellData.text;
                        td.className = "yss-status-cell";

                    } else if (cellData.type === 'index') {
                        td.textContent = cellData.text;
                        td.className = "yss-index-cell";
                    } else {
                        td.textContent = cellData.text;
                    }

                    row.appendChild(td);
                });

                tbody.appendChild(row);
            });

            table.appendChild(tbody);
            videoListContainer.appendChild(table);

            // 3. Create button configurations
            const buttonConfigs = {
                exportBtn: {
                    id: 'yss-modal-export',
                    text: 'Export Summary',
                    icon: 'fa-solid fa-file-export',
                    classes: ['yss-btn', 'yss-btn-primary'],
                    tooltip: 'Export Summary',
                    position: 'right',
                    handlers: {
                        onClick: (e, button) => {
                            // Extract just the URLs from the video objects
                            const videoUrls = videos.map(video => video.url);
                            exportProcessingSummary(videoUrls, '');
                        }
                    }
                },
                cancelBtn: {
                    id: 'yss-modal-cancel',
                    text: 'Cancel',
                    icon: 'fa-solid fa-xmark',
                    classes: ['yss-btn', 'yss-btn-secondary'],
                    position: 'left',
                    handlers: {
                        onClick: (e, button) => {
                            modal.close();
                        }
                    }
                }
            };

            document.addEventListener('keydown', function escapeHandler(e) {
                if (e.key === 'Escape') {
                    cleanup();
                    document.removeEventListener('keydown', escapeHandler);
                    resolve();
                }
            });

            resolve();
            const buttons = setupModalButtons(modal, buttonConfigs);
            modal.getViewContainer().appendChild(statsContainer);
            modal.getViewContainer().appendChild(videoListContainer);
            // 6. Set the content and show the modal

            return modal.show();
        });
    }

    // Improved progress checking function
    function shouldShowResumePrompt() {
        const progress = loadProgress();
        if (!progress) return false;

        const totalProcessed = progress.successes ? progress.successes.length : (progress.usedTitles ? progress.usedTitles.length : 0);

        // Don't show resume if all titles were used successfully
        if (totalProcessed > 0 && progress.pendingTitles && progress.pendingTitles.length === 0) {
            return false;
        }

        // Don't show resume if it was a failed attempt with no progress
        if (totalProcessed === 0) {
            return false;
        }

        // Show resume if there are pending titles or partial progress
        return true;
    }

    // Function to get progress summary for display
    function getProgressSummary() {
        const progress = loadProgress();
        if (!progress) return null;

        const totalProcessed = progress.successes ? progress.successes.length : (progress.usedTitles ? progress.usedTitles.length : 0);
        const hasProgress = totalProcessed > 0 ||
            (progress.config && progress.config.videoTitles && progress.pendingTitles && progress.pendingTitles.length < progress.config.videoTitles.length);

        // Debug logging
        console.log('Progress Debug:', {
            progress,
            totalProcessed,
            hasProgress,
            successes: progress.successes,
            usedTitles: progress.usedTitles,
            pendingTitles: progress.pendingTitles
        });

        return {
            totalProcessed: totalProcessed,
            totalTitles: progress.config?.videoTitles?.length || 0,
            usedTitles: progress.usedTitles?.length || 0,
            pendingTitles: progress.pendingTitles?.length || 0,
            mode: progress.config?.renameOnlyMode ? 'Rename Only' : 'Full Scheduling',
            hasProgress: hasProgress
        };
    }

