    // Debug function to check save button status
    window.debugSaveButton = function () {
        log("[AllNotifs] Debug: Checking save button status...", "info");

        const selectors = [
            '#save',
            '#save-button',
            'button[aria-label*="Save"]',
            'button[aria-label*="save"]',
            'button[data-tooltip*="Save"]',
            'button[data-tooltip*="save"]',
            'button[title*="Save"]',
            'button[title*="save"]'
        ];

        selectors.forEach((selector, index) => {
            const element = document.querySelector(selector);
            if (element) {
                const disabled = element.hasAttribute('disabled');
                const ariaLabel = element.getAttribute('aria-label') || 'N/A';
                const textContent = element.textContent || 'N/A';
                const title = element.getAttribute('title') || 'N/A';
                log(`[AllNotifs] Debug: Selector ${index + 1} (${selector}) - Found: ${!disabled ? 'ENABLED' : 'DISABLED'}, Aria: ${ariaLabel}, Text: ${textContent}, Title: ${title}`, "info");
            } else {
                log(`[AllNotifs] Debug: Selector ${index + 1} (${selector}) - Not found`, "warn");
            }
        });

        // Also check for any buttons that might be save buttons
        const allButtons = document.querySelectorAll('button');
        log(`[AllNotifs] Debug: Found ${allButtons.length} total buttons on page`, "info");

        allButtons.forEach((btn, index) => {
            const text = btn.textContent || '';
            const ariaLabel = btn.getAttribute('aria-label') || '';
            const title = btn.getAttribute('title') || '';
            const disabled = btn.hasAttribute('disabled');

            if (text.toLowerCase().includes('save') || ariaLabel.toLowerCase().includes('save') || title.toLowerCase().includes('save')) {
                log(`[AllNotifs] Debug: Potential save button ${index} - Text: "${text}", Aria: "${ariaLabel}", Title: "${title}", Disabled: ${disabled}`, "info");
            }
        });

        return {
            totalSelectors: selectors.length,
            foundElements: selectors.filter(selector => document.querySelector(selector)).length,
            totalButtons: allButtons.length
        };
    };

