    // Apply downloader states to video rows
    function applyDownloaderStatesToRows(forceRemove = false) {
        document.querySelectorAll('ytcp-video-row').forEach(row => {
            const videoId = extractVideoIdFromRow(row);
            const currentState = getDownloaderVideoState(videoId);

            row.classList.remove('yss-dl-queued-video', 'yss-dl-already-video', 'yss-dl-downloaded-video', 'yss-dl-failed-video', 'yss-dl-skipped-video');

            if (forceRemove) return;

            // Apply visual styling based on state
            switch (currentState) {
                case DOWNLOAD_STATE_DOWNLOADED:
                    row.classList.add('yss-dl-downloaded-video');
                    break;
                case DOWNLOAD_STATE_SKIPPED:
                    row.classList.add('yss-dl-skipped-video');
                    break;
                case DOWNLOAD_STATE_ERROR:
                    row.classList.add('yss-dl-failed-video');
                    break;
                case DOWNLOAD_STATE_PROCESSING:
                    row.classList.add('yss-dl-queued-video');
                    break;
                case DOWNLOAD_STATE_PENDING:
                default:
                    // No specific class for pending state
                    break;
            }
        });
    }

    // Apply state to a specific row (more efficient for processing)
    function applyDownloaderStateToRow(row, state) {
        row.classList.remove('yss-dl-queued-video', 'yss-dl-already-video', 'yss-dl-downloaded-video', 'yss-dl-failed-video', 'yss-dl-skipped-video');

        switch (state) {
            case DOWNLOAD_STATE_DOWNLOADED:
                row.classList.add('yss-dl-downloaded-video');
                break;
            case DOWNLOAD_STATE_SKIPPED:
                row.classList.add('yss-dl-skipped-video');
                break;
            case DOWNLOAD_STATE_ERROR:
                row.classList.add('yss-dl-failed-video');
                break;
            case DOWNLOAD_STATE_PROCESSING:
                row.classList.add('yss-dl-queued-video');
                break;
            case DOWNLOAD_STATE_PENDING:
            default:
                // No specific class for pending state
                break;
        }
    }

    // Helper function to validate YouTube video ID format
    function isValidYouTubeVideoId(id) {
        if (!id || typeof id !== 'string') return false;
        if (id.length !== 11) return false;

        // YouTube video IDs contain a mix of letters, numbers, hyphens, and underscores
        // They typically contain at least one number and don't start with common words
        const validPattern = /^[a-zA-Z0-9_-]{11}$/;
        if (!validPattern.test(id)) return false;

        // Must contain at least one number
        if (!/[0-9]/.test(id)) return false;

        // Should not start with common words that might appear in text content
        const invalidPrefixes = /^(galactic|video|title|watch|youtube|studio|channel|playlist|user|edit|delete|publish|private|public|unlisted|draft|scheduled)/i;
        if (invalidPrefixes.test(id)) return false;

        return true;
    }

    // Extract video ID from row - Enhanced with multiple robust methods
    function extractVideoIdFromRow(row) {
        try {
            // Only log when we actually find a valid ID to reduce noise
            let foundId = null;

            // Method 1: Try to get from Studio edit URL (most reliable for Studio)
            const studioEditLink = row.querySelector('a[href*="/edit"]');
            if (studioEditLink?.href) {
                const match = studioEditLink.href.match(/\/edit\/([a-zA-Z0-9_-]{11})/);
                if (match && match[1] && isValidYouTubeVideoId(match[1])) {
                    foundId = match[1];
                    log(`[Downloader] Extracted video ID from Studio edit link: ${foundId}`, 'debug');
                    return foundId;
                }
            }

            // Method 2: Try to get from title link with watch URL
            const titleElement = row.querySelector('#video-title');
            const titleLink = titleElement?.closest('a');
            if (titleLink?.href?.includes('watch?v=')) {
                const videoId = new URL(titleLink.href).searchParams.get('v');
                if (videoId && isValidYouTubeVideoId(videoId)) {
                    foundId = videoId;
                    log(`[Downloader] Extracted video ID from title link: ${foundId}`, 'debug');
                    return foundId;
                }
            }

            // Method 3: Try to get from any link in the row with watch URL
            const anyLink = row.querySelector('a[href*="watch?v="]');
            if (anyLink) {
                const videoId = new URL(anyLink.href).searchParams.get('v');
                if (videoId && isValidYouTubeVideoId(videoId)) {
                    foundId = videoId;
                    log(`[Downloader] Extracted video ID from any link: ${foundId}`, 'debug');
                    return foundId;
                }
            }

            // Method 4: Try to get from data attributes
            const dataVideoId = row.getAttribute('data-video-id');
            if (dataVideoId && isValidYouTubeVideoId(dataVideoId)) {
                foundId = dataVideoId;
                log(`[Downloader] Extracted video ID from data-video-id: ${foundId}`, 'debug');
                return foundId;
            }

            const dataRowId = row.getAttribute('data-row-id');
            if (dataRowId && isValidYouTubeVideoId(dataRowId)) {
                foundId = dataRowId;
                log(`[Downloader] Extracted video ID from data-row-id: ${foundId}`, 'debug');
                return foundId;
            }

            // Method 5: Try to extract from the row's ID
            const rowId = row.id;
            if (rowId) {
                // Look for 11-character video ID pattern in the row ID
                const videoIdMatch = rowId.match(/[a-zA-Z0-9_-]{11}/);
                if (videoIdMatch && isValidYouTubeVideoId(videoIdMatch[0])) {
                    foundId = videoIdMatch[0];
                    log(`[Downloader] Extracted video ID from row ID: ${foundId}`, 'debug');
                    return foundId;
                }
            }

            // Method 6: Try to find any element with a video ID pattern
            const allElements = row.querySelectorAll('*');
            for (const element of allElements) {
                const href = element.href;
                if (href && href.includes('watch?v=')) {
                    const videoId = new URL(href).searchParams.get('v');
                    if (videoId && isValidYouTubeVideoId(videoId)) {
                        foundId = videoId;
                        log(`[Downloader] Extracted video ID from element href: ${foundId}`, 'debug');
                        return foundId;
                    }
                }
            }

            // Method 7: Try to extract from any text content that looks like a video ID
            // This is the least reliable method, so we're very strict about validation
            const textContent = row.textContent;
            const videoIdMatch = textContent.match(/[a-zA-Z0-9_-]{11}/);
            if (videoIdMatch) {
                const potentialId = videoIdMatch[0];
                if (isValidYouTubeVideoId(potentialId)) {
                    foundId = potentialId;
                    log(`[Downloader] Extracted video ID from text content: ${foundId}`, 'debug');
                    return foundId;
                } else {
                    log(`[Downloader] Rejected potential video ID from text content: ${potentialId} (doesn't match YouTube ID pattern)`, 'debug');
                }
            }

            // Only log if no ID was found and we're in debug mode
            if (!foundId) {
                log(`[Downloader] Could not extract video ID from row`, 'debug');
            }
            return null;
        } catch (e) {
            log(`[Downloader] Failed to extract video ID from row: ${e.message}`, 'error');
            console.warn('[Downloader] Video ID extraction error', e, row);
            return null;
        }
    }

    // Helper function to wait for videos to load on a page
    async function waitForVideosToLoadDl(timeout = 10000) {
        log(`[Downloader] Waiting for videos to load (timeout: ${timeout / 1000}s)...`, 'info');
        return new Promise(async (resolve) => {
            const timeLimit = Date.now() + timeout;

            while (Date.now() < timeLimit && !bulkDownloaderState.stop) {
                const videoRows = document.querySelectorAll('ytcp-video-row');
                if (videoRows.length > 0) {
                    log(`[Downloader] Found ${videoRows.length} video rows`, 'success');
                    resolve(true);
                    return;
                }

                if (!(await sleep(500))) {
                    log(`[Downloader] Stop detected during video load wait`, 'warn');
                    resolve(false);
                    return;
                }
            }

            log(`[Downloader] Timeout waiting for videos to load`, 'warn');
            resolve(false);
        });
    }


