    // Make debug function available globally
    window.debugManualSelection = debugManualSelection;

    // Download video for a specific row
    const downloadVideoForRow = async (row, videoId, retryCount = 0) => {
        if (bulkDownloaderState.stop) {
            return {
                success: false,
                reason: 'Stopped before start'
            };
        }

        let downloadClicked = false;
        let menuListbox = null;
        const videoTitle = row.querySelector('#video-title')?.textContent?.trim() || `Video (ID: ${videoId || 'Unknown'})`;

        // Extract the actual download URL from the dropdown menu (same as pre-fetch function)
        let videoUrl = '';
        try {
            // First try to get the download URL by opening the options menu
            const optionsButton = row.querySelector('ytcp-icon-button[aria-label="Options"]') ||
                row.querySelector('ytcp-icon-button#options-menu') ||
                row.querySelector('ytcp-icon-button[tooltip="Options"]');

            if (optionsButton) {
                optionsButton.click();
                await sleep(400);

                const menuListbox = document.querySelector('tp-yt-paper-listbox[role="menu"]');
                if (menuListbox) {
                    // Use the same logic as extractDownloadUrl function
                    let downloadLink = null;
                    const downloadItem = menuListbox.querySelector('tp-yt-paper-item[test-id="download"]');
                    if (downloadItem) {
                        downloadLink = downloadItem.querySelector('a[href*="/download_my_video"]');
                        if (!downloadLink) {
                            downloadLink = downloadItem;
                        }
                    }

                    if (!downloadLink) {
                        downloadLink = menuListbox.querySelector('a[href*="/download_my_video"]');
                    }

                    if (downloadLink) {
                        if (downloadLink.href) {
                            videoUrl = downloadLink.href;
                        } else if (downloadLink.getAttribute('href')) {
                            videoUrl = downloadLink.getAttribute('href');
                        } else if (downloadLink.tagName === 'TP-YT-PAPER-ITEM') {
                            const anchor = downloadLink.querySelector('a[href*="/download_my_video"]');
                            if (anchor) {
                                videoUrl = anchor.href || anchor.getAttribute('href');
                            }
                        }
                    }

                    // Clean up - remove the open menu
                    if (menuListbox.parentNode) {
                        menuListbox.parentNode.removeChild(menuListbox);
                    }
                }
            }

            // Fallback: if we couldn't get the download URL, use the watch URL
            if (!videoUrl) {
                const editLink = row.querySelector('a[href*="/edit"]');
                if (editLink?.href) {
                    const match = editLink.href.match(/\/video\/([a-zA-Z0-9_-]{11})\/edit/);
                    if (match) {
                        videoUrl = `https://www.youtube.com/watch?v=${match[1]}`;
                    }
                }
                if (!videoUrl) {
                    videoUrl = row.querySelector('a[href*="watch?v="]')?.href || '';
                }
            }
        } catch (error) {
            log(`[Downloader] Error extracting download URL for "${videoTitle}": ${error.message}`, 'warn');
            // Fallback to edit URL conversion
            const editLink = row.querySelector('a[href*="/edit"]');
            if (editLink?.href) {
                const match = editLink.href.match(/\/video\/([a-zA-Z0-9_-]{11})\/edit/);
                if (match) {
                    videoUrl = `https://www.youtube.com/watch?v=${match[1]}`;
                }
            }
            if (!videoUrl) {
                videoUrl = row.querySelector('a[href*="watch?v="]')?.href || '';
            }
        }

        if (retryCount > 0) {
            log(`[Downloader] Retry attempt ${retryCount} for: "${videoTitle}"`, 'info');
        } else {
            log(`[Downloader] Attempting download for: "${videoTitle}"`, 'info');
        }

        try {
            const rowContainer = row.querySelector('#row-container');
            if (rowContainer) {
                rowContainer.scrollIntoView({
                    behavior: 'smooth',
                    block: 'center'
                });
                await sleep(150); // Reduced from 300ms
                if (bulkDownloaderState.stop) {
                    return {
                        success: false,
                        reason: 'Stopped during scroll/focus'
                    };
                }
                simulateEvent(rowContainer, 'mouseover');
                await sleep(350); // Reduced from 700ms
                if (bulkDownloaderState.stop) {
                    return {
                        success: false,
                        reason: 'Stopped after hover'
                    };
                }
            } else {
                log(`[Downloader] Could not find #row-container for "${videoTitle}"`, 'warn');
            }

            await removeOldOptionMenus();
            if (bulkDownloaderState.stop) {
                return {
                    success: false,
                    reason: 'Stopped after cleanup'
                };
            }

            let optionsButton = null;
            const optionsSelectors = [
                'ytcp-icon-button[aria-label="Options"]',
                'ytcp-icon-button#options-menu',
                'ytcp-icon-button[tooltip="Options"]',
                'button[aria-label="Options"]',
                'ytcp-icon-button > yt-icon[icon="more_vert"]',
                'ytcp-icon-button[aria-label*="Options"]',
                'ytcp-icon-button[aria-label*="More"]',
                'ytcp-icon-button[aria-label*="Menu"]',
                'button[aria-label*="Options"]',
                'button[aria-label*="More"]',
                'button[aria-label*="Menu"]',
                'ytcp-icon-button[data-tooltip*="Options"]',
                'ytcp-icon-button[data-tooltip*="More"]',
                'ytcp-icon-button[data-tooltip*="Menu"]',
                'ytcp-icon-button:has(yt-icon[icon="more_vert"])',
                'ytcp-icon-button:has(yt-icon[icon="more_horiz"])',
                'ytcp-icon-button:has(yt-icon[icon="more"])'
            ];

            // Try to find options button with multiple strategies
            for (const selector of optionsSelectors) {
                optionsButton = row.querySelector(selector) ?? rowContainer?.querySelector(selector);
                if (optionsButton) {
                    log(`[Downloader] Found options button using selector: "${selector}"`, 'info');
                    break;
                }
            }

            // If still not found, try a broader search
            if (!optionsButton) {
                const allButtons = row.querySelectorAll('ytcp-icon-button, button');
                for (const button of allButtons) {
                    const ariaLabel = button.getAttribute('aria-label') || '';
                    const tooltip = button.getAttribute('data-tooltip') || '';
                    const text = button.textContent || '';

                    if (ariaLabel.toLowerCase().includes('options') ||
                        ariaLabel.toLowerCase().includes('more') ||
                        ariaLabel.toLowerCase().includes('menu') ||
                        tooltip.toLowerCase().includes('options') ||
                        tooltip.toLowerCase().includes('more') ||
                        tooltip.toLowerCase().includes('menu') ||
                        text.toLowerCase().includes('options') ||
                        text.toLowerCase().includes('more') ||
                        text.toLowerCase().includes('menu')) {
                        optionsButton = button;
                        log(`[Downloader] Found options button via text search: "${ariaLabel || tooltip || text}"`, 'info');
                        break;
                    }
                }
            }

            if (!optionsButton) {
                log(`[Downloader] Options button not found for "${videoTitle}".`, 'error');
                return {
                    success: false,
                    reason: 'Options button not found'
                };
            }

            log(`[Downloader] Clicking options button for "${videoTitle}"...`, 'info');
            optionsButton.click();

            // Debug: Check stop state before sleep
            log(`[Downloader] Stop state before sleep: ${bulkDownloaderState.stop}`, 'info');

            const sleepResult = await sleep(200);
            log(`[Downloader] Sleep result: ${sleepResult}`, 'info');

            if (!sleepResult) {
                log(`[Downloader] Stop state after sleep: ${bulkDownloaderState.stop}`, 'info');
                return {
                    success: false,
                    reason: 'Stopped after options click'
                };
            }

            const menuListboxSelector = 'tp-yt-paper-listbox#paper-list[role="menu"]';
            const menuListboxSelectorFallback = 'tp-yt-paper-listbox[role="menu"]';

            menuListbox = await waitForElement(menuListboxSelector, document.body);
            if (!menuListbox && !bulkDownloaderState.stop) {
                menuListbox = await waitForElement(menuListboxSelectorFallback, document.body, 5000);
            }

            if (bulkDownloaderState.stop) {
                return {
                    success: false,
                    reason: 'Stopped waiting for menu'
                };
            }

            if (!menuListbox) {
                log(`[Downloader] Options menu listbox timed out for "${videoTitle}".`, 'error');
                await removeOldOptionMenus();
                return {
                    success: false,
                    reason: 'Menu listbox not found'
                };
            }

            // Try multiple strategies to find the download link
            let downloadLink = null;
            const downloadSelectors = [
                'tp-yt-paper-item[test-id="download"] a',
                'tp-yt-paper-item[test-id="download"]',
                'a[href*="/download_my_video"]',
                'a[href*="download"]',
                'tp-yt-paper-item a[href*="download"]',
                'tp-yt-paper-item:contains("Download")',
                'tp-yt-paper-item:contains("download")'
            ];

            // First try to find by href
            for (const selector of downloadSelectors) {
                downloadLink = menuListbox.querySelector(selector);
                if (downloadLink) {
                    log(`[Downloader] Found download link using selector: "${selector}"`, 'info');
                    break;
                }
            }

            // If not found by href, try to find by text content
            if (!downloadLink) {
                const allItems = menuListbox.querySelectorAll('tp-yt-paper-item');
                for (const item of allItems) {
                    const text = item.textContent?.toLowerCase() || '';
                    if (text.includes('download')) {
                        downloadLink = item;
                        log(`[Downloader] Found download item by text: "${text.trim()}"`, 'info');
                        break;
                    }
                }
            }

            // If still not found, try to find any clickable element with download text
            if (!downloadLink) {
                const allElements = menuListbox.querySelectorAll('*');
                for (const element of allElements) {
                    const text = element.textContent?.toLowerCase() || '';
                    if (text.includes('download') && (element.tagName === 'A' || element.tagName === 'TP-YT-PAPER-ITEM')) {
                        downloadLink = element;
                        log(`[Downloader] Found download element by text: "${text.trim()}"`, 'info');
                        break;
                    }
                }
            }

            // If still not found, try to find the specific structure you showed
            if (!downloadLink) {
                const downloadItems = menuListbox.querySelectorAll('tp-yt-paper-item[test-id="download"]');
                if (downloadItems.length > 0) {
                    const downloadItem = downloadItems[0];
                    const anchor = downloadItem.querySelector('a');
                    if (anchor) {
                        downloadLink = anchor;
                        log(`[Downloader] Found download link in test-id="download" item`, 'info');
                    } else {
                        downloadLink = downloadItem;
                        log(`[Downloader] Found download item with test-id="download"`, 'info');
                    }
                }
            }

            if (!downloadLink) {
                log(`[Downloader] Download link not found in menu for "${videoTitle}". Menu items:`, 'error');
                const menuItems = menuListbox.querySelectorAll('tp-yt-paper-item');
                menuItems.forEach((item, index) => {
                    log(`[Downloader] Menu item ${index + 1}: "${item.textContent?.trim()}"`, 'info');
                });

                // Additional debugging - log all elements in the menu
                log(`[Downloader] All menu elements:`, 'info');
                const allElements = menuListbox.querySelectorAll('*');
                allElements.forEach((element, index) => {
                    const tagName = element.tagName;
                    const text = element.textContent?.trim();
                    const href = element.href || '';
                    const ariaLabel = element.getAttribute('aria-label') || '';
                    if (text || href || ariaLabel) {
                        log(`[Downloader] Element ${index + 1}: ${tagName} - Text: "${text}" - Href: "${href}" - Aria: "${ariaLabel}"`, 'info');
                    }
                });

                // Try to find any element with "download" in the text
                const downloadElements = Array.from(menuListbox.querySelectorAll('*')).filter(el =>
                    el.textContent?.toLowerCase().includes('download')
                );
                if (downloadElements.length > 0) {
                    log(`[Downloader] Found ${downloadElements.length} elements with 'download' text:`, 'info');
                    downloadElements.forEach((el, index) => {
                        log(`[Downloader] Download element ${index + 1}: ${el.tagName} - "${el.textContent?.trim()}"`, 'info');
                    });
                }
            } else {
                log(`[Downloader] Clicking download link for "${videoTitle}"...`, 'success');

                // Try multiple click strategies
                let clickSuccess = false;

                // Strategy 1: Direct click
                try {
                    downloadLink.click();
                    clickSuccess = true;
                    log(`[Downloader] Direct click successful`, 'success');
                } catch (e) {
                    log(`[Downloader] Direct click failed: ${e.message}`, 'warn');
                }

                // Strategy 2: If direct click failed, try programmatic click
                if (!clickSuccess) {
                    try {
                        const clickEvent = new MouseEvent('click', {
                            view: window,
                            bubbles: true,
                            cancelable: true
                        });
                        downloadLink.dispatchEvent(clickEvent);
                        clickSuccess = true;
                        log(`[Downloader] Programmatic click successful`, 'success');
                    } catch (e) {
                        log(`[Downloader] Programmatic click failed: ${e.message}`, 'warn');
                    }
                }

                // Strategy 3: If still failed, try to find and click the actual link
                if (!clickSuccess) {
                    const actualLink = downloadLink.querySelector('a') || downloadLink;
                    if (actualLink && actualLink.href) {
                        try {
                            window.open(actualLink.href, '_blank');
                            clickSuccess = true;
                            log(`[Downloader] Opened download link in new tab`, 'success');
                        } catch (e) {
                            log(`[Downloader] Failed to open link: ${e.message}`, 'warn');
                        }
                    }
                }

                if (clickSuccess) {
                    downloadClicked = true;
                    log(`[Downloader] Download click successful for "${videoTitle}"`, 'success');

                    // Wait a bit longer to ensure download starts
                    if (!(await sleep(1000))) { // Increased delay for download processing
                        return {
                            success: false,
                            reason: 'Stopped after download click'
                        };
                    }

                    // Additional verification - check if download dialog appeared
                    const downloadDialogs = document.querySelectorAll('ytcp-download-dialog, ytcp-video-download-dialog, [role="dialog"]');
                    if (downloadDialogs.length > 0) {
                        log(`[Downloader] Download dialog detected for "${videoTitle}"`, 'success');
                    } else {
                        log(`[Downloader] No download dialog detected for "${videoTitle}" - may still be processing`, 'info');
                    }
                } else {
                    log(`[Downloader] All click strategies failed for "${videoTitle}"`, 'error');
                }
            }

        } catch (error) {
            log(`[Downloader] CRITICAL error for "${videoTitle}": ${error.message}`, 'error');
            console.error(error);
            return {
                success: false,
                reason: `Exception: ${error.message}`
            };
        } finally {
            log(`[Downloader] Row processing finished for "${videoTitle}". Click initiated: ${downloadClicked}`, downloadClicked ? 'success' : 'warn');

            if (menuListbox && menuListbox.closest) {
                const dialogParent = menuListbox.closest('tp-yt-paper-dialog[role="dialog"], ytcp-popup-container, iron-dropdown');
                if (dialogParent && document.body.contains(dialogParent)) {
                    dialogParent.style.display = 'none';
                    await sleep(25); // Reduced from 50ms
                    dialogParent.remove();
                    await sleep(75); // Reduced from 150ms
                } else {
                    await removeOldOptionMenus();
                }
            } else {
                await removeOldOptionMenus();
            }
        }

        return {
            success: downloadClicked,
            reason: downloadClicked ? 'Clicked' : 'Download link not found or other error'
        };
    };

    // Process current page for downloads
    const processDownloaderCurrentPage = async (pageNumber = 1) => {
        if (bulkDownloaderState.stop) {
            return {
                processed: false,
                finished: false
            };
        }

        await loadDownloaderVideoStates();
        await loadDownloaderHistory(); // Load download history

        // Load imported files from storage
        const importedFiles = loadImportedFilesFromStorage();
        if (importedFiles.length > 0) {
            existingDownloadedFiles = [...existingDownloadedFiles, ...importedFiles];
            log(`[Downloader] Loaded ${importedFiles.length} imported files from storage`, 'info');
        }

        const videoRows = document.querySelectorAll('ytcp-video-row');

        if (videoRows.length === 0) {
            log("[Downloader] No video rows found.", 'warn');
            alert("No videos found.");
            return {
                processed: false,
                finished: true
            };
        }

        const selectedCheckboxes = document.querySelectorAll('.ysbd-manual-checkbox:checked');
        const useManualSelection = selectedCheckboxes.length > 0;

        // Get options from bulkDownloaderState
        const options = bulkDownloaderState.options || {};
        const maxVideos = options.maxVideos || 0;
        const startPosition = options.startPosition || 1;
        const searchTitles = options.searchTitles || [];

        log(`[Downloader] Found ${videoRows.length} videos. Manual selection: ${useManualSelection ? `Yes (${selectedCheckboxes.length} selected)` : 'No'}.`, 'info');
        log(`[Downloader] Download history: ${downloaderHistory.length} successful, ${downloaderFailedVideos.length} failed`, 'info');
        log(`[Downloader] Existing files loaded: ${existingDownloadedFiles.length}`, 'info');
        log(`[Downloader] Options: maxVideos=${maxVideos}, startPosition=${startPosition}, searchTitles=${searchTitles.length}`, 'info');

        // Don't scan all videos here - only process them one by one when needed
        log(`[Downloader] Starting to process videos on page ${pageNumber || 1}...`, 'info');

        let processedCount = 0,
            skippedCount = 0,
            errorCount = 0,
            manualSkippedCount = 0;

        for (let i = 0; i < videoRows.length; i++) {
            const row = videoRows[i];
            const videoId = extractVideoIdFromRow(row);
            const videoTitle = row.querySelector('#video-title')?.textContent?.trim() || `Video ${i + 1}`;
            const currentState = getDownloaderVideoState(videoId);
            const checkbox = row.querySelector('.ysbd-manual-checkbox');

            // Check start position (1-based index)
            if (startPosition > 1 && i < (startPosition - 1)) {
                log(`[Downloader] Skipping video at position ${i + 1} (before start position ${startPosition})`, 'info');
                skippedCount++;
                continue;
            }

            // Check max videos limit
            if (maxVideos > 0 && processedCount >= maxVideos) {
                log(`[Downloader] Reached maximum videos limit (${maxVideos}). Stopping processing.`, 'info');
                break;
            }

            if (useManualSelection && (!checkbox || !checkbox.checked)) {
                manualSkippedCount++;
                continue;
            }

            // Check if already downloaded (from history) - skip this check in manual selection mode
            if (!useManualSelection && isVideoAlreadyDownloaded(videoId)) {
                log(`[Downloader] [ALREADY] "${videoTitle}" - Found as already downloaded and skipped`, 'info');
                row.classList.add('yss-dl-already-video');
                await setDownloaderVideoState(videoId, DOWNLOAD_STATE_DOWNLOADED);
                applyDownloaderStateToRow(row, DOWNLOAD_STATE_DOWNLOADED);
                skippedCount++;
                continue;
            }

            // Check if already downloaded by filename
            if (isVideoAlreadyDownloadedByFilename(videoTitle)) {
                log(`[Downloader] [ALREADY] "${videoTitle}" - Found as already downloaded and skipped`, 'info');
                row.classList.add('yss-dl-already-video');
                await setDownloaderVideoState(videoId, DOWNLOAD_STATE_DOWNLOADED);
                applyDownloaderStateToRow(row, DOWNLOAD_STATE_DOWNLOADED);
                skippedCount++;
                continue;
            }

            // Apply search title filtering if specified
            if (searchTitles.length > 0) {
                const matchesSearch = searchTitles.some(searchTitle =>
                    videoTitle.toLowerCase().includes(searchTitle.toLowerCase().trim())
                );

                if (!matchesSearch) {
                    log(`[Downloader] [SKIPPED] "${videoTitle}" - Does not match any search titles`, 'info');
                    row.classList.add('yss-dl-skipped-video');
                    await setDownloaderVideoState(videoId, DOWNLOAD_STATE_SKIPPED);
                    applyDownloaderStateToRow(row, DOWNLOAD_STATE_SKIPPED);
                    skippedCount++;
                    continue;
                }

                log(`[Downloader] [MATCH] "${videoTitle}" - Matches search title filter`, 'info');
            }

            if (!useManualSelection && (currentState === DOWNLOAD_STATE_DOWNLOADED || currentState === DOWNLOAD_STATE_SKIPPED)) {
                log(`[Downloader] Skipping "${videoTitle}" (State: ${currentState}).`, 'info');
                applyDownloaderStateToRow(row, currentState);
                skippedCount++;
                continue;
            }

            log(`[Downloader] --- [${i + 1}/${videoRows.length}] Processing: "${videoTitle}" ${videoId ? `(ID: ${videoId})` : ''} ---`, 'info');

            if (bulkDownloaderState.stop) {
                log('[Downloader] Stop requested.', 'warn');
                break;
            }

            // Add queued class and log status
            row.classList.add('yss-dl-queued-video');
            log(`[Downloader] [QUEUED] "${videoTitle}" - Starting to process row`, 'info');

            await setDownloaderVideoState(videoId, DOWNLOAD_STATE_PROCESSING);
            applyDownloaderStateToRow(row, DOWNLOAD_STATE_PROCESSING);

            // Try download with retry logic
            let result = null;
            let retryCount = getDownloaderRetryCount(videoId);
            const maxRetries = 3;

            // Extract both the download URL and the YouTube watch URL separately
            let downloadUrl = '';
            let videoUrl = '';

            try {
                // First try to get the download URL by opening the options menu
                const optionsButton = row.querySelector('ytcp-icon-button[aria-label="Options"]') ||
                    row.querySelector('ytcp-icon-button#options-menu') ||
                    row.querySelector('ytcp-icon-button[tooltip="Options"]');

                if (optionsButton) {
                    optionsButton.click();
                    await sleep(400);

                    const menuListbox = document.querySelector('tp-yt-paper-listbox[role="menu"]');
                    if (menuListbox) {
                        // Use the same logic as extractDownloadUrl function
                        let downloadLink = null;
                        const downloadItem = menuListbox.querySelector('tp-yt-paper-item[test-id="download"]');
                        if (downloadItem) {
                            downloadLink = downloadItem.querySelector('a[href*="/download_my_video"]');
                            if (!downloadLink) {
                                downloadLink = downloadItem;
                            }
                        }

                        if (!downloadLink) {
                            downloadLink = menuListbox.querySelector('a[href*="/download_my_video"]');
                        }

                        if (downloadLink) {
                            if (downloadLink.href) {
                                downloadUrl = downloadLink.href;
                            } else if (downloadLink.getAttribute('href')) {
                                downloadUrl = downloadLink.getAttribute('href');
                            } else if (downloadLink.tagName === 'TP-YT-PAPER-ITEM') {
                                const anchor = downloadLink.querySelector('a[href*="/download_my_video"]');
                                if (anchor) {
                                    downloadUrl = anchor.href || anchor.getAttribute('href');
                                }
                            }
                        }

                        // Clean up - remove the open menu
                        if (menuListbox.parentNode) {
                            menuListbox.parentNode.removeChild(menuListbox);
                        }
                    }
                }

                // Always extract the YouTube watch URL separately (never as a fallback for download URL)
                const editLink = row.querySelector('a[href*="/edit"]');
                if (editLink?.href) {
                    const match = editLink.href.match(/\/video\/([a-zA-Z0-9_-]{11})\/edit/);
                    if (match) {
                        videoUrl = `https://www.youtube.com/watch?v=${match[1]}`;
                    }
                }
                if (!videoUrl) {
                    videoUrl = row.querySelector('a[href*="watch?v="]')?.href || '';
                }

                // Log what we found
                if (downloadUrl) {
                    log(`[Downloader] Successfully extracted download URL for "${videoTitle}": ${downloadUrl}`, 'success');
                } else {
                    log(`[Downloader] No download URL found for "${videoTitle}" - will be stored as null`, 'warn');
                }

                if (videoUrl) {
                    log(`[Downloader] YouTube watch URL for "${videoTitle}": ${videoUrl}`, 'info');
                }

            } catch (error) {
                log(`[Downloader] Error extracting URLs for "${videoTitle}": ${error.message}`, 'warn');

                // Still try to get the YouTube watch URL even if download URL extraction failed
                const editLink = row.querySelector('a[href*="/edit"]');
                if (editLink?.href) {
                    const match = editLink.href.match(/\/video\/([a-zA-Z0-9_-]{11})\/edit/);
                    if (match) {
                        videoUrl = `https://www.youtube.com/watch?v=${match[1]}`;
                    }
                }
                if (!videoUrl) {
                    videoUrl = row.querySelector('a[href*="watch?v="]')?.href || '';
                }

                // Note: downloadUrl remains empty/null if extraction failed
                log(`[Downloader] Download URL extraction failed for "${videoTitle}" - will be stored as null`, 'warn');
            }

            for (let attempt = 0; attempt <= maxRetries; attempt++) {
                if (bulkDownloaderState.stop) {
                    log(`[Downloader] [FAILED] "${videoTitle}" - Couldn't be processed or fetched (stopped)`, 'error');
                    row.classList.remove('yss-dl-queued-video');
                    row.classList.add('yss-dl-failed-video');
                    await setDownloaderVideoState(videoId, DOWNLOAD_STATE_ERROR);
                    applyDownloaderStateToRow(row, DOWNLOAD_STATE_ERROR);
                    errorCount++;
                    break;
                }

                result = await downloadVideoForRow(row, videoId, attempt);

                if (result.success) {
                    log(`[Downloader] [DOWNLOADED] "${videoTitle}" - Successfully processed video`, 'success');
                    row.classList.remove('yss-dl-queued-video');
                    row.classList.add('yss-dl-downloaded-video');

                    // Add to download history with correct URLs
                    addToDownloaderHistory(videoId, videoTitle, videoUrl, downloadUrl);
                    await saveDownloaderHistory();

                    await setDownloaderVideoState(videoId, DOWNLOAD_STATE_DOWNLOADED);
                    applyDownloaderStateToRow(row, DOWNLOAD_STATE_DOWNLOADED);
                    processedCount++;

                    const postDownloadDelay = 2000; // Reduced from 10000ms (10s) to 2s
                    log(`[Downloader] Waiting ${postDownloadDelay / 1000}s before next...`, 'info');

                    if (!(await sleep(postDownloadDelay))) {
                        log(`[Downloader] [FAILED] "${videoTitle}" - Couldn't be processed or fetched (timeout)`, 'error');
                        row.classList.remove('yss-dl-queued-video');
                        row.classList.add('yss-dl-failed-video');
                        await setDownloaderVideoState(videoId, DOWNLOAD_STATE_ERROR);
                        applyDownloaderStateToRow(row, DOWNLOAD_STATE_ERROR);
                        errorCount++;
                        break;
                    }
                    break; // Success, exit retry loop
                } else {
                    retryCount = incrementDownloaderRetryCount(videoId);
                    log(`[Downloader] Attempt ${attempt + 1} failed for "${videoTitle}". Reason: ${result.reason}`, 'warn');

                    if (attempt < maxRetries) {
                        log(`[Downloader] Retrying in 1 second... (${retryCount}/${maxRetries})`, 'info');
                        await sleep(1000);
                    } else {
                        log(`[Downloader] [FAILED] "${videoTitle}" - Couldn't be processed or fetched (all retries failed)`, 'error');
                        row.classList.remove('yss-dl-queued-video');
                        row.classList.add('yss-dl-failed-video');
                        addToFailedVideos(videoId, videoTitle, videoUrl, null, result.reason);
                        await saveDownloaderHistory();
                        await setDownloaderVideoState(videoId, DOWNLOAD_STATE_ERROR);
                        applyDownloaderStateToRow(row, DOWNLOAD_STATE_ERROR);
                        errorCount++;
                        // Don't stop the entire process, just continue to next video
                        break;
                    }
                }
            }
        }

        log("[Downloader] Saving final video states...", 'info');
        await saveDownloaderVideoStates();

        // Log page summary
        log(`[Downloader] --- Page Processing Finished ---`, 'info');
        log(`[Downloader] Downloads Initiated: ${processedCount}`, 'info');
        log(`[Downloader] Skipped (Already Done): ${skippedCount}`, 'info');
        log(`[Downloader] Errors/Stopped: ${errorCount}`, 'info');
        log(`[Downloader] -----------------------------`, 'info');
        if (useManualSelection) {
            log(`[Downloader] Manually Selected: ${selectedCheckboxes.length}, Skipped (Not Selected): ${manualSkippedCount}`, 'info');
        }
        log(`[Downloader] Downloads Initiated: ${processedCount}`, 'success');
        log(`[Downloader] Skipped (Already Done): ${skippedCount}`, 'info');
        log(`[Downloader] Errors/Stopped: ${errorCount}`, errorCount > 0 ? 'error' : 'info');
        log(`[Downloader] -----------------------------`, 'info');

        return {
            processed: true,
            finished: !bulkDownloaderState.stop,
            processedCount: processedCount
        };
    };

    // Multi-page downloader process
    const processDownloaderAllPages = async () => {
        if (bulkDownloaderState.stop) {
            return {
                processed: false,
                finished: false
            };
        }

        // Clear any existing download state classes from video rows
        const allVideoRows = document.querySelectorAll('ytcp-video-row');
        allVideoRows.forEach(row => {
            row.classList.remove('yss-dl-queued-video', 'yss-dl-already-video', 'yss-dl-downloaded-video', 'yss-dl-failed-video', 'yss-dl-skipped-video');
        });

        // Get options from bulkDownloaderState
        const options = bulkDownloaderState.options || {};
        const maxVideos = options.maxVideos || 0;

        log(`[Downloader] Starting multi-page download process...`, 'info');
        log(`[Downloader] Global options: maxVideos=${maxVideos}`, 'info');
        let totalProcessed = 0,
            totalSkipped = 0,
            totalErrors = 0;
        let pageNumber = 1;
        let hasMorePages = true;

        while (hasMorePages && !bulkDownloaderState.stop) {
            log(`[Downloader] --- Processing Page ${pageNumber} ---`, 'info');

            // Check if we've reached the global maxVideos limit before processing this page
            if (maxVideos > 0 && totalProcessed >= maxVideos) {
                log(`[Downloader] Reached global maximum videos limit (${maxVideos}). Stopping multi-page processing.`, 'info');
                break;
            }

            // Process current page
            const {
                processed,
                finished,
                processedCount: pageProcessedCount
            } = await processDownloaderCurrentPage(pageNumber);

            if (bulkDownloaderState.stop) {
                log(`[Downloader] Stop requested on page ${pageNumber}.`, 'warn');
                break;
            }

            if (!processed) {
                log(`[Downloader] No videos found on page ${pageNumber}.`, 'warn');
                break;
            }

            // Update total processed count
            totalProcessed += pageProcessedCount || 0;
            log(`[Downloader] Page ${pageNumber} processed ${pageProcessedCount || 0} videos. Total processed: ${totalProcessed}${maxVideos > 0 ? `/${maxVideos}` : ''}`, 'info');

            // If there were errors on this page, don't continue to next page
            if (!finished) {
                log(`[Downloader] Errors occurred on page ${pageNumber}. Stopping navigation.`, 'warn');
                break;
            }

            // Check if we've reached the global maxVideos limit
            if (maxVideos > 0 && totalProcessed >= maxVideos) {
                log(`[Downloader] Reached global maximum videos limit (${maxVideos}). Stopping multi-page processing.`, 'info');
                break;
            }

            // Try to navigate to next page
            log(`[Downloader] Attempting to navigate to next page...`, 'info');
            const navigationSuccess = await clickNextPageButton();

            if (!navigationSuccess) {
                log(`[Downloader] No more pages available. Finished processing all pages.`, 'success');
                hasMorePages = false;
                break;
            }

            // Wait for page to load
            log(`[Downloader] Waiting for page ${pageNumber + 1} to load...`, 'info');
            if (!(await sleep(3000))) { // Wait 3 seconds for page load
                log(`[Downloader] Stop requested during page navigation.`, 'warn');
                break;
            }

            // Wait for videos to load on new page
            await waitForVideosToLoadDl(10000);

            pageNumber++;
        }

        log(`[Downloader] --- Multi-Page Processing Complete ---`, 'info');
        log(`[Downloader] Total Pages Processed: ${pageNumber}`, 'success');
        log(`[Downloader] Total Videos Processed: ${totalProcessed}${maxVideos > 0 ? `/${maxVideos}` : ''}`, 'success');
        log(`[Downloader] -----------------------------`, 'info');

        return {
            processed: true,
            finished: !bulkDownloaderState.stop
        };
    };

    // Main downloader process controller
    const startDownloaderProcess = async () => {
        try {
            const options = bulkDownloaderState.options || {};
            const processingMode = options.processingMode || 'live';

            if (processingMode === 'manual') {
                await showManualSelectionMode();
                // Manual selection handles its own reset. It is a self-contained flow.
                // We return here so the finally block doesn't run unnecessarily.
                return;
            }

            if (processingMode === 'prefetch-only' || processingMode === 'prefetch') {
                const allVideos = await prefetchAllVideos(options);

                // If user stopped, the log is already inside prefetchAllVideos.
                // The crucial part is to check if we have any videos to show.
                if (allVideos.length > 0) {
                    log(`[Downloader] Pre-fetch finished/stopped. Proceeding to comparison with ${allVideos.length} videos.`, 'info');
                    bulkDownloaderState.lastPrefetchData = {
                        videos: allVideos,
                        timestamp: Date.now()
                    };
                    saveLastPrefetchData();

                    const importedFiles = (processingMode === 'prefetch') ? loadImportedFilesFromStorage() : [];
                    const comparisonResult = await showVideoComparisonModal(allVideos, importedFiles);

                    if (comparisonResult && comparisonResult.action === 'confirm') {
                        // User wants to download. This is a continuation of the process.
                        bulkDownloaderState.stop = false; // Reset stop flag for the download part.
                        await processConfirmedVideos(comparisonResult.videos);
                    }
                } else {
                    log("[Downloader] No videos were collected during pre-fetch.", 'warn');
                    if (!bulkDownloaderState.stop) {
                        alert("No videos found to process.");
                    }
                }
            } else { // 'live' mode
                log(`[Downloader] Starting live processing...`, 'info');
                await processDownloaderCurrentPage(1);
                // After finishing the page, show the summary
                setTimeout(() => showDownloaderSummaryModal(), 1000);
            }
        } catch (error) {
            log(`[Downloader] CRITICAL SCRIPT ERROR: ${error.message}`, 'error');
            console.error('[Downloader] Critical error:', error);
            alert('A critical error occurred: ' + error.message);
        } finally {
            // This 'finally' block now ONLY handles the case where the process finishes on its own.
            // User-initiated stops are handled in the onBulkDownloaderClick handler.
            if (!bulkDownloaderState.stop) {
                log("[Downloader] Process finished naturally. Finalizing and cleaning up UI.", 'info');
                resetBulkDownloaderUI();
            } else {
                log("[Downloader] Process was stopped by user; UI cleanup was already triggered.", 'info');
            }
        }
    };




    async function onBulkDownloaderClick() {
        if (bulkDownloaderState.isRunning) {
            log("[Downloader] Stop requested by user. Process will halt.", "warn");
            bulkDownloaderState.stop = true;

            if (bulkDownloaderBtn.smartButton) {
                bulkDownloaderBtn.smartButton.setText('Stopping...');
                bulkDownloaderBtn.disabled = true;
            }

            // Give the running process a moment to see the stop flag.
            // Then, force a UI reset regardless of the process's state.
            setTimeout(() => {
                log("[Downloader] Forcing UI reset after stop request.", "info");
                resetBulkDownloaderUI();
            }, 1500); // 1.5-second delay
            return;
        }

        // --- Start a new process ---
        if (!window.location.href.includes('/videos/upload')) {
            const contentLink = document.querySelector('ytcp-navigation-drawer a[href*="/videos/upload"]');
            if (contentLink) {
                contentLink.click();
            } else {
                window.location.href = 'https://studio.youtube.com/channel/CH/videos/upload';
            }
            return;
        }

        const options = await showDownloaderProcessingOptionsModal();
        if (!options) {
            log("[Downloader] Process cancelled by user.", "info");
            return;
        }

        bulkDownloaderState.isRunning = true;
        bulkDownloaderState.stop = false;
        bulkDownloaderState.options = options;
        setActiveProcess('bulkDownloader');
        startDownloaderProcess();
    }

    async function startQuickPageNavigation() {
        let isRunning = false;
        let currentPage = 1;
        let pageCount = 0;
        let stopRequested = false;

        // Variables to store the original button's state
        let originalButton = null;
        let originalButtonChildNodes = []; // Will store an array of nodes, not an HTML string
        let originalButtonClasses = null;
        let originalButtonTooltip = null;

        // --- SAVING STATE ---
        // Find the button and store its original state
        const bulkDownloaderBtn = document.getElementById('yss-bulk-downloader-btn');
        if (bulkDownloaderBtn) {
            originalButton = bulkDownloaderBtn;
            // Create a deep clone of all child nodes (e.g., the <i> icon and text)
            originalButtonChildNodes = Array.from(bulkDownloaderBtn.childNodes).map(node => node.cloneNode(true));
            originalButtonClasses = bulkDownloaderBtn.className;
            originalButtonTooltip = bulkDownloaderBtn.getAttribute('data-tooltip');
        }

        // --- RESTORING STATE ---
        // Function to restore the original button's appearance and functionality
        const restoreOriginalButton = () => {
            if (originalButton && originalButtonChildNodes.length > 0) {
                // 1. Clear any current content (like the stop icon and counter)
                originalButton.textContent = ''; // Safely removes all child nodes

                // 2. Append the saved original child nodes back into the button
                originalButtonChildNodes.forEach(node => {
                    originalButton.appendChild(node);
                });

                // 3. Restore the original classes, tooltip, and enabled state
                originalButton.className = originalButtonClasses;
                if (originalButtonTooltip) {
                    originalButton.setAttribute('data-tooltip', originalButtonTooltip);
                } else {
                    originalButton.removeAttribute('data-tooltip');
                }
                originalButton.disabled = false;
            }
        };

        // Function to update both counters consistently
        const updateCounters = () => {
            if (floatingCounter) {
                floatingCounterSpan.textContent = `${pageCount}`;
            }
            if (counterDiv) {
                counterDiv.textContent = `Page: ${pageCount}`;
            }
        };

        // Function to disable/enable UI controls
        const disableUI = (disable) => {
            const yssControls = document.querySelector('.yss-controls');
            if (yssControls) {
                if (disable) {
                    yssControls.classList.add('disabled');
                } else {
                    yssControls.classList.remove('disabled');
                }
            }
        };

        // Function to continue navigation after pause
        const continueNavigation = async () => {
            try {
                while (!stopRequested && isRunning) {
                    const nextPageBtn = document.querySelector('ytcp-icon-button#navigate-after:not([disabled])');
                    if (!nextPageBtn) {
                        statusDiv.textContent = 'Reached last page or no more pages';
                        statusDiv.style.background = '#ffc107';
                        break;
                    }

                    nextPageBtn.click();
                    pageCount++;
                    currentPage++;

                    // Update both counters consistently
                    updateCounters();

                    // Log the page navigation
                    log(`[QuickNav] Navigated to page ${pageCount}`, 'info');

                    await sleep(500);

                    let waitCount = 0;
                    const maxWait = 50;
                    while (waitCount < maxWait && !stopRequested && isRunning) {
                        const currentNextBtn = document.querySelector('ytcp-icon-button#navigate-after:not([disabled])');
                        if (currentNextBtn && currentNextBtn !== nextPageBtn) {
                            break;
                        }
                        await sleep(100);
                        waitCount++;
                    }

                    if (stopRequested || !isRunning) break;
                }

                // Only complete if not stopped
                if (isRunning && !stopRequested) {
                    // Process completed normally
                    isRunning = false;
                    startBtn.textContent = 'Start Navigation';
                    startBtn.style.cssText = '';
                    pauseBtn.style.display = 'none';
                    floatingCounter.style.display = 'none';
                    disableUI(false);
                    statusDiv.textContent = 'Navigation completed';
                    statusDiv.style.background = '#28a745';
                }
            } catch (error) {
                log(`[QuickNav] Error during resumed navigation: ${error.message}`, 'error');
                statusDiv.textContent = `Error: ${error.message}`;
                statusDiv.style.background = '#dc3545';
                isRunning = false;
                disableUI(false);
            }
        };


        // Create minimal floating counter
        const floatingCounter = document.createElement('button');
        floatingCounter.id = 'yss-floating-counter';
        floatingCounter.className = 'yss-btn yss-btn-primary';
        floatingCounter.textContent = 'Page: ';

        const floatingCounterIcon = createIcon('fa-solid fa-window-restore');
        floatingCounter.prepend(floatingCounterIcon);

        const floatingCounterSpan = document.createElement('span');
        floatingCounterSpan.textContent = `${pageCount}`;
        floatingCounter.appendChild(floatingCounterSpan);

        floatingCounter.style.display = 'none'; // Initially hidden
        document.body.appendChild(floatingCounter);

        // Create status and counter elements
        const statusDiv = document.createElement('div');
        statusDiv.id = 'quick-nav-status';
        statusDiv.textContent = 'Ready to start navigation';

        const counterDiv = document.createElement('div');
        counterDiv.id = 'quick-nav-counter';
        counterDiv.textContent = 'Page: 0';

        // Create the modal using YSSModalBuilder
        const quickNavModal = new YSSModalBuilder('Quick Page Navigation', {
            id: 'yss-quick-nav-modal',
            maxWidth: '400px',
            isSticky: true,
            showBackButton: true,
            draggable: true
        });

        // Set content (status and counter)
        quickNavModal.setContent([statusDiv, counterDiv]);

        // Create Smart Buttons for the modal
        console.log('QuickNav: Creating smart buttons...');
        const smartButtons = {
            minimize: createSmartButton({
                id: 'yss-modal-minimize',
                text: 'Minimize',
                icon: 'fa-solid fa-minus',
                classes: ['yss-btn', 'yss-btn-secondary'],
                tooltip: 'Minimize navigation modal',
                handlers: {
                    onClick: (e, btn) => {
                        console.log('QuickNav: Minimize button clicked!');
                        quickNavModal.getOverlay().style.display = 'none';
                        floatingCounter.style.display = 'flex';
                        updateCounters(); // Update counter before showing
                    }
                }
            }),

            pause: createSmartButton({
                id: 'quick-nav-pause',
                text: 'Pause',
                icon: 'fa-solid fa-pause',
                classes: ['yss-btn', 'yss-btn-warning'],
                tooltip: 'Pause/Resume page navigation',
                states: {
                    'pause': {
                        icon: 'fa-solid fa-pause',
                        text: 'Pause',
                        classes: ['yss-btn', 'yss-btn-warning'],
                        tooltip: 'Pause page navigation'
                    },
                    'resume': {
                        icon: 'fa-solid fa-play',
                        text: 'Resume',
                        classes: ['yss-btn', 'yss-btn-primary'],
                        tooltip: 'Resume page navigation'
                    }
                },
                handlers: {
                    onClick: (e, btn) => {
                        console.log('QuickNav: Pause button clicked!');
                        console.log(`QuickNav: Pause button clicked. Current state: ${btn.currentState}, isRunning: ${isRunning}, stopRequested: ${stopRequested}`);

                        if (isRunning && !stopRequested) {
                            // Pause the process
                            stopRequested = true;
                            btn.setState('resume');
                            statusDiv.textContent = 'Navigation paused';
                            statusDiv.style.background = '#6c6c6c';
                            log('[QuickNav] Navigation paused', 'info');
                        } else if (isRunning && stopRequested) {
                            // Resume the process
                            stopRequested = false;
                            btn.setState('pause');
                            statusDiv.textContent = 'Navigating pages...';
                            statusDiv.style.background = '#28a745';
                            log('[QuickNav] Navigation resumed', 'info');

                            // Continue navigation in background
                            continueNavigation();
                        }
                    }
                }
            }),

            start: createSmartButton({
                id: 'quick-nav-start',
                text: 'Start Navigation',
                icon: 'fa-solid fa-play',
                classes: ['yss-btn', 'yss-btn-primary'],
                tooltip: 'Start/Stop page navigation',
                states: {
                    'start': {
                        icon: 'fa-solid fa-play',
                        text: 'Start Navigation',
                        classes: ['yss-btn', 'yss-btn-primary'],
                        tooltip: 'Start page navigation'
                    },
                    'stop': {
                        icon: 'fa-solid fa-stop',
                        text: 'Stop Navigation',
                        classes: ['yss-btn', 'yss-btn-stop'],
                        tooltip: 'Stop page navigation'
                    }
                },
                handlers: {
                    onClick: async (e, btn) => {
                        console.log('QuickNav: Start button clicked!');
                        console.log(`QuickNav: Start button clicked. Current state: ${btn.currentState}, isRunning: ${isRunning}`);

                        if (isRunning) {
                            // Stop the process completely
                            stopRequested = true;
                            isRunning = false;
                            btn.setState('start');

                            // Update status
                            statusDiv.textContent = 'Navigation stopped';
                            statusDiv.style.background = '#dc3545';

                            // Reset pause button to pause state and hide it, also re-enable UI
                            smartButtons.pause.setState('pause');
                            smartButtons.pause.hide();
                            floatingCounter.style.display = 'none';
                            disableUI(false); // Re-enable UI

                            // Log final navigation summary
                            log(`[QuickNav] Navigation stopped. Total pages navigated: ${pageCount}`, 'info');

                            // Close modal and clean up
                            quickNavModal.close();
                            floatingCounter.remove();
                            return;
                        }

                        // Start the process
                        isRunning = true;
                        btn.setState('stop');
                        stopRequested = false;

                        // Update status and enable UI
                        statusDiv.textContent = 'Navigating pages...';
                        statusDiv.style.background = '#28a745';
                        disableUI(true); // Disable UI during navigation

                        // Show pause button and floating counter, ensure it's in pause state and enabled
                        smartButtons.pause.setState('pause');
                        smartButtons.pause.show();
                        smartButtons.pause.enable();
                        floatingCounter.style.display = 'flex';

                        try {
                            while (!stopRequested && isRunning) {
                                const nextPageBtn = document.querySelector('ytcp-icon-button#navigate-after:not([disabled])');
                                if (!nextPageBtn) {
                                    statusDiv.textContent = 'Reached last page or no more pages';
                                    statusDiv.style.background = '#ffc107';
                                    break;
                                }

                                nextPageBtn.click();
                                pageCount++;
                                currentPage++;

                                // Update both counters consistently
                                updateCounters();

                                // Log the page navigation
                                log(`[QuickNav] Navigated to page ${pageCount}`, 'info');

                                await sleep(500);

                                let waitCount = 0;
                                const maxWait = 50;
                                while (waitCount < maxWait && !stopRequested && isRunning) {
                                    const currentNextBtn = document.querySelector('ytcp-icon-button#navigate-after:not([disabled])');
                                    if (currentNextBtn && currentNextBtn !== nextPageBtn) {
                                        break;
                                    }
                                    await sleep(100);
                                    waitCount++;
                                }

                                if (stopRequested || !isRunning) break;
                            }
                        } catch (error) {
                            log(`[QuickNav] Error during navigation: ${error.message}`, 'error');
                            statusDiv.textContent = `Error: ${error.message}`;
                            statusDiv.style.background = '#dc3545';
                        }

                        // Only reset if not stopped (i.e., completed normally)
                        if (!stopRequested) {
                            isRunning = false;
                            btn.setState('start');
                            smartButtons.pause.hide();
                            floatingCounter.style.display = 'none';
                            disableUI(false); // Re-enable UI
                            statusDiv.textContent = 'Navigation completed';
                            statusDiv.style.background = '#28a745';
                        }
                    }
                }
            })
        };



        // Add Smart Buttons to the modal and connect click handlers
        Object.values(smartButtons).forEach(btn => {
            console.log(`QuickNav: Processing button ${btn.id}:`, {
                hasHandlers: !!btn.handlers,
                hasOnClick: !!btn.handlers?.onClick,
                element: btn.element,
                elementOnclick: btn.element.onclick
            });

            quickNavModal.elements.leftActions.appendChild(btn.element);


            //console.log(`QuickNav: Added smart button ${btn.id} with state ${btn.currentState}`);
        });

        // Show the modal
        quickNavModal.show();

        // Add back button functionality
        const backBtn = quickNavModal.getModal().querySelector('.yss-btn-back');
        if (backBtn) {
            backBtn.onclick = () => {
                quickNavModal.close();
                // Return to the downloader processing options modal
                showDownloaderProcessingOptionsModal();
            };
        }

        // Add close button functionality
        const closeBtn = quickNavModal.getModal().querySelector('.yss-close-btn');
        if (closeBtn) {
            closeBtn.onclick = () => {
                stopRequested = true;
                isRunning = false;
                disableUI(false); // Re-enable UI
                floatingCounter.remove();
                quickNavModal.close();
            };
        }

        // Add floating counter click functionality
        floatingCounter.addEventListener('click', () => {
            // Toggle modal visibility
            const modalOverlay = quickNavModal.getOverlay();
            if (modalOverlay.style.display === 'none' || modalOverlay.style.display === '') {
                modalOverlay.style.display = 'flex';
                floatingCounter.style.display = 'none';
            } else {
                modalOverlay.style.display = 'none';
                floatingCounter.style.display = 'block';
            }
        });

        // Original button functionality is preserved - no interference with QuickNav
    }
    // Reset bulk downloader UI
    function resetBulkDownloaderUI() {
        bulkDownloaderState.isRunning = false;
        bulkDownloaderState.stop = false;
        bulkDownloaderState.isPaused = false;
        bulkDownloaderState.options = null;

        clearActiveProcess(); // This handles resetting the main panel buttons correctly.
    }



    // =================================================================================
    //       SECTION 4.8: BULK UPLOADER
    // =================================================================================
    let masterFileInput = null; // This will hold our persistent file input element

    /**
     * Creates and appends a single, hidden file input to the body.
     * This element will persist across modal openings to hold the selected files.
     */
    function ensureMasterFileInput() {
        if (!document.getElementById('yss-master-file-input')) {
            masterFileInput = document.createElement('input');
            masterFileInput.id = 'yss-master-file-input';
            masterFileInput.type = 'file';
            masterFileInput.multiple = true;
            masterFileInput.accept = 'video/mp4,video/quicktime,video/x-msvideo,video/x-matroska,.mov,.mpeg4,.mp4,.avi,.wmv,.mpegps,.flv,.3gpp,.webm';
            masterFileInput.style.display = 'none';
            document.body.appendChild(masterFileInput);
        } else {
            masterFileInput = document.getElementById('yss-master-file-input');
        }
    }

    /**
     * Checks on page load if this tab should automatically continue an upload process.
     */
    async function initializeUploaderOnLoad() {
        ensureMasterFileInput(); // Make sure the master input exists
        try {
            const batchIndex = GM_getValue('YSS_UPLOADER_BATCH_INDEX', -1);
            if (batchIndex !== -1 && !bulkUploaderState.isRunning) {
                // An upload process is active. Let's continue it.
                log(`[Uploader] Auto-starting: Continuing upload process at Batch #${batchIndex + 1}.`, 'info');
                startUploadProcess();
            }
        } catch (e) {
            log(`[Uploader] Error during auto-initialization: ${e.message}`, 'error');
        }
    }

    /**
     * Main click handler for the Bulk Uploader button.
     */
    async function onBulkUploaderClick() {
        if (bulkUploaderState.isRunning) {
            log('[Uploader] Stop requested by user. Halting all upload tasks.', 'warn');
            bulkUploaderState.stop = true;

            const indicator = UPLOADS_MINI_INDICATOR_SELECTOR;
            if (indicator) {
                const UPLOADS_MINI_INDICATOR_CANCEL_BUTTON_SELECTOR = indicator.querySelectorAll('.cancel-button');
                log(`[Uploader] Attempting to cancel ${UPLOADS_MINI_INDICATOR_CANCEL_BUTTON_SELECTOR.length} ongoing uploads...`, 'info');
                UPLOADS_MINI_INDICATOR_CANCEL_BUTTON_SELECTOR.forEach(btn => btn.click());
            }

            // Let the central UI manager handle the button state
            if (bulkUploaderBtn.smartButton) {
                bulkUploaderBtn.smartButton.setText('Stopping...');
                bulkUploaderBtn.disabled = true;
            }
        } else {
            const userSelection = await showUploaderModal();
            if (userSelection && userSelection.files.length > 0) {
                log(`[Uploader] User confirmed upload for ${userSelection.files.length} files.`, 'info');
                bulkUploaderState.fileQueue = userSelection.files;

                // --- NEW LOGIC: DYNAMICALLY SET THE TOTAL ---
                // Get the process config for the uploader
                const uploaderProcessConfig = processConfig.bulkUploader;
                if (uploaderProcessConfig && uploaderProcessConfig.counterConfig) {
                    // Set the manualTotal to the number of files the user selected
                    uploaderProcessConfig.counterConfig.manualTotal = userSelection.files.length;
                }

                // Now, start the process. setActiveProcess will read the updated config.
                setActiveProcess('bulkUploader');
                startUploadProcess();
            } else {
                log('[Uploader] Upload process cancelled or no files selected.', 'info');
            }
        }
    }

    /**
     * Resets the UI and state for the Bulk Uploader.
     */
    function resetUploaderUI() {
        bulkUploaderState.isRunning = false;
        bulkUploaderState.stop = false;
        bulkUploaderState.fileQueue = [];
        if (masterFileInput) {
            masterFileInput.value = ''; // Clear the selected files from the persistent input
        }

        if (bulkUploaderBtn && bulkUploaderBtn.smartButton) {
            bulkUploaderBtn.smartButton.setText(' Uploader');
            bulkUploaderBtn.smartButton.setIcon('fa-solid fa-cloud-arrow-up');
            bulkUploaderBtn.classList.remove('yss-btn-stop');
            bulkUploaderBtn.disabled = false;
            bulkUploaderBtn.smartButton.hideCounter();
        }
        clearActiveProcess(); // This handles resetting the main panel buttons correctly.

    }


    /**
     * Displays the modal for selecting files and starting the upload process.
     * Now includes functionality to select either individual files or an entire folder.
     * @returns {Promise<null|{files: File[]}>} A promise that resolves with selected files or null if cancelled.
     */
    async function showUploaderModal() {
        const modal = new YSSModalBuilder('Bulk Video Uploader', {
            maxWidth: '700px',
            isSticky: true,
            showBackButton: false
        });

        // Use the module's state to hold the files for this modal instance
        bulkUploaderState.fileQueue = [];

        // --- 1. Create Modal Content Elements ---
        const fileInput = document.createElement('input');
        fileInput.id = 'yss-uploader-file-input';
        fileInput.type = 'file';
        fileInput.multiple = true;
        fileInput.accept = 'video/mp4,video/quicktime,video/x-msvideo,video/x-matroska,.mov,.mpeg4,.mp4,.avi,.wmv,.mpegps,.flv,.3gpp,.webm';
        fileInput.style.display = 'none';

        const fileListContainer = document.createElement('div');
        fileListContainer.className = 'yss-videolist-container';

        const placeholder = document.createElement('div');
        placeholder.className = 'yss-noFiles';
        placeholder.textContent = 'Click "Add Files" or "Add Folder" to choose videos for upload.';
        fileListContainer.appendChild(placeholder);

        const summaryContainer = document.createElement('div');
        summaryContainer.className = 'yss-summary-table';
        const summaryTitle = document.createElement('div');
        summaryTitle.className = 'yss-summary-title';
        summaryTitle.textContent = 'Upload Queue Summary';
        const summaryRows = document.createElement('div');
        summaryRows.className = 'yss-summary-rows';
        const countRow = document.createElement('div');
        countRow.textContent = 'Files Selected: ';
        const countStrong = document.createElement('strong');
        countStrong.textContent = '0';
        countRow.appendChild(countStrong);
        summaryRows.appendChild(countRow);
        const duplicateRow = document.createElement('div');
        duplicateRow.className = 'duplicated-uploads'; // Class for styling
        duplicateRow.style.display = 'none'; // Initially hidden
        duplicateRow.textContent = 'Duplicated Uploads: ';
        const duplicateStrong = document.createElement('strong');
        duplicateStrong.textContent = '0';
        duplicateRow.appendChild(duplicateStrong);
        summaryRows.appendChild(duplicateRow)
        summaryContainer.appendChild(summaryTitle);
        summaryContainer.appendChild(summaryRows);

        const toggleStatsBtn = modal.createToggleStatsButton();
        summaryTitle.appendChild(toggleStatsBtn);




        //const handleSelect = () => fileInput.click();

        // Handler for selecting individual files
        const handleSelectFiles = () => {
            // Ensure webkitdirectory is NOT set, to allow file selection
            fileInput.removeAttribute('webkitdirectory');
            fileInput.click();
        };

        // NEW: Handler for selecting a folder
        const handleSelectFolder = () => {
            // Set webkitdirectory to enable folder selection
            fileInput.setAttribute('webkitdirectory', true);
            fileInput.click();
        };



        const handleClear = () => {
            bulkUploaderState.fileQueue = []; // Clear the state array
            _populateFileListUI(fileListContainer, []); // Update UI
            countStrong.textContent = '0';
            smartButtons.start.disable(); // Disable start button
            fileInput.value = ''; // Reset the actual input so you can re-select the same files
        };

        const handleHistory = () => {
            modal.close();
            showUploaderHistoryModal();
        };

        const handleStart = () => {
            const history = GM_getValue(bulkUploaderState.storageKey, []);
            const successfulDuplicates = bulkUploaderState.fileQueue.filter(file => {
                const historyEntry = history.find(h => h.filename === file.name);
                return historyEntry && historyEntry.status === 'success';
            });

            if (successfulDuplicates.length > 0) {
                if (!confirm(`You have ${successfulDuplicates.length} file(s) in the queue that were already successfully uploaded.\n\nAre you sure you want to upload these duplicates again?`)) {
                    return; // Abort the start process
                }
            }

            // Pass the final, cumulative list of files when closing
            modal.close({
                files: bulkUploaderState.fileQueue
            });
        };

        // --- 3. Define Button Configurations ---
        const buttonConfigs = {
            clear: {
                id: 'yss-uploader-clear',
                text: 'Clear List',
                icon: 'fa-solid fa-trash',
                classes: ['yss-btn', 'yss-btn-stop'],
                position: 'left',
                handlers: { onClick: handleClear },
                tooltip: 'Remove all files from the current queue.'
            },
            history: {
                id: 'yss-uploader-history',
                text: 'View History',
                icon: 'fa-solid fa-history',
                classes: ['yss-btn', 'yss-btn-secondary'],
                position: 'left',
                handlers: { onClick: handleHistory },
                tooltip: 'View the history of past uploads.'
            },
            // NEW: Folder Select Button
            folderSelect: {
                id: 'yss-uploader-folder-select',
                text: 'Add Folder',
                icon: 'fa-solid fa-folder-plus',
                classes: ['yss-btn', 'yss-btn-secondary'],
                position: 'right',
                handlers: { onClick: handleSelectFolder },
                tooltip: 'Select a folder to add all video files within it to the queue.'
            },
            // MODIFIED: Original file select button
            select: {
                id: 'yss-uploader-select',
                text: 'Add Files',
                icon: 'fa-solid fa-plus',
                classes: ['yss-btn', 'yss-btn-green'],
                position: 'right',
                handlers: { onClick: handleSelectFiles },
                tooltip: 'Select one or more individual video files to add to the queue.'
            },
            start: {
                id: 'yss-uploader-start',
                text: 'Start Upload',
                icon: 'fa-solid fa-upload',
                classes: ['yss-btn', 'yss-btn-primary'],
                position: 'right',
                handlers: { onClick: handleStart },
                disabled: true,
                tooltip: 'Begin the bulk upload process.'
            },
        };

        // --- 4. Create the Smart Buttons ---
        const smartButtons = setupModalButtons(modal, buttonConfigs);

        if (bulkUploaderState.fileQueue.length > 0) {
            smartButtons.start.enable();
        } else {
            smartButtons.start.disable();
        }
        fileInput.addEventListener('change', (event) => {
            const newFiles = Array.from(event.target.files);
            const existingFilenames = new Set(bulkUploaderState.fileQueue.map(f => f.name));

            const uniqueNewFiles = newFiles.filter(f => !existingFilenames.has(f.name));

            if (uniqueNewFiles.length > 0) {
                bulkUploaderState.fileQueue.push(...uniqueNewFiles);
                _populateFileListUI(fileListContainer, bulkUploaderState.fileQueue);
                countStrong.textContent = bulkUploaderState.fileQueue.length;
            }

            if (bulkUploaderState.fileQueue.length > 0) {
                smartButtons.start.enable();
            } else {
                smartButtons.start.disable();
            }

            // IMPORTANT: Reset the input value to allow selecting the same files/folder again after clearing.
            fileInput.value = '';
        });


        // --- 6. Set Content and Show Modal ---
        modal.setContent([fileInput, summaryContainer, fileListContainer]);

        return modal.show();
    }

    /**
     * Populates the file list UI inside the uploader modal.
     * @param {HTMLElement} container - The container element to populate.
     * @param {File[]} files - An array of File objects.
     */
    function _populateFileListUI(container, files) {
        const history = GM_getValue(bulkUploaderState.storageKey, []);
        let duplicateCount = 0;

        // --- Get the summary elements from the modal ---
        const duplicateRow = document.querySelector('.duplicated-uploads');
        const duplicateStrong = duplicateRow ? duplicateRow.querySelector('strong') : null;

        while (container.firstChild) {
            container.removeChild(container.firstChild);
        }

        if (files.length === 0) {
            const placeholder = document.createElement('div');
            placeholder.className = 'yss-noFiles';
            placeholder.textContent = 'Click "Add Files" to choose videos for upload.';
            container.appendChild(placeholder);
            if (duplicateRow) duplicateRow.style.display = 'none'; // Hide counter if no files
            return;
        }

        const table = document.createElement('table');
        const thead = document.createElement('thead');
        const headerRow = document.createElement('tr');
        ['#', 'Filename', 'Size'].forEach(text => {
            const th = document.createElement('th');
            th.textContent = text;
            headerRow.appendChild(th);
        });
        thead.appendChild(headerRow);
        table.appendChild(thead);

        const tbody = document.createElement('tbody');
        files.forEach((file, index) => {
            const row = document.createElement('tr');
            row.dataset.filename = file.name; // Add filename for easy removal

            // --- Check for duplicates in history ---
            const historyEntry = history.find(h => h.filename === file.name);
            if (historyEntry) {
                duplicateCount++;
                row.classList.add('yss-uploaded-file');
                if (historyEntry.status !== 'success') {
                    row.classList.add('failed');
                    row.dataset.tooltip = "This file was attempted before but failed. Check content just in case.";
                } else {
                    row.dataset.tooltip = "This file was successfully uploaded before. Consider removing it from the queue.";
                }
                row.dataset.tooltipAlign = "left";
            }

            const cellNum = document.createElement('td');
            cellNum.className = 'yss-index-cell';
            cellNum.textContent = index + 1;

            const cellName = document.createElement('td');
            cellName.className = 'yss-title-cell';
            cellName.textContent = file.name;

            const cellSize = document.createElement('td');
            cellSize.textContent = `${(file.size / 1024 / 1024).toFixed(2)} MB`;

            row.appendChild(cellNum);
            row.appendChild(cellName);
            row.appendChild(cellSize);

            // --- Add Delete Button to ALL rows ---
            const deleteBtn = document.createElement('button');
            deleteBtn.className = 'yss-btn yss-delete yss-btn-icon';
            deleteBtn.dataset.tooltip = "Remove this file";
            const deleteIcon = createIcon('fa-solid fa-trash');
            const deleteSpan = document.createElement('span');
            deleteSpan.textContent = 'Delete';
            deleteBtn.appendChild(deleteIcon);
            deleteBtn.appendChild(deleteSpan);

            deleteBtn.addEventListener('click', (e) => {
                e.stopPropagation(); // Prevent row click events if any
                const filenameToRemove = row.dataset.filename;
                // Filter the file out of the main state array
                bulkUploaderState.fileQueue = bulkUploaderState.fileQueue.filter(f => f.name !== filenameToRemove);
                // Re-render the entire list with the updated queue
                _populateFileListUI(container, bulkUploaderState.fileQueue);
                // Update the main file count in the summary
                const countStrong = document.querySelector('.yss-summary-rows strong');
                if (countStrong) countStrong.textContent = bulkUploaderState.fileQueue.length;
                // Re-check and potentially disable the Start button
                const startBtn = document.getElementById('yss-uploader-start');
                if (startBtn) startBtn.disabled = bulkUploaderState.fileQueue.length === 0;
            });

            // Append the delete button directly to the TR element
            row.appendChild(deleteBtn);
            tbody.appendChild(row);
        });

        // Update and show/hide the duplicate counter
        if (duplicateStrong && duplicateRow) {
            if (duplicateCount > 0) {
                duplicateStrong.textContent = duplicateCount;
                duplicateRow.style.display = '';
            } else {
                duplicateRow.style.display = 'none';
            }
        }

        table.appendChild(tbody);
        container.appendChild(table);
    }
    /**
     * Shows a modal prompting the user to select the specific files for the current batch.
     * @param {object[]} batchInfo - An array of file info objects {name, size}.
     * @param {number} batchNum - The current batch number (e.g., 1, 2, 3).
     * @param {number} totalBatches - The total number of batches.
     * @returns {Promise<File[]|null>} A promise resolving with the File objects, or null if cancelled.
     */
    async function promptForFiles(batchInfo, batchNum, totalBatches) {
        const modal = new YSSModalBuilder(`Upload Batch ${batchNum} of ${totalBatches}`, {
            maxWidth: '700px',
            isSticky: true
        });

        const instructionText = document.createElement('p');
        instructionText.textContent = `Please select the following ${batchInfo.length} files for this batch:`;

        const fileListContainer = document.createElement('div');
        fileListContainer.className = 'yss-videolist-container';
        _populateFileListUI(fileListContainer, batchInfo); // We can reuse the UI populator

        const fileInput = document.createElement('input');
        fileInput.type = 'file';
        fileInput.multiple = true;
        fileInput.style.display = 'none';

        modal.setContent([instructionText, fileListContainer, fileInput]);

        return new Promise(resolve => {
            const handleSelect = () => fileInput.click();
            const handleCancel = () => {
                modal.close();
                resolve(null);
            };

            const buttons = setupModalButtons(modal, {
                cancel: {
                    id: 'prompt-cancel',
                    text: 'Cancel Upload',
                    classes: ['yss-btn', 'yss-btn-stop'],
                    position: 'left',
                    handlers: {
                        onClick: handleCancel
                    }
                },
                select: {
                    id: 'prompt-select',
                    text: `Select ${batchInfo.length} Files...`,
                    classes: ['yss-btn', 'yss-btn-primary'],
                    position: 'right',
                    handlers: {
                        onClick: handleSelect
                    }
                }
            });

            fileInput.onchange = (event) => {
                const selectedFiles = Array.from(event.target.files);
                if (selectedFiles.length !== batchInfo.length) {
                    alert(`Incorrect number of files selected. Please select exactly ${batchInfo.length} files for this batch.`);
                    return;
                }
                // A more robust check could verify filenames, but this is a good start.
                modal.close();
                resolve(selectedFiles);
            };

            modal.show();
        });
    }

    //Main control for bulk uploader key selectors from youtube studio  UI.

    const CREATE_BUTTON_SELECTOR = 'ytcp-button#create-icon, .ytcpAppHeaderCreateIcon';
    const CREATE_MENU_CANDIDATE_SELECTOR = 'ytcp-text-menu#creation-menu, .ytcpAppHeaderCreationMenu';
    const UPLOAD_MENU_ITEM_SELECTOR = 'tp-yt-paper-item[test-id="upload-beta"], ytcp-text-menu-item#upload-video, ytcp-text-menu-item[role="menuitem"]:nth-child(1), .ytcpAppHeaderUploadVideoMenuItem, tp-yt-paper-item[test-id="upload"]';
    const UPLOAD_DIALOG_CANDIDATE_SELECTOR = 'ytcp-uploads-dialog, ytcp-uploads-dialog[open], .yss-upload-dialog';
    const PAPER_DIALOG_SELECTOR = 'tp-yt-paper-dialog';
    const UPLOADS_MINI_INDICATOR_SELECTOR = 'ytcp-uploads-mini-indicator';
    const UPLOADS_CURRENT_MINI_INDICATOR = document.querySelector('ytcp-uploads-mini-indicator');

    const UPLOADS_PROGRESS_MONITOR_CLOSE_BTN_SELECTOR = 'ytcp-multi-progress-monitor #close-button';
    const UPLOADS_PROGRESS_MONITOR_HEADER_SELECTOR = 'ytcp-multi-progress-monitor .header span.count';
    const UPLOADS_FILE_INPUT_SELECTOR = 'input[type="file"][name="Filedata"]';


    //Main control function for the entire upload process. Handles batching and multi-tab logic.

    async function startUploadProcess() {
        bulkUploaderState.isRunning = true;
        if (bulkUploaderBtn.smartButton) {
            bulkUploaderBtn.smartButton.setText('Stop');
            bulkUploaderBtn.smartButton.setIcon('fa-solid fa-stop');
            bulkUploaderBtn.classList.add('yss-btn-stop');
        }

        const fullQueue = [...bulkUploaderState.fileQueue];
        const batchSize = bulkUploaderState.batchSize;
        let allResults = {
            successful: [],
            failed: []
        };

        for (let i = 0; i < fullQueue.length; i += batchSize) {
            if (bulkUploaderState.stop) {
                log('[Uploader] Process stopped by user.', 'warn');
                break;
            }

            const batch = fullQueue.slice(i, i + batchSize);
            const batchNumber = (i / batchSize) + 1;
            const totalBatches = Math.ceil(fullQueue.length / batchSize);
            log(`[Uploader] Starting Batch ${batchNumber} of ${totalBatches} (${batch.length} files)...`, 'info');

            let batchResults;
            try {
                // Open the main YouTube upload dialog
                const uploadDialog = await openUploadDialog();
                if (!uploadDialog) throw new Error("Failed to open upload dialog.");
                if (bulkUploaderState.stop) break; // Check for stop after dialog opens

                // Assign the files to the dialog's hidden input
                const assignmentSuccess = await uploadFileBatch(uploadDialog, batch);
                if (!assignmentSuccess) throw new Error("Failed to assign files to the input.");
                if (bulkUploaderState.stop) break;

                // Monitor the mini-indicator until all files in the batch are processed
                batchResults = await monitorUploadProgress(batch);

                // Add this batch's results to the cumulative total
                allResults.successful.push(...batchResults.successful);
                allResults.failed.push(...batchResults.failed);

            } catch (error) {
                log(`[Uploader] FATAL ERROR during Batch ${batchNumber}: ${error.message}`, 'error');
                // If a batch fails catastrophically, mark all its files as failed and stop
                const failedResults = batch.map(file => ({
                    filename: file.name,
                    status: 'error',
                    reason: error.message,
                    timestamp: new Date().toISOString()
                }));
                allResults.failed.push(...failedResults);
                break;
            }

            // --- THIS IS THE MODIFIED LOGIC ---
            // Check if there are more batches to process and if the user hasn't stopped the process
            if ((i + batchSize) < fullQueue.length && !bulkUploaderState.stop) {
                log(`[Uploader] Batch ${batchNumber} complete. Preparing for next batch in 5 seconds...`, 'info');
                // Add a delay to allow the UI to fully settle after closing the upload indicator.
                await sleep(5000);
            }
        }

        log(`[Uploader] === UPLOAD PROCESS FINISHED ===`, 'info');

        // Load the existing history
        const existingHistory = GM_getValue(bulkUploaderState.storageKey, []);
        // Combine the old history with the results of this new session
        const newHistory = existingHistory.concat(allResults.successful, allResults.failed);
        // Save the combined, cumulative history
        GM_setValue(bulkUploaderState.storageKey, newHistory);
        log(`[Uploader] Saved ${allResults.successful.length} successful and ${allResults.failed.length} failed results to history.`, 'info');

        resetUploaderUI();
        showUploaderHistoryModal();
    }

    /**
     * Automates the clicks to open the main upload dialog using a robust, step-by-step polling method.
     * @returns {Promise<HTMLElement|null>} The dialog element or null on failure.
     */
    async function openUploadDialog() {
        try {
            // --- Step 1 & 2: Click the 'Create' button ---
            log('[Uploader] Step 1: Locating "Create" button...', 'info');


            const createButton = await waitForElement(CREATE_BUTTON_SELECTOR, document, 5000);
            if (!createButton) throw new Error('"Create" button (#create-icon) not found.');

            log('[Uploader] Step 2: Clicking "Create" button...', 'info');
            await simulateNaturalInteraction(createButton);
            await sleep(500);

            // if (bulkUploaderState.stop) return null; // Temporarily commented for testing

            // --- Step 3: Patiently POLLING for the creation menu ---
            log('[Uploader] Step 3: Polling for visible creation menu...', 'info');
            let creationMenu = null;
            let waitedMenu = 0;
            const timeoutMenu = 8000;

            while (waitedMenu < timeoutMenu) {
                // if (bulkUploaderState.stop) return null; // Temporarily commented for testing
                const menuCandidate = document.querySelector(CREATE_MENU_CANDIDATE_SELECTOR);
                if (menuCandidate && menuCandidate.offsetParent !== null) {
                    creationMenu = menuCandidate;
                    break;
                }
                await new Promise(r => setTimeout(r, 250));
                waitedMenu += 250;
            }
            if (!creationMenu) throw new Error("Creation dropdown menu (#creation-menu) did not become visible.");
            log('[Uploader] Step 3 successful: Found creation menu.', 'success');

            // --- Step 4 & 5: Click the 'Upload videos' item ---
            log('[Uploader] Step 4: Locating "Upload videos" item...', 'info');
            const uploadMenuItem = await waitForElement(UPLOAD_MENU_ITEM_SELECTOR, creationMenu, 5000);
            if (!uploadMenuItem) throw new Error('"Upload videos" menu item not found.');

            log('[Uploader] Step 5: Clicking "Upload videos"...', 'info');
            await simulateNaturalInteraction(uploadMenuItem);
            await sleep(1000); // Wait for the main dialog to start appearing

            // if (bulkUploaderState.stop) return null; // Temporarily commented for testing

            // --- Step 6: Patiently POLLING for the FINAL UPLOAD DIALOG ---
            // THIS IS THE NEW, CRITICAL FIX
            log('[Uploader] Step 6: Polling for final upload dialog...', 'info');
            let uploadDialog = null;
            let waitedDialog = 0;
            const timeoutDialog = 10000; // Give it 10 seconds

            while (waitedDialog < timeoutDialog) {
                // if (bulkUploaderState.stop) return null; // Temporarily commented for testing
                const dialogCandidate = document.querySelector(UPLOAD_DIALOG_CANDIDATE_SELECTOR);

                // Check if the dialog exists and is visible on screen
                if (dialogCandidate && dialogCandidate.offsetParent !== null) {
                    uploadDialog = dialogCandidate;
                    break; // Success!
                }

                await new Promise(r => setTimeout(r, 250));
                waitedDialog += 250;
            }

            if (!uploadDialog) throw new Error('Final upload dialog (ytcp-uploads-dialog) did not appear.');
            log('[Uploader] Upload dialog opened successfully.', 'success');
            return uploadDialog;

        } catch (error) {
            log(`[Uploader] Error in openUploadDialog: ${error.message}`, 'error');
            // Clean up any partially opened menus on failure
            const lingeringMenu = document.querySelector(CREATE_MENU_CANDIDATE_SELECTOR);
            if (lingeringMenu) {
                const parentDialog = lingeringMenu.closest(PAPER_DIALOG_SELECTOR);
                if (parentDialog) parentDialog.remove();
            }
            return null;
        }
    }

    /**
     * Directly assigns a batch of files to the hidden file input.
     * @param {HTMLElement} uploadDialog - The upload dialog element.
     * @param {File[]} batch - The array of File objects to upload.
     * @returns {Promise<boolean>} A promise that resolves to true if files were assigned, false otherwise.
     */
    async function uploadFileBatch(uploadDialog, batch) {

        log(`[Uploader] Polling for hidden file input inside the dialog...`, 'info');
        let fileInput = null;
        let waited = 0;
        const timeout = 7000;

        while (waited < timeout) {
            const inputCandidate = uploadDialog.querySelector(UPLOADS_FILE_INPUT_SELECTOR);
            if (inputCandidate) {
                fileInput = inputCandidate;
                break;
            }
            await new Promise(r => setTimeout(r, 250));
            waited += 250;
        }

        if (!fileInput) {
            log('[Uploader] Could not find the hidden file input after polling.', 'error');
            return false; // Return false on failure
        }

        log(`[Uploader] Found hidden file input. Assigning ${batch.length} files directly...`, 'info');
        const dataTransfer = new DataTransfer();
        batch.forEach(file => dataTransfer.items.add(file));
        fileInput.files = dataTransfer.files;
        fileInput.dispatchEvent(new Event('change', {
            bubbles: true
        }));

        log('[Uploader] File input change event dispatched.', 'success');
        return true; // Return true to indicate the action was performed
    }

    /**
     * Checks the header of the mini-indicator for the global completion message.
     * @returns {boolean} True if the "Upload complete" message is found.
     */
    function _checkGlobalUploadCompletion() {
        const indicatorHeader = document.querySelector(UPLOADS_PROGRESS_MONITOR_HEADER_SELECTOR);
        if (indicatorHeader && indicatorHeader.textContent.toLowerCase().includes('upload complete')) {
            return true;
        }
        return false;
    }

    /**
     * Monitors the mini upload indicator to track batch progress using robust polling.
     * @param {File[]} batch - An array of File objects for the current batch.
     * @returns {Promise<{successful: object[], failed: object[]}>}
     */
    async function monitorUploadProgress(batch) {
        const batchSize = batch.length;
        log(`[Uploader] Monitoring progress for ${batchSize} files...`, 'info');
        const results = {
            successful: [],
            failed: []
        };
        const processedFiles = new Set();
        const batchFilenames = new Set(batch.map(f => f.name));
        const lastLoggedStatus = new Map();

        log('[Uploader] Polling for the upload indicator to appear and populate...', 'info');
        let indicator = null;
        let waited = 0;
        const indicatorTimeout = 25000; // Increased to 25 seconds for safety

        while (waited < indicatorTimeout) {
            if (bulkUploaderState.stop) {
                throw new Error("Process stopped by user while waiting for indicator.");
            }


            const indicatorCandidate = document.querySelector(UPLOADS_MINI_INDICATOR_SELECTOR);
            // Check if it exists, is visible, AND contains at least one list item
            if (indicatorCandidate && indicatorCandidate.offsetParent !== null && indicatorCandidate.querySelector('li.row')) {
                indicator = indicatorCandidate;
                break;
            }
            await new Promise(r => setTimeout(r, 500));
            waited += 500;
        }

        if (!indicator) {
            // This is now the single point of failure if the indicator truly never shows up.
            throw new Error('Monitoring failed: Upload indicator never appeared or was dismissed.');
        }
        log('[Uploader] Upload indicator is active. Starting main monitoring loop.', 'info');
        // --- End of Definitive Fix ---

        let monitorTimeout = 300 * 1000 * batchSize; // 5 minutes per video
        const interval = 2000;

        while (processedFiles.size < batchSize && monitorTimeout > 0 && !bulkUploaderState.stop) {
            await sleep(interval);
            monitorTimeout -= interval;

            const currentIndicator = document.querySelector(UPLOADS_MINI_INDICATOR_SELECTOR);
            if (!currentIndicator) {
                log('[Uploader] Upload indicator disappeared. Assuming batch is done.', 'warn');
                break;
            }

            const rows = currentIndicator.querySelectorAll('li.row');
            rows.forEach(row => {
                const titleEl = row.querySelector('.progress-title');
                const statusEl = row.querySelector('.progress-status-text');
                if (!titleEl || !statusEl) return;

                const filename = titleEl.textContent.trim();
                if (processedFiles.has(filename) || !batchFilenames.has(filename)) return;

                const statusText = statusEl.textContent.trim().toLowerCase();

                if (lastLoggedStatus.get(filename) !== statusText && !statusText.includes('waiting')) {
                    log(`[Uploader] STATUS UPDATE for "${filename}": ${statusText}`, 'info');
                    lastLoggedStatus.set(filename, statusText);
                }

                const successKeywords = ['upload complete', '100% uploaded', 'processing complete', 'finished processing', 'checks complete'];
                const failureKeywords = ['upload failed', 'upload canceled', 'error'];
                const isSuccess = successKeywords.some(keyword => statusText.includes(keyword));
                const isFailure = failureKeywords.some(keyword => statusText.includes(keyword));

                if (isSuccess) {
                    processedFiles.add(filename);
                    results.successful.push({
                        filename,
                        status: 'success',
                        timestamp: new Date().toISOString()
                    });
                    log(`[Uploader] SUCCESS: "${filename}" (${processedFiles.size}/${batchSize})`, 'success');
                } else if (isFailure) {
                    processedFiles.add(filename);
                    results.failed.push({
                        filename,
                        status: 'error',
                        timestamp: new Date().toISOString(),
                        reason: statusText
                    });
                    log(`[Uploader] FAILED: "${filename}" (${processedFiles.size}/${batchSize})`, 'error');
                }
            });

            if (_checkGlobalUploadCompletion()) {
                log('[Uploader] Global "Upload complete" status detected. Finalizing batch.', 'success');
                break;
            }
        }

        batch.forEach(file => {
            if (!processedFiles.has(file.name)) {
                const reason = bulkUploaderState.stop ? 'Process stopped by user.' : 'Monitoring timed out or final status was not detected.';
                results.failed.push({
                    filename: file.name,
                    status: 'error',
                    timestamp: new Date().toISOString(),
                    reason
                });
                log(`[Uploader] FAILED (Post-Loop): "${file.name}"`, 'error');
            }
        });
        const closeIndicatorBtn = document.querySelector(UPLOADS_PROGRESS_MONITOR_CLOSE_BTN_SELECTOR);
        if (closeIndicatorBtn) {
            await sleep(2000);
            closeIndicatorBtn.click();
        }

        return results;
    }


    async function showUploaderHistoryModal() {
        const history = GM_getValue(bulkUploaderState.storageKey, []);

        const modal = new YSSModalBuilder('Bulk Uploader History', {
            isSticky: true,
            maxWidth: '700px',
            showBackButton: true,
            onBack: () => showUploaderModal(),
            counter: history.length
        });

        const tableContainer = document.createElement('div');
        tableContainer.className = 'yss-videolist-container';

        if (history.length === 0) {
            const noHistory = document.createElement('div');
            noHistory.className = 'yss-noFiles';
            noHistory.textContent = 'No upload history found.';
            tableContainer.appendChild(noHistory);
        } else {
            const table = document.createElement('table');
            table.id = 'uploader-history-table'; // ID for the sorter to find

            // --- 1. Create Header with Data Attributes using DOM methods ---
            const thead = document.createElement('thead');
            const headerRow = document.createElement('tr');

            // Define headers with their sort keys
            const headers = [{
                text: '#',
                key: 'index'
            },
            {
                text: 'Filename',
                key: 'filename'
            },
            {
                text: 'Status',
                key: null
            }, // Not sortable
            {
                text: 'Timestamp',
                key: 'timestamp'
            }
            ];

            headers.forEach(header => {
                const th = document.createElement('th');
                th.textContent = header.text;
                if (header.key) {
                    // This is the crucial part: setting the dataset property
                    th.dataset.sortKey = header.key;
                }
                headerRow.appendChild(th);
            });

            thead.appendChild(headerRow);
            table.appendChild(thead);



            // --- 2. Create Table Body with Data Values for Sorting ---
            const tbody = document.createElement('tbody');

            // Add a stable, original index to each history item before sorting/displaying
            const historyWithIndex = history.map((item, index) => ({
                ...item,
                originalIndex: index + 1
            }));

            // Show newest uploads first by default (by reversing the array)
            historyWithIndex.reverse().forEach(item => {
                const row = document.createElement('tr');
                const isSuccess = item.status === 'success';
                const timestamp = new Date(item.timestamp);

                // --- CREATE AND APPEND CELLS ---

                // # Column: Always displays the original, stable index.
                const cellNum = document.createElement('td');
                cellNum.className = 'yss-index-cell';
                cellNum.textContent = item.originalIndex;
                cellNum.dataset.value = item.originalIndex; // Use this for sorting '#' column

                // Filename Column
                const cellName = document.createElement('td');
                cellName.className = 'yss-title-cell';
                cellName.textContent = item.filename;
                // No data-value needed; the sorter will use textContent for alphabetical sort.

                // Status Column
                const cellStatus = document.createElement('td');
                cellStatus.className = 'yss-status-cell';
                cellStatus.textContent = isSuccess ? '✅ Success' : '❌ Error';
                cellStatus.style.color = isSuccess ? 'var(--yss-log-success)' : 'var(--yss-log-error)';

                // Timestamp Column
                const cellTime = document.createElement('td');
                cellTime.className = 'yss-time-cell';
                cellTime.textContent = timestamp.toLocaleString();
                cellTime.dataset.value = timestamp.getTime(); // Use numeric timestamp for correct date sorting

                row.appendChild(cellNum);
                row.appendChild(cellName);
                row.appendChild(cellStatus);
                row.appendChild(cellTime);
                tbody.appendChild(row);
            });
            table.appendChild(tbody);
            tableContainer.appendChild(table);
        }

        modal.setContent([tableContainer]);



        const handleClearHistory = () => {
            if (confirm("Are you sure you want to clear the entire upload history? This cannot be undone.")) {
                GM_setValue(bulkUploaderState.storageKey, []);
                modal.close();
                showUploaderHistoryModal(); // Re-open to show it's empty
            }
        };

        const handleExportHistory = () => {
            const historyToExport = GM_getValue(bulkUploaderState.storageKey, []);
            if (historyToExport.length === 0) {
                alert('No history to export.');
                return;
            }
            const dataStr = JSON.stringify(historyToExport, null, 2);
            const blob = new Blob([dataStr], {
                type: 'application/json;charset=utf-8;'
            });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `yss-uploader-history-${new Date().toISOString().slice(0, 10)}.json`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        };

        const buttonConfigs = {
            clear: {
                id: 'yss-uploader-clear-history',
                text: 'Clear History',
                icon: 'fa-solid fa-trash',
                classes: ['yss-btn', 'yss-btn-clear'],
                position: 'left',
                handlers: {
                    onClick: handleClearHistory
                }
            },
            export: {
                id: 'yss-uploader-export-history',
                text: 'Export History',
                icon: 'fa-solid fa-file-export',
                classes: ['yss-btn', 'yss-btn-secondary'],
                position: 'left',
                handlers: {
                    onClick: handleExportHistory
                }
            },
            close: {
                id: 'yss-uploader-close-history',
                text: 'Close',
                icon: 'fa-solid fa-times',
                classes: ['yss-btn', 'yss-btn-secondary'],
                position: 'right',
                handlers: {
                    onClick: () => modal.close()
                }
            }
        };
        setupModalButtons(modal, buttonConfigs);

        modal.show();

        // --- 3. Initialize the Table Sorter AFTER the browser's next paint cycle ---
        // This is the crucial fix for the timing issue.
        requestAnimationFrame(() => {
            const tableElement = document.getElementById('uploader-history-table');
            if (tableElement) {
                console.log("TableSorter: Initializing...");
                new TableSorter(tableElement, {
                    key: 'timestamp',
                    reverse: true
                });
            } else {
                console.error("TableSorter: Could not find table element after modal was shown.");
            }
        });
    }


    // =================================================================================
    //       SECTION 4.9.2: Transcript Downloader (MERGED - With Summary Modal)
    //       Base: 4.9.1 (working) + New Features from 4.9.2
    // =================================================================================

    // --- State & Timers ---
    let nextVideoNavigationTimer = null;
    let isHandlingDownload = false;
    let currentVideoDownloaded = false; // Track if current video has been downloaded to prevent duplicates
    let currentProcessingVideoUrl = null; // Track which video is currently being processed

    // --- URL Check Utility ---
    /**
     * Checks if we're on www.youtube.com (not studio.youtube.com)
     * Batch processes should only run on www.youtube.com
     */
    function isOnYouTubeWatchPage() {
        return window.location.href.startsWith('https://www.youtube.com/') &&
            !window.location.href.startsWith('https://www.youtube.com/studio') &&
            !window.location.href.startsWith('https://studio.youtube.com/');
    }

    // --- Utility Functions ---
    function td_sleep(ms) { return new Promise(resolve => setTimeout(resolve, ms)); }
    async function td_waitForElement(selector, timeout = 15000, parent = document) {
        const startTime = Date.now();
        while (Date.now() - startTime < timeout) {
            const element = parent.querySelector(selector);
            if (element && (element.offsetParent !== null || parent === document || element.closest('ytd-transcript-renderer'))) {
                return element;
            }
            await td_sleep(800);
        }
        log(`[TranscriptDL] Element not found: ${selector}`, 'warn');
        return null;
    }

    /**
     * Observes DOM changes to wait for transcript loading to complete.
     * Watches for the loading spinner to disappear and segments to appear.
     * In persistent mode, will wait longer (up to 120 seconds) until segments appear.
     */
    async function td_waitForTranscriptLoad(timeout = 15000, persistent = false) {
        return new Promise((resolve) => {
            const startTime = Date.now();
            // In persistent mode, use a much longer timeout (2 minutes)
            const maxTimeout = persistent ? 120000 : timeout;
            let contentContainer = document.querySelector('#content.ytd-engagement-panel-section-list-renderer');

            // If container not found initially, wait a bit for it to appear
            if (!contentContainer) {
                const waitForContainer = setInterval(() => {
                    contentContainer = document.querySelector('#content.ytd-engagement-panel-section-list-renderer');
                    if (contentContainer) {
                        clearInterval(waitForContainer);
                        startObserving();
                    } else if (Date.now() - startTime >= 5000) {
                        clearInterval(waitForContainer);
                        log('[TranscriptDL] Content container not found for observation.', 'warn');
                        resolve(false);
                    }
                }, 500);
                return;
            }

            const checkForLoadedTranscript = () => {
                // Re-check container in case DOM changed
                if (!contentContainer) {
                    contentContainer = document.querySelector('#content.ytd-engagement-panel-section-list-renderer');
                }

                if (!contentContainer) return false;

                const loadingRenderer = contentContainer.querySelector('yt-content-loading-renderer[panel-content-visible]');
                const spinner = loadingRenderer?.querySelector('tp-yt-paper-spinner#spinner[aria-label="Loading..."]');
                const segmentsContainer = document.querySelector('div#segments-container');
                const segments = segmentsContainer?.querySelectorAll('ytd-transcript-segment-renderer');

                // If segments are loaded, transcript is ready
                if (segments && segments.length > 0) {
                    // Only log in non-persistent mode to reduce noise
                    if (!persistent) {
                        log('[TranscriptDL] Transcript segments loaded successfully.', 'success');
                    }
                    resolve(true);
                    return true;
                }

                return false;
            };

            const startObserving = () => {
                // Initial check
                if (checkForLoadedTranscript()) return;

                // Set up MutationObserver to watch for changes
                const observer = new MutationObserver(() => {
                    // Removed pause check - allow current video to complete even if paused
                    if (checkForLoadedTranscript()) {
                        observer.disconnect();
                        if (intervalId) clearInterval(intervalId);
                    } else if (Date.now() - startTime >= maxTimeout) {
                        observer.disconnect();
                        if (intervalId) clearInterval(intervalId);
                        // Only log timeout in non-persistent mode to reduce noise
                        if (!persistent) {
                            log(`[TranscriptDL] Maximum timeout (${maxTimeout / 1000}s) reached waiting for transcript to load.`, 'warn');
                        }
                        resolve(false);
                    }
                });

                // Also use interval as fallback
                let intervalId = setInterval(() => {
                    // Removed pause check - allow current video to complete even if paused
                    if (checkForLoadedTranscript()) {
                        observer.disconnect();
                        clearInterval(intervalId);
                    } else if (Date.now() - startTime >= maxTimeout) {
                        observer.disconnect();
                        clearInterval(intervalId);
                        // Only log timeout in non-persistent mode to reduce noise
                        if (!persistent) {
                            log(`[TranscriptDL] Maximum timeout (${maxTimeout / 1000}s) reached waiting for transcript to load (interval).`, 'warn');
                        }
                        resolve(false);
                    }
                }, 500);

                observer.observe(contentContainer, {
                    childList: true,
                    subtree: true,
                    attributes: true,
                    attributeFilter: ['panel-content-visible', 'aria-label']
                });

                // Set maximum timeout (even in persistent mode, we need a limit)
                setTimeout(() => {
                    observer.disconnect();
                    clearInterval(intervalId);
                    // CHANGED: Check if batch was paused
                    if (persistent && !GM_getValue(GM_KEYS.td_batchProcessActive, false)) {
                        log('[TranscriptDL] Batch was paused during timeout, aborting transcript load wait.', 'info');
                        resolve(false);
                        return;
                    }
                    if (checkForLoadedTranscript()) {
                        resolve(true);
                    } else {
                        log(`[TranscriptDL] Maximum timeout (${maxTimeout / 1000}s) reached waiting for transcript to load (final).`, 'warn');
                        resolve(false);
                    }
                }, maxTimeout);
            };

            startObserving();
        });
    }

    /**
     * Forces transcript reload by switching to Timeline tab then back to Transcript tab.
     */
    async function td_forceTranscriptReload() {
        log('[TranscriptDL] Attempting to force transcript reload...', 'info');
        try {
            // Wait for engagement panel to be fully loaded
            const header = await td_waitForElement('ytd-engagement-panel-title-header-renderer', 5000);
            if (!header) {
                log('[TranscriptDL] Could not find engagement panel header.', 'warn');
                return false;
            }

            // Wait for subheader to appear
            const subheader = await td_waitForElement('div#subheader', 5000, header);
            if (!subheader) {
                log('[TranscriptDL] Could not find subheader.', 'warn');
                return false;
            }

            // Wait for Timeline button - try multiple selectors
            let timelineButton = await td_waitForElement('button[aria-label="Timeline"]', 5000, subheader);
            if (!timelineButton) {
                // Try alternative selector
                timelineButton = await td_waitForElement('button[aria-label*="Timeline"], button[title*="Timeline"]', 3000, subheader);
            }
            if (!timelineButton) {
                // Try finding by text content
                const allButtons = subheader.querySelectorAll('button, yt-chip-chip-renderer button, .ytChipBarViewModelChipWrapper button');
                for (const btn of allButtons) {
                    const text = btn.textContent?.trim() || btn.getAttribute('aria-label') || '';
                    if (text.toLowerCase().includes('timeline')) {
                        timelineButton = btn;
                        break;
                    }
                }
            }
            if (!timelineButton) {
                log('[TranscriptDL] Could not find Timeline button.', 'warn');
                return false;
            }

            // Click Timeline to switch tabs
            timelineButton.click();
            await td_sleep(1500);

            // Wait for Transcript button - try multiple selectors
            let transcriptButton = await td_waitForElement('button[aria-label="Transcript"]', 5000, subheader);
            if (!transcriptButton) {
                transcriptButton = await td_waitForElement('button[aria-label*="Transcript"], button[title*="Transcript"]', 3000, subheader);
            }
            if (!transcriptButton) {
                // Try finding by text content
                const allButtons = subheader.querySelectorAll('button, yt-chip-chip-renderer button, .ytChipBarViewModelChipWrapper button');
                for (const btn of allButtons) {
                    const text = btn.textContent?.trim() || btn.getAttribute('aria-label') || '';
                    if (text.toLowerCase().includes('transcript')) {
                        transcriptButton = btn;
                        break;
                    }
                }
            }
            if (!transcriptButton) {
                log('[TranscriptDL] Could not find Transcript button.', 'warn');
                return false;
            }

            // Click Transcript to switch back and force reload
            transcriptButton.click();
            log('[TranscriptDL] Forced transcript reload by tab switching.', 'info');
            await td_sleep(1500);
            return true;
        } catch (error) {
            log(`[TranscriptDL] Error forcing transcript reload: ${error.message}`, 'error');
            return false;
        }
    }

    const getPlaylistParserPolicy = (() => {
        let policy = null; let policyAttempted = false;
        return () => {
            if (policy) return policy; if (policyAttempted) return null;
            policyAttempted = true;
            if (typeof window.trustedTypes !== 'undefined' && window.trustedTypes.createPolicy) {
                try {
                    policy = window.trustedTypes.createPolicy('ytdPlaylistParserPolicy#userscript', { createHTML: (s) => s });
                } catch (e) { log(`[TranscriptDL] Failed to create TrustedHTML policy: ${e.message}`, 'warn'); policy = null; }
            } return policy;
        };
    })();

    // --- Optimized Draggable Functionality (Shared for modals and other components) ---
    // This is a simplified version of makeDraggable without height management
    function td_makeDraggable(el, keyPosX, keyPosY) {
        const handle = el.querySelector('.yss-modal-title');
        if (!handle) return;

        let isDragging = false;
        let rafId = null;
        let initialRect = null;
        let initialMouseX = 0;
        let currentMouseX = 0;
        let initialMouseY = 0;
        let currentMouseY = 0;

        // Cache for dimensions
        let cachedElWidth = 0;
        let cachedElHeight = 0;
        let cachedViewportWidth = 0;
        let cachedViewportHeight = 0;

        const updateCachedDimensions = () => {
            const rect = el.getBoundingClientRect();
            cachedElWidth = rect.width;
            cachedElHeight = rect.height;
            cachedViewportWidth = window.innerWidth;
            cachedViewportHeight = window.innerHeight;
        };

        // Optimized drag function using requestAnimationFrame
        const performDrag = () => {
            if (!isDragging) return;

            const deltaX = currentMouseX - initialMouseX;
            const deltaY = currentMouseY - initialMouseY;

            // Calculate new position from initial rect
            let newLeft = initialRect.left + deltaX;
            let newTop = initialRect.top + deltaY;

            // Update cached dimensions if viewport might have changed
            if (cachedViewportWidth !== window.innerWidth || cachedViewportHeight !== window.innerHeight) {
                updateCachedDimensions();
            }

            // Constrain to viewport bounds
            newLeft = Math.max(0, Math.min(newLeft, cachedViewportWidth - cachedElWidth));
            newTop = Math.max(0, Math.min(newTop, cachedViewportHeight - cachedElHeight));

            // Apply position using transform for better performance (GPU accelerated)
            el.style.transform = `translate(${newLeft - initialRect.left}px, ${newTop - initialRect.top}px)`;
            el.style.willChange = 'transform';

            // Continue animation loop
            rafId = requestAnimationFrame(performDrag);
        };

        handle.style.cursor = 'move';

        handle.addEventListener('mousedown', (e) => {
            // Prevent dragging from interactive elements
            if (e.target.closest('button, input, textarea, select, a, label')) return;
            const panel = e.currentTarget.closest('.yss-modal-content');
            if (panel && panel.classList.contains('docked')) return;

            e.preventDefault();
            e.stopPropagation();

            // Initialize drag state
            isDragging = true;
            initialRect = el.getBoundingClientRect();
            initialMouseX = e.clientX;
            initialMouseY = e.clientY;
            currentMouseX = e.clientX;
            currentMouseY = e.clientY;

            // Cache initial dimensions
            updateCachedDimensions();

            // Unset right/bottom styles if they exist
            if (el.style.right !== 'auto' || el.style.bottom !== 'auto') {
                el.style.right = 'auto';
                el.style.bottom = 'auto';
            }

            // Get current position (accounting for any existing transform)
            const currentRect = el.getBoundingClientRect();
            el.style.top = currentRect.top + 'px';
            el.style.left = currentRect.left + 'px';
            el.style.transform = '';

            // Add dragging class for CSS styling
            el.classList.add('dragging');
            handle.style.cursor = 'grabbing';
            document.body.style.userSelect = 'none';

            // Use passive event listeners for better performance
            document.addEventListener('mousemove', handleMouseMove, { passive: false });
            document.addEventListener('mouseup', closeDragElement, { once: true });

            // Start animation loop
            rafId = requestAnimationFrame(performDrag);
        });

        const handleMouseMove = (e) => {
            if (!isDragging) return;
            e.preventDefault();
            currentMouseX = e.clientX;
            currentMouseY = e.clientY;
        };

        function closeDragElement() {
            if (!isDragging) return;

            isDragging = false;

            // Cancel animation frame
            if (rafId !== null) {
                cancelAnimationFrame(rafId);
                rafId = null;
            }

            // Remove event listeners
            document.removeEventListener('mousemove', handleMouseMove);
            document.removeEventListener('mouseup', closeDragElement);

            // Remove dragging class
            el.classList.remove('dragging');
            handle.style.cursor = 'move';
            document.body.style.userSelect = '';

            // Get final position (transform is still applied)
            const finalRect = el.getBoundingClientRect();
            const finalTop = finalRect.top;
            const finalLeft = finalRect.left;

            // Convert transform back to top/left for persistence
            el.style.transform = '';
            el.style.willChange = 'auto';
            el.style.top = finalTop + 'px';
            el.style.left = finalLeft + 'px';

            // Save the final position using the provided GM keys
            GM_setValue(keyPosX, el.style.left);
            GM_setValue(keyPosY, el.style.top);
        }
    }

    /** Toggles the visibility of the batch panel. */
    function onTranscriptDownloaderClick() {
        // CHANGED: Only work on www.youtube.com
        if (!isOnYouTubeWatchPage()) {
            log('[TranscriptDL] Batch panel not available on studio.youtube.com.', 'warn');
            return;
        }

        const batchWrapper = getOrCreateTranscriptBatchPanel();
        if (!batchWrapper) return;

        const isVisible = batchWrapper.style.display !== 'none';
        batchWrapper.style.display = isVisible ? 'none' : 'flex';
        GM_setValue(GM_KEYS.td_batchWrapperVisible, !isVisible);
        updateBatchPanelToggleButton();
    }

    /** Gets or creates the persistent batch panel UI. */
    function getOrCreateTranscriptBatchPanel(force = false) {
        // CHANGED: Only create panel on www.youtube.com, not on studio.youtube.com
        if (!isOnYouTubeWatchPage()) {
            const existingPanel = document.getElementById(TD_BUTTON_IDS.batchWrapper);
            if (existingPanel) existingPanel.remove();
            return null;
        }

        let batchWrapper = document.getElementById(TD_BUTTON_IDS.batchWrapper);
        if (batchWrapper) return batchWrapper;

        const shouldBeVisible = GM_getValue(GM_KEYS.td_batchWrapperVisible, false);
        const isDocked = GM_getValue(GM_KEYS.isTranscriptPanelDocked, false);

        // Create only when needed or explicitly forced by user action.
        if (!force && !shouldBeVisible && !isDocked) {
            return null;
        }

        return _buildTranscriptBatchPanel();
    }

    /** Builds the entire transcript batch panel UI programmatically. */
    function _buildTranscriptBatchPanel() {
        log('[TranscriptDL] Creating persistent batch panel UI...', 'info');

        const batchWrapper = document.createElement('div');
        batchWrapper.id = TD_BUTTON_IDS.batchWrapper;
        batchWrapper.className = 'yt-batch-controls-wrapper yss-modal-content yss-sticky-modal yss-batch';
        // CHANGED: Set visibility immediately based on GM key (no delay)
        const shouldBeVisible = GM_getValue(GM_KEYS.td_batchWrapperVisible, false);
        batchWrapper.style.display = shouldBeVisible ? 'flex' : 'none';

        const header = new ContentBuilder({
            tag: 'div', className: 'yss-modal-title', children: [
                { tag: 'h3', text: 'Transcript Downloader ', children: [{ id: 'yss-transcript-dock-toggle-count', tag: 'strong', text: '[Batch Process]' }] }
            ]
        }).render();
        const dockToggleBtn = createSmartButton({ id: 'yss-transcript-dock-toggle-btn', icon: 'fa-regular fa-window-restore', classes: ['yss-btn-icon', 'yss-btn-fullscreen', 'yss-btn-undock'], handlers: { onClick: toggleTranscriptPanelDocking } });
        header.appendChild(dockToggleBtn.getElement());

        const view = new ContentBuilder({
            tag: 'div', className: 'yss-modal-view', children: [
                {
                    tag: 'div', className: 'yss-form-group', children: [
                        { tag: 'textarea', id: TD_BUTTON_IDS.batchInput, placeholder: "Enter YouTube playlist URL or video URLs (one per line)" },
                        { tag: 'div', id: TD_BUTTON_IDS.batchDelayContainer, className: 'yss-form-block' }
                    ]
                },
                // CHANGED: Proper log container for cumulative entries
                { tag: 'div', id: TD_BUTTON_IDS.batchProgress, className: 'yss-log-wrapper' }
            ]
        }).render();

        const actions = new ContentBuilder({
            tag: 'div', id: TD_BUTTON_IDS.batchButtonsContainer, className: 'yt-batch-buttons-container yss-modal-actions', children: [
                { tag: 'div', className: 'yss-modal-actions-left' },
                { tag: 'div', className: 'yss-modal-actions-right' }
            ]
        }).render();

        batchWrapper.append(header, view, actions);
        document.body.appendChild(batchWrapper);

        // CHANGED: Check dock status immediately when panel is created
        const isDockedOnCreate = GM_getValue('isTranscriptPanelDocked', false);
        if (isDockedOnCreate) {
            setTranscriptPanelDockState(true, batchWrapper);
        }

        // CHANGED: Ensure panel is visible immediately if it should be
        // Force a reflow to ensure display style is applied
        batchWrapper.offsetHeight;
        if (shouldBeVisible) {
            batchWrapper.style.display = 'flex';
        }

        const delaySliderContainer = view.querySelector(`#${TD_BUTTON_IDS.batchDelayContainer}`);
        const initialDelay = GM_getValue(GM_KEYS.td_batchDownloadDelay, 5);
        const delayLabel = document.createElement('label');
        delayLabel.htmlFor = TD_BUTTON_IDS.batchDelaySlider;
        delayLabel.textContent = 'Nav Delay (s):';
        const delaySlider = document.createElement('input');
        delaySlider.type = 'range';
        delaySlider.id = TD_BUTTON_IDS.batchDelaySlider;
        delaySlider.min = '1'; delaySlider.max = '30'; delaySlider.step = '1';
        delaySlider.value = initialDelay;
        const delayValueSpan = document.createElement('span');
        delayValueSpan.id = TD_BUTTON_IDS.batchDelayValue;
        delayValueSpan.textContent = initialDelay;
        delaySlider.addEventListener('input', (e) => {
            const value = e.target.value;
            delayValueSpan.textContent = value;
            GM_setValue(GM_KEYS.td_batchDownloadDelay, parseInt(value, 10));
        });
        delaySliderContainer.append(delayLabel, delaySlider, delayValueSpan);

        const textarea = view.querySelector(`#${TD_BUTTON_IDS.batchInput}`);
        textarea.addEventListener('input', updateBatchControlsUI);

        const leftActions = actions.querySelector('.yss-modal-actions-left');
        const rightActions = actions.querySelector('.yss-modal-actions-right');
        leftActions.append(
            createSmartButton({ id: TD_BUTTON_IDS.batchStartResumeBtn, text: 'Start Batch', icon: 'fa-solid fa-play', classes: ['yss-btn', 'yss-btn-primary'], handlers: { onClick: handleStartResumeBatch } }).getElement(),
            createSmartButton({ id: TD_BUTTON_IDS.batchPauseBtn, text: 'Pause Batch', icon: 'fa-solid fa-pause', classes: ['yss-btn', 'yss-btn-warning'], handlers: { onClick: handlePauseBatch } }).getElement()
        );
        rightActions.append(
            createSmartButton({ id: TD_BUTTON_IDS.batchClearBtn, text: 'Clear Queue', icon: 'fa-solid fa-trash', classes: ['yss-btn', 'yss-btn-clear'], handlers: { onClick: onClearTranscriptQueueClick } }).getElement(),
            // CHANGED: Button now opens summary modal
            createSmartButton({ id: TD_BUTTON_IDS.batchDownloadLogBtn, text: 'View Summary', icon: 'fa-solid fa-table-list', classes: ['yss-btn', 'yss-btn-secondary'], handlers: { onClick: showTranscriptSummaryModal } }).getElement()
        );

        td_makeDraggable(batchWrapper, GM_KEYS.td_batchWrapperPosX, GM_KEYS.td_batchWrapperPosY);
        // CHANGED: Dock state already set above, just update UI
        updateBatchControlsUI();
        return batchWrapper;
    }

    /** Toggles the docked/floating state of the transcript batch panel. */
    function toggleTranscriptPanelDocking() {
        const isCurrentlyDocked = GM_getValue('isTranscriptPanelDocked', false);
        setTranscriptPanelDockState(!isCurrentlyDocked);
    }

    /** Sets the dock state of the panel and updates UI accordingly. */
    function setTranscriptPanelDockState(shouldBeDocked, panel = null) {
        panel = panel || document.getElementById(TD_BUTTON_IDS.batchWrapper);
        const dock = document.getElementById('yss-transcript-dock');
        if (!panel || !dock) return;

        const toggleBtn = panel.querySelector('#yss-transcript-dock-toggle-btn');
        if (shouldBeDocked) {
            dock.appendChild(panel);
            panel.classList.add('docked');
            panel.style.top = ''; panel.style.left = '';
            if (toggleBtn?.smartButton) {
                toggleBtn.smartButton.setIcon('fa-regular fa-window-maximize');
                toggleBtn.dataset.tooltip = 'Undock Panel';
            }
        } else {
            document.body.appendChild(panel);
            panel.classList.remove('docked');
            panel.style.left = GM_getValue(GM_KEYS.td_batchWrapperPosX, '20px');
            panel.style.top = GM_getValue(GM_KEYS.td_batchWrapperPosY, '80px');
            if (toggleBtn?.smartButton) {
                toggleBtn.smartButton.setIcon('fa-regular fa-window-restore');
                toggleBtn.dataset.tooltip = 'Dock Panel to Main UI';
            }
        }
        GM_setValue('isTranscriptPanelDocked', shouldBeDocked);
    }

    /** Updates the main toggle button's appearance based on panel visibility. */
    function updateBatchPanelToggleButton() {
        const button = document.getElementById(TD_BUTTON_IDS.batchToggleVisibilityBtn);
        if (!button?.smartButton) return;
        const isVisible = GM_getValue(GM_KEYS.td_batchWrapperVisible, false);
        if (isVisible) {
            button.smartButton.setText(' Hide Panel');
            button.smartButton.setIcon('fa-solid fa-window-minimize');
            button.classList.add('yss-btn-clear');
        } else {
            button.smartButton.setText(' Batch Process');
            button.smartButton.setIcon('fa-solid fa-layer-group');
            button.classList.remove('yss-btn-clear');
        }
    }

