    /* ============================================================
       FEED PAGE DETECTION & BODY CLASS
    ============================================================ */

    (function () { // Feed Page Detection and Body Class Injection

        "use strict";

        function isFeedPage() {
            return window.location.hostname === 'www.youtube.com' &&
                window.location.pathname.startsWith('/feed/');
        }

        function addFrontendBodyClass() {
            if (isFeedPage() && !document.body.classList.contains('yss-custom-yt-frontend')) {
                document.body.classList.add('yss-custom-yt-frontend');
                if (typeof log === 'function') {
                    log('[YT_HISTORY] Added .yss-custom-yt-frontend class to body', 'info');
                }
            }
        }

        // Add class immediately if already on feed page
        if (document.readyState === 'loading') {
            document.addEventListener('DOMContentLoaded', addFrontendBodyClass);
        } else {
            addFrontendBodyClass();
        }

        // Watch for navigation changes (YouTube SPA)
        let lastPath = window.location.pathname;
        const checkNavigation = () => {
            if (window.location.pathname !== lastPath) {
                lastPath = window.location.pathname;
                addFrontendBodyClass();

                // Hide toolbar and action bar when navigating away from history
                if (window.YT_HISTORY_MANAGER && !window.location.pathname.startsWith('/feed/history')) {
                    const manager = window.YT_HISTORY_MANAGER;
                    if (manager.state.toolbar) {
                        manager.state.toolbar.style.display = 'none';
                    }
                    if (manager.state.bottomActionBar) {
                        manager.state.bottomActionBar.style.display = 'none';
                    }
                }
            }
        };

        // Listen for YouTube navigation events
        window.addEventListener('yt-navigate-finish', addFrontendBodyClass);
        window.addEventListener('yt-navigate-start', addFrontendBodyClass);

        // Also poll for pathname changes (fallback)
        setInterval(checkNavigation, 1000);

    })(); // Feed Page Detection and Body Class Injection

    /* ============================================================
       TOGGLE BUTTON INJECTION
    ============================================================ */

    (function () { // Toggle Button Injection

        "use strict";

        function injectToggleButton() {
            const header = document.querySelector('yt-dynamic-text-view-model h1.dynamicTextViewModelH1');
            if (!header) return false;

            // Check if button already exists
            if (document.getElementById('toggle-script')) return true;

            const button = document.createElement('button');
            button.id = 'toggle-script';
            button.className = 'yss-btn yss-btn-clear togglescript';

            const icon = document.createElement('i');
            icon.className = 'fa-solid fa-list-check';
            button.appendChild(icon);

            const span = document.createElement('span');
            span.textContent = 'Toggle Filter';
            button.appendChild(span);

            button.addEventListener('click', () => {
                if (window.YT_HISTORY_MANAGER) {
                    const manager = window.YT_HISTORY_MANAGER;

                    // Always refresh scan when toggling - get current videos
                    manager.scanRows();

                    // Initialize topbar if not already done
                    if (!manager.state.topbarInitialized) {
                        manager.initializeTopbar();
                    } else {
                        // Refresh filter UI with current videos
                        manager.createFilterUI();
                    }

                    // Toggle visibility of both topbar and bottom action bar
                    if (manager.state.toolbar) {
                        const toolbar = manager.state.toolbar;
                        const isHidden = toolbar.style.display === 'none' || !toolbar.style.display;
                        toolbar.style.display = isHidden ? 'block' : 'none';
                    }
                    if (manager.state.bottomActionBar) {
                        const actionBar = manager.state.bottomActionBar;
                        const isHidden = actionBar.style.display === 'none' || !actionBar.style.display;
                        // Show action bar if there are selections, or if toggling to show
                        if (manager.state.selected.size > 0 || isHidden) {
                            actionBar.style.display = 'flex';
                        } else {
                            actionBar.style.display = 'none';
                        }
                    }

                    // Update selection count
                    manager.updateSelectionCount();
                }
            }, { passive: true });

            header.appendChild(button);
            return true;
        }

        function tryInjectToggleButton() {
            if (window.location.pathname === '/feed/history') {
                if (injectToggleButton()) {
                    if (typeof log === 'function') {
                        log('[YT_HISTORY] Toggle button injected', 'info');
                    }
                }
            }
        }

        // Try immediately
        if (document.readyState === 'loading') {
            document.addEventListener('DOMContentLoaded', tryInjectToggleButton);
        } else {
            tryInjectToggleButton();
        }

        // Watch for header element
        const observer = new MutationObserver(() => {
            if (window.location.pathname === '/feed/history') {
                tryInjectToggleButton();
            }
        });

        observer.observe(document.body, {
            childList: true,
            subtree: true
        });

        // Also listen for navigation
        window.addEventListener('yt-navigate-finish', () => {
            setTimeout(tryInjectToggleButton, 500);
        });

    })(); // Toggle Button Injection

    (function () { // Youtube History Management Singleton Protection

        "use strict";

        /* ============================================================
           SINGLETON PROTECTION
        ============================================================ */

        if (window.YT_HISTORY_MANAGER) {
            if (typeof log === 'function') {
                log('[YT_HISTORY] YT_HISTORY_MANAGER already initialized', 'warn');
            } else {
                console.warn("YT_HISTORY_MANAGER already initialized");
            }
            return;
        }

        /* ============================================================
           MANAGER
        ============================================================ */

        const YT_HISTORY_MANAGER = {

            /* ============================================================
               CONFIG
            ============================================================ */

            config: {
                debug: false,
                selectors: {
                    container: "ytd-item-section-renderer #contents",
                    row: "yt-lockup-view-model.lockup",
                    observerRoot: "ytd-section-list-renderer"
                },
                storageKeys: {
                    videoIndex: 'yss_history_video_index',
                    channels: 'yss_history_channels',
                    selected: 'yss_history_selected',
                    activeFilter: 'yss_history_active_filter',
                    lastExport: 'yss_history_last_export'
                }
            },

            /* ============================================================
               STATE
            ============================================================ */

            state: {
                initialized: false,
                observer: null,
                chipObserver: null,

                videos: new Map(),
                channels: new Map(),
                videoIndex: new Map(), // Fast lookup: id -> video, handle -> Set<videoId>, title -> Set<videoId>
                selected: new Set(), // Set of video IDs

                toolbar: null,
                actionBar: null,
                bottomActionBar: null,
                filterContainer: null,
                filterDropdown: null,
                filterDropdownMenu: null,
                filterDropdownTrigger: null,
                dropdownCloseHandler: null,
                closeButton: null,
                selectionControls: null,

                activeFilter: "all",
                topbarInitialized: false
            },

            /* ============================================================
               UTILS
            ============================================================ */

            utils: {

                log(...args) {
                    if (typeof log === 'function') {
                        log(`[YT_HISTORY] ${args.join(' ')}`, 'info');
                    } else if (YT_HISTORY_MANAGER.config.debug) {
                        console.log("[YT_HISTORY]", ...args);
                    }
                },

                /* ---------- sanitizeChannelName ---------- */

                sanitizeChannelName(text) {

                    if (!text) return "";

                    let t = text;

                    // Remove emojis
                    t = t.replace(/[\p{Emoji_Presentation}\p{Extended_Pictographic}]/gu, "");

                    // Normalize unicode
                    t = t.normalize("NFKD").replace(/[\u0300-\u036f]/g, "");

                    // Replace dashes with underscores
                    t = t.replace(/\s+[-–—]\s+/g, "_");

                    t = t.toLowerCase();

                    t = t.replace(/[^a-z0-9_\- ]/g, "");

                    t = t.replace(/\s+/g, "");

                    t = t.replace(/_+/g, "_");

                    t = t.replace(/-+/g, "-");

                    return t;
                },

                /* ---------- extractVideoId ---------- */

                extractVideoId(row) {

                    const link = row.querySelector('a[href*="watch?v="]');

                    if (link) {

                        const m = link.href.match(/[?&]v=([a-zA-Z0-9_-]{11})/);

                        if (m) return m[1];
                    }

                    const idClass = [...row.classList]
                        .find(c => c.startsWith("content-id-"));

                    if (idClass)
                        return idClass.replace("content-id-", "");

                    return null;
                },

                /* ---------- extractChannelNode ---------- */

                extractChannelNode(row) {
                    return row.querySelector(
                        '.yt-lockup-view-model__metadata ' +
                        'span.yt-core-attributed-string.yt-content-metadata-view-model__metadata-text' +
                        ':has(+ span.yt-content-metadata-view-model__delimiter)'
                    );
                },

                /* ---------- extractChannelName ---------- */

                extractChannelName(row) {
                    // Try the working selector first
                    const channelNode = this.extractChannelNode(row);
                    if (channelNode) {
                        return channelNode.textContent.trim();
                    }

                    // Fallback to metadata approach
                    const metadata = row.querySelector("yt-lockup-metadata-view-model");
                    if (!metadata) return null;

                    const spans = metadata.querySelectorAll(
                        ".yt-content-metadata-view-model__metadata-row span"
                    );

                    for (const span of spans) {
                        const text = span.textContent?.trim();
                        if (!text) continue;
                        if (!/views|ago|watched/i.test(text)) {
                            return text;
                        }
                    }

                    return null;
                },

                /* ---------- extractTitle ---------- */

                extractTitle(row) {
                    const link = row.querySelector('a[href*="watch?v="]');
                    if (!link) return null;

                    // Try aria-label first
                    if (link.getAttribute('aria-label')) {
                        return link.getAttribute('aria-label').trim();
                    }

                    // Try text content
                    const titleSpan = link.querySelector('span');
                    if (titleSpan && titleSpan.textContent.trim()) {
                        return titleSpan.textContent.trim();
                    }

                    // Fallback to link text
                    if (link.textContent.trim()) {
                        return link.textContent.trim();
                    }

                    return null;
                },

                /* ---------- extractThumbnail ---------- */

                extractThumbnail(row) {
                    // Try to find img tag
                    const img = row.querySelector('img');
                    if (img && img.src) {
                        return img.src;
                    }

                    // Construct from video ID
                    const videoId = this.extractVideoId(row);
                    if (videoId) {
                        return `https://img.youtube.com/vi/${videoId}/mqdefault.jpg`;
                    }

                    return null;
                },

                /* ---------- extractDuration ---------- */

                extractDuration(row) {
                    // Look for duration badge
                    const durationBadge = row.querySelector(
                        '.yt-lockup-view-model__overlay .yt-lockup-view-model__duration, ' +
                        '.yt-lockup-view-model__content-image .yt-lockup-view-model__duration, ' +
                        '[class*="duration"], ' +
                        '[class*="time"]'
                    );

                    if (durationBadge) {
                        const text = durationBadge.textContent.trim();
                        return this.parseDuration(text);
                    }

                    return null;
                },

                /* ---------- parseDuration ---------- */

                parseDuration(text) {
                    if (!text) return 0;

                    // Format: "H:MM:SS" or "M:SS" or "SS"
                    const parts = text.split(':').map(Number);
                    if (parts.length === 3) {
                        return parts[0] * 3600 + parts[1] * 60 + parts[2];
                    } else if (parts.length === 2) {
                        return parts[0] * 60 + parts[1];
                    } else if (parts.length === 1) {
                        return parts[0];
                    }

                    return 0;
                },

                /* ---------- normalizeTitle ---------- */

                normalizeTitle(title) {
                    if (!title) return '';
                    return title.toLowerCase()
                        .normalize('NFKD')
                        .replace(/[\u0300-\u036f]/g, '')
                        .replace(/[^a-z0-9\s]/g, '')
                        .replace(/\s+/g, ' ')
                        .trim();
                }

            },

            /* ============================================================
               SCAN ROWS
            ============================================================ */

            scanRows() {
                // Only scan videos in CURRENT VIEW (respect YouTube native filters like Music, Podcasts, etc)
                // Find the active content container based on YouTube's filter state
                const activeContainer = this.getCurrentViewContainer();
                if (!activeContainer) {
                    this.utils.log('No active view container found', 'warn');
                    return;
                }

                const rows = activeContainer.querySelectorAll(this.config.selectors.row);
                this.utils.log(`Scanning ${rows.length} rows in current view...`);

                // Clear channels map to rebuild from current view only
                this.state.channels.clear();

                // Also clear processed flags so we can re-process if needed
                rows.forEach(row => {
                    delete row.dataset.ythProcessed;
                });

                rows.forEach(row => {
                    this.processRow(row);
                });

                this.utils.log(`Processed ${this.state.videos.size} videos, ${this.state.channels.size} channels from current view`);

                // If topbar is initialized, refresh the filter UI
                if (this.state.topbarInitialized) {
                    this.createFilterUI();
                }

            },

            getCurrentViewContainer() {
                // Find the currently visible/active section that YouTube is showing
                // This respects YouTube's native filters (All, Music, Podcasts, etc)
                const sections = document.querySelectorAll('ytd-item-section-renderer');
                for (const section of sections) {
                    // Check if section is visible (not hidden by YouTube's filter)
                    const style = window.getComputedStyle(section);
                    if (style.display !== 'none' && style.visibility !== 'hidden') {
                        const contents = section.querySelector('#contents');
                        if (contents) {
                            return contents;
                        }
                    }
                }
                // Fallback to first available container
                return document.querySelector(this.config.selectors.container);
            },

            /* ============================================================
               PROCESS ROW
            ============================================================ */

            processRow(row) {

                if (row.dataset.ythProcessed)
                    return;

                const videoId = this.utils.extractVideoId(row);
                if (!videoId) return;

                const channelName = this.utils.extractChannelName(row);
                if (!channelName) return;

                const handle = this.utils.sanitizeChannelName(channelName);
                const title = this.utils.extractTitle(row) || 'Untitled';
                const thumbnail = this.utils.extractThumbnail(row);
                const duration = this.utils.extractDuration(row);
                const url = `https://www.youtube.com/watch?v=${videoId}`;

                row.dataset.channel = handle;
                row.dataset.videoId = videoId;
                row.dataset.filter = handle;

                const video = {
                    id: videoId,
                    channelName,
                    handle,
                    title,
                    thumbnail,
                    duration,
                    url,
                    element: row
                };

                this.state.videos.set(videoId, video);

                // Update fast index
                this.updateVideoIndex(videoId, video, handle, title);

                // Update channels
                if (!this.state.channels.has(handle)) {
                    this.state.channels.set(handle, {
                        name: channelName,
                        handle,
                        count: 0
                    });
                }
                this.state.channels.get(handle).count++;

                // Inject checkbox
                this.injectCheckbox(row);

                row.dataset.ythProcessed = "1";

            },

            /* ============================================================
               UPDATE VIDEO INDEX
            ============================================================ */

            updateVideoIndex(videoId, video, handle, title) {
                // Index by video ID
                this.state.videoIndex.set(`id:${videoId}`, video);

                // Index by channel handle
                const handleKey = `handle:${handle}`;
                if (!this.state.videoIndex.has(handleKey)) {
                    this.state.videoIndex.set(handleKey, new Set());
                }
                this.state.videoIndex.get(handleKey).add(videoId);

                // Index by normalized title
                const normalizedTitle = this.utils.normalizeTitle(title);
                if (normalizedTitle) {
                    const titleKey = `title:${normalizedTitle}`;
                    if (!this.state.videoIndex.has(titleKey)) {
                        this.state.videoIndex.set(titleKey, new Set());
                    }
                    this.state.videoIndex.get(titleKey).add(videoId);
                }
            },

            /* ============================================================
               CHECKBOX INJECTION
            ============================================================ */

            injectCheckbox(row) {
                if (row.querySelector('.yth-checkbox')) return;

                // Use requestAnimationFrame for proper timing
                requestAnimationFrame(() => {
                    if (row.querySelector('.yth-checkbox')) return; // Double-check

                    const checkbox = document.createElement('input');
                    checkbox.type = 'checkbox';
                    checkbox.className = 'yth-checkbox';

                    // CSS handles positioning via injected styles
                    row.classList.add('yth-row-selectable');

                    // Use passive: false for change events (we need preventDefault capability)
                    checkbox.addEventListener('change', () => {
                        const videoId = row.dataset.videoId;
                        if (checkbox.checked) {
                            this.state.selected.add(videoId);
                            row.classList.add('yth-selected');
                        } else {
                            this.state.selected.delete(videoId);
                            row.classList.remove('yth-selected');
                        }
                        this.updateSelectionCount();
                        this.saveState();

                        // Ensure action bar is visible if there are selections
                        if (this.state.selected.size > 0 && this.state.bottomActionBar) {
                            this.state.bottomActionBar.style.display = 'flex';
                        }
                    }, { passive: true });

                    row.appendChild(checkbox);
                });
            },

            /* ============================================================
               SELECTION METHODS
            ============================================================ */

            getSelected() {
                return [...document.querySelectorAll('.yth-checkbox:checked')]
                    .map(cb => {
                        const row = cb.closest('yt-lockup-view-model');
                        return row ? this.state.videos.get(row.dataset.videoId) : null;
                    })
                    .filter(v => v !== null);
            },

            selectAllVisible() {
                // Get ALL checkboxes in the document - use a simple, reliable approach
                // Don't filter by :not(:checked) initially - get all and check state
                const allCheckboxes = document.querySelectorAll('input.yth-checkbox');
                let clicked = 0;

                // Simple loop - click all unchecked checkboxes
                for (let i = 0; i < allCheckboxes.length; i++) {
                    const checkbox = allCheckboxes[i];

                    // Skip if already checked
                    if (checkbox.checked) continue;

                    // Check visibility using getBoundingClientRect (most reliable)
                    const rect = checkbox.getBoundingClientRect();
                    if (rect.width === 0 || rect.height === 0) continue;

                    // Use click() method - this is the only way that works reliably
                    checkbox.click();
                    clicked++;
                }

                // Update state after all clicks
                this.updateSelectionCount();
                this.saveState();

                if (typeof toastInfo === 'function') {
                    toastInfo(`Selected ${clicked} videos`);
                }

                this.utils.log(`Selected ${clicked} visible videos out of ${allCheckboxes.length} total`);
            },

            selectByChannel(handle) {
                this.state.videos.forEach(video => {
                    if (video.handle === handle) {
                        const checkbox = video.element.querySelector('.yth-checkbox');
                        if (checkbox && !checkbox.checked) {
                            checkbox.checked = true;
                            this.state.selected.add(video.id);
                            video.element.classList.add('yth-selected');
                        }
                    }
                });
                this.updateSelectionCount();
                this.saveState();
            },

            clearSelection() {
                // Use click() method for checked checkboxes
                const checkedBoxes = document.querySelectorAll('.yth-checkbox:checked');
                checkedBoxes.forEach(cb => {
                    cb.click(); // Use click() for solid state
                });

                this.state.selected.clear();
                document.querySelectorAll('.yth-selected').forEach(row => {
                    row.classList.remove('yth-selected');
                });
                this.updateSelectionCount();
                this.saveState();
            },

            updateSelectionCount() {
                const count = this.state.selected.size;

                // Update count display
                if (this.state.selectionControls) {
                    const countElement = this.state.selectionControls.querySelector('.yth-selection-count');
                    if (countElement) {
                        countElement.textContent = count > 0 ? `${count} selected` : '';
                        countElement.className = 'yth-selection-count yss-button-counter-inline';
                    }
                }

                // Show/hide action bar based on selection
                if (this.state.bottomActionBar) {
                    if (count > 0) {
                        this.state.bottomActionBar.style.display = 'flex';
                    } else {
                        // Only hide if toolbar is also hidden (user might want to keep it open)
                        if (this.state.toolbar && (this.state.toolbar.style.display === 'none' || !this.state.toolbar.style.display)) {
                            this.state.bottomActionBar.style.display = 'none';
                        }
                    }
                }
            },

            /* ============================================================
               CREATE TOOLBAR ROOT
            ============================================================ */

            createToolbar() {

                if (this.state.toolbar)
                    this.state.toolbar.remove();

                const toolbar = document.createElement("div");

                toolbar.classList.add("yss-topbar", "sticky");
                toolbar.style.display = 'none'; // Hidden by default

                this.state.toolbar = toolbar;

                document.body.prepend(toolbar);

            },

            /* ============================================================
               CREATE ACTION BAR
            ============================================================ */

            createActionBar() {
                // Create fixed bottom action bar (floating bar)
                const actionBar = document.createElement("div");
                actionBar.className = "yss-history-action-bar";
                actionBar.id = "yss-history-action-bar";
                actionBar.style.display = "none"; // Hidden by default - CSS handles the rest

                // Left side: Selection counter
                const leftSide = document.createElement("div");
                leftSide.className = "yss-action-bar-left";
                const countSpan = document.createElement("span");
                countSpan.className = "yth-selection-count yss-button-counter-inline";
                this.state.selectionControls = leftSide; // Store for updateSelectionCount
                leftSide.appendChild(countSpan);

                // Right side: Action buttons
                const rightSide = document.createElement("div");
                rightSide.className = "yss-action-bar-right";

                // Action bar for filters (separate from bottom bar - goes in topbar)
                const filterBar = document.createElement("div");
                filterBar.classList.add("yss-topbar-left");
                this.state.actionBar = filterBar; // For filter dropdown

                // Add buttons to right side of bottom bar
                if (typeof createSmartButton === 'function') {
                    // Select All Visible button
                    const selectAllBtn = createSmartButton({
                        id: 'yth-select-all',
                        text: 'Select All Visible',
                        icon: 'fa-solid fa-check-square',
                        classes: ['yss-btn', 'yss-btn-sm', 'yss-btn-select-all', 'yss-btn-green'],
                        tooltip: 'Select All Visible Videos',
                        handlers: {
                            onClick: () => {
                                this.selectAllVisible();
                            }
                        }
                    });
                    rightSide.appendChild(selectAllBtn.getElement());

                    // Clear Selection button
                    const clearBtn = createSmartButton({
                        id: 'yth-clear-selection',
                        text: 'Clear',
                        icon: 'fa-solid fa-trash',
                        classes: ['yss-btn', 'yss-btn-sm', 'yss-btn-clear'],
                        tooltip: 'Clear Selection',
                        handlers: {
                            onClick: () => {
                                this.clearSelection();
                            }
                        }
                    });
                    rightSide.appendChild(clearBtn.getElement());

                    // Create Playlist button
                    const createPlaylistBtn = createSmartButton({
                        id: 'yth-create-playlist',
                        text: 'Create Playlist',
                        icon: 'fa-solid fa-list',
                        classes: ['yss-btn', 'yss-btn-sm', 'yss-btn-primary'],
                        tooltip: 'Create Playlist from Selected Videos',
                        handlers: {
                            onClick: () => {
                                this.createPlaylistFromSelected();
                            }
                        }
                    });
                    rightSide.appendChild(createPlaylistBtn.getElement());

                    // Export JSON button
                    const exportJsonBtn = createSmartButton({
                        id: 'yth-export-json',
                        text: 'Export JSON',
                        icon: 'fa-solid fa-file-code',
                        classes: ['yss-btn', 'yss-btn-sm', 'yss-btn-json', 'yss-btn-start'],
                        tooltip: 'Export Selected Videos to JSON',
                        handlers: {
                            onClick: () => {
                                this.exportJSON(this.state.selected.size > 0);
                            }
                        }
                    });
                    rightSide.appendChild(exportJsonBtn.getElement());

                    // Export CSV button
                    const exportCsvBtn = createSmartButton({
                        id: 'yth-export-csv',
                        text: 'Export CSV',
                        icon: 'fa-solid fa-file-csv',
                        classes: ['yss-btn', 'yss-btn-sm', 'yss-btn-csv', 'yss-btn-purple'],
                        tooltip: 'Export Selected Videos to CSV',
                        handlers: {
                            onClick: () => {
                                this.exportCSV(this.state.selected.size > 0);
                            }
                        }
                    });
                    rightSide.appendChild(exportCsvBtn.getElement());

                    // Minimize/Dismiss button
                    const minimizeBtn = createSmartButton({
                        id: 'yth-minimize',
                        text: 'Minimize',
                        icon: 'fa-solid fa-chevron-down',
                        classes: ['yss-btn', 'yss-btn-sm', 'yss-btn-icon'],
                        tooltip: 'Minimize Action Bar',
                        handlers: {
                            onClick: () => {
                                actionBar.style.display = actionBar.style.display === 'none' ? 'flex' : 'none';
                            }
                        }
                    });
                    rightSide.appendChild(minimizeBtn.getElement());
                }

                // Assemble bottom bar
                actionBar.appendChild(leftSide);
                actionBar.appendChild(rightSide);

                // Add filter bar to topbar (for dropdown)
                this.state.toolbar.appendChild(filterBar);

                // Store bottom action bar
                this.state.bottomActionBar = actionBar;
                document.body.appendChild(actionBar);

                this.updateSelectionCount();

            },

            /* ============================================================
               CREATE CLOSE BUTTON
            ============================================================ */

            createCloseButton(container) {

                const btn = document.createElement("button");

                btn.classList.add(
                    "yss-btn-close",
                    "yss-btn-icon",
                    "yss-lightbox-close"
                );

                btn.setAttribute("aria-label", "Close");
                btn.setAttribute("type", "button");

                const icon = document.createElement("i");

                icon.classList.add("fa-solid", "fa-xmark");

                btn.appendChild(icon);

                btn.addEventListener("click", () => {
                    this.destroy();
                }, { passive: true });

                container.appendChild(btn);

                this.state.closeButton = btn;

            },

            /* ============================================================
               CREATE FILTER UI
            ============================================================ */

            createFilterUI() {
                if (!this.state.actionBar) return;

                while (this.state.actionBar.firstChild)
                    this.state.actionBar.removeChild(
                        this.state.actionBar.firstChild
                    );

                // Only get channels from CURRENT VIEW videos
                const currentViewChannels = new Map();
                const currentContainer = this.getCurrentViewContainer();

                if (currentContainer) {
                    const visibleRows = currentContainer.querySelectorAll(
                        `${this.config.selectors.row}:not([style*="display: none"])`
                    );

                    this.utils.log(`Found ${visibleRows.length} visible rows for filter UI`);

                    visibleRows.forEach(row => {
                        // Get handle from dataset.filter (set by processRow) or from video data
                        const handle = row.dataset.filter || row.dataset.channel;
                        if (handle) {
                            // Get channel name from dataset.channel or from video data
                            const videoId = row.dataset.videoId;
                            let channelName = row.dataset.channel;

                            // If we have video data, use that for accurate name
                            if (videoId && this.state.videos.has(videoId)) {
                                const video = this.state.videos.get(videoId);
                                channelName = video.channelName || channelName;
                            }

                            if (!currentViewChannels.has(handle)) {
                                currentViewChannels.set(handle, {
                                    name: channelName || handle,
                                    handle: handle,
                                    count: 0
                                });
                            }
                            currentViewChannels.get(handle).count++;
                        }
                    });
                }

                // Fallback: If no channels found from rows, use state.channels (from scanRows)
                if (currentViewChannels.size === 0 && this.state.channels.size > 0) {
                    this.utils.log('No channels from visible rows, using state.channels as fallback');
                    this.state.channels.forEach((channel, handle) => {
                        currentViewChannels.set(handle, {
                            name: channel.name,
                            handle: handle,
                            count: channel.count
                        });
                    });
                }

                this.utils.log(`Creating filter UI with ${currentViewChannels.size} channels`);

                // Create new dropdown container with proper class
                const dropdownWrapper = document.createElement("div");
                dropdownWrapper.className = "yth-channel-selector";

                // Trigger button
                const triggerBtn = document.createElement("button");
                triggerBtn.className = "yth-channel-selector-trigger";
                triggerBtn.type = "button";

                const triggerContent = document.createElement("span");
                triggerContent.className = "yth-channel-selector-text";
                triggerContent.textContent = this.state.activeFilter === 'all' ? 'All Channels' :
                    (currentViewChannels.get(this.state.activeFilter)?.name || 'Select Channel');
                triggerBtn.appendChild(triggerContent);

                const triggerIcon = document.createElement("i");
                triggerIcon.className = "fa-solid fa-chevron-down yth-channel-selector-icon";
                triggerBtn.appendChild(triggerIcon);

                // Dropdown panel
                const dropdownPanel = document.createElement("div");
                dropdownPanel.className = "yth-channel-selector-panel";
                dropdownPanel.style.display = "none";

                // Search input wrapper
                const searchWrapper = document.createElement("div");
                searchWrapper.className = "yth-channel-selector-search-wrapper";

                const searchIcon = document.createElement("i");
                searchIcon.className = "fa-solid fa-search yth-channel-selector-search-icon";
                searchWrapper.appendChild(searchIcon);

                const searchBox = document.createElement("input");
                searchBox.type = "text";
                searchBox.className = "yth-channel-selector-search";
                searchBox.placeholder = "Search channels...";
                searchWrapper.appendChild(searchBox);
                dropdownPanel.appendChild(searchWrapper);

                // Options list
                const optionsList = document.createElement("div");
                optionsList.className = "yth-channel-selector-options";

                // Sort channels by count (descending)
                const sortedChannels = Array.from(currentViewChannels.values())
                    .sort((a, b) => b.count - a.count);

                const totalCount = currentViewChannels.size > 0 ?
                    Array.from(currentViewChannels.values()).reduce((sum, ch) => sum + ch.count, 0) : 0;

                // Create "All" option
                const allOption = this.createChannelOption("All", "all", totalCount);
                optionsList.appendChild(allOption);

                // Create channel options
                if (sortedChannels.length > 0) {
                    sortedChannels.forEach(channel => {
                        const option = this.createChannelOption(channel.name, channel.handle, channel.count);
                        optionsList.appendChild(option);
                    });
                } else {
                    // Show message if no channels found
                    const noChannelsMsg = document.createElement("div");
                    noChannelsMsg.className = "yth-channel-option";
                    noChannelsMsg.style.padding = "16px";
                    noChannelsMsg.style.textAlign = "center";
                    noChannelsMsg.style.color = "var(--yt-ui-text-secondary, #aaa)";
                    noChannelsMsg.style.fontStyle = "italic";
                    noChannelsMsg.textContent = "No channels found. Click 'Toggle Filter' to scan videos.";
                    optionsList.appendChild(noChannelsMsg);
                }

                dropdownPanel.appendChild(optionsList);
                dropdownWrapper.appendChild(triggerBtn);
                dropdownWrapper.appendChild(dropdownPanel);

                // Toggle dropdown
                const toggleDropdown = (e) => {
                    if (e) e.stopPropagation();
                    const isOpen = dropdownPanel.style.display !== 'none' && dropdownPanel.style.display !== '';
                    dropdownPanel.style.display = isOpen ? 'none' : 'block';
                    if (!isOpen) {
                        setTimeout(() => searchBox.focus(), 50);
                    }
                };

                triggerBtn.addEventListener('click', toggleDropdown, { passive: true });

                // Close on outside click
                const closeHandler = (e) => {
                    if (!dropdownWrapper.contains(e.target)) {
                        dropdownPanel.style.display = 'none';
                    }
                };
                document.addEventListener('click', closeHandler, { passive: true });
                this.state.dropdownCloseHandler = closeHandler;

                // Search functionality
                searchBox.addEventListener('input', (e) => {
                    const query = e.target.value.toLowerCase().trim();
                    const options = optionsList.querySelectorAll('.yth-channel-option');
                    options.forEach(option => {
                        const text = option.textContent.toLowerCase();
                        option.style.display = query === '' || text.includes(query) ? '' : 'none';
                    });
                }, { passive: true });

                // Store references
                this.state.filterDropdown = dropdownWrapper;
                this.state.filterDropdownMenu = dropdownPanel;
                this.state.filterDropdownTrigger = triggerBtn;

                // Append to action bar
                this.state.actionBar.appendChild(dropdownWrapper);
            },

            createChannelOption(name, handle, count = null) {
                const option = document.createElement("button");
                option.type = "button";
                option.className = "yth-channel-option";
                option.dataset.handle = handle;

                // Active state indicator (only checked circle icon, no other icons)
                if (handle === this.state.activeFilter) {
                    option.classList.add('yth-channel-option-active');
                    const checkIcon = document.createElement("i");
                    checkIcon.className = "fa-solid fa-circle-check yth-channel-option-check";
                    option.appendChild(checkIcon);
                }

                // Channel name
                const nameSpan = document.createElement("span");
                nameSpan.className = "yth-channel-option-name";
                nameSpan.textContent = name;
                option.appendChild(nameSpan);

                // Counter badge
                if (count !== null) {
                    const counter = document.createElement("span");
                    counter.className = "yss-button-counter-inline yth-channel-option-count";
                    counter.textContent = count;
                    option.appendChild(counter);
                }

                // Click handler
                option.addEventListener('click', (e) => {
                    e.stopPropagation();
                    this.state.activeFilter = handle;
                    this.filter(handle);
                    this.updateFilterDropdown();
                    this.saveState();
                    // Close dropdown
                    if (this.state.filterDropdownMenu) {
                        this.state.filterDropdownMenu.style.display = 'none';
                    }
                }, { passive: true });

                return option;
            },

            updateFilterDropdown() {
                if (this.state.filterDropdownTrigger) {
                    const currentViewChannels = new Map();
                    const currentContainer = this.getCurrentViewContainer();

                    if (currentContainer) {
                        const visibleRows = currentContainer.querySelectorAll(
                            `${this.config.selectors.row}:not([style*="display: none"])`
                        );
                        visibleRows.forEach(row => {
                            // Get handle from dataset.filter (set by processRow)
                            const handle = row.dataset.filter || row.dataset.channel;
                            if (handle) {
                                const videoId = row.dataset.videoId;
                                let channelName = row.dataset.channel;

                                // If we have video data, use that for accurate name
                                if (videoId && this.state.videos.has(videoId)) {
                                    const video = this.state.videos.get(videoId);
                                    channelName = video.channelName || channelName;
                                }

                                if (!currentViewChannels.has(handle)) {
                                    currentViewChannels.set(handle, {
                                        name: channelName || handle,
                                        handle: handle
                                    });
                                }
                            }
                        });
                    }

                    const triggerText = this.state.filterDropdownTrigger.querySelector('.yth-channel-selector-text');
                    if (triggerText) {
                        triggerText.textContent = this.state.activeFilter === 'all' ? 'All Channels' :
                            (currentViewChannels.get(this.state.activeFilter)?.name || 'Select Channel');
                    }

                    // Update active state in dropdown
                    const options = this.state.filterDropdown?.querySelectorAll('.yth-channel-option');
                    if (options) {
                        options.forEach(opt => {
                            opt.classList.remove('yth-channel-option-active');
                            opt.querySelector('i.yth-channel-option-check')?.remove();
                            if (opt.dataset.handle === this.state.activeFilter) {
                                opt.classList.add('yth-channel-option-active');
                                const checkIcon = document.createElement("i");
                                checkIcon.className = "fa-solid fa-circle-check yth-channel-option-check";
                                opt.insertBefore(checkIcon, opt.firstChild);
                            }
                        });
                    }
                }
            },

            /* ============================================================
               CREATE FALLBACK BUTTON
            ============================================================ */

            createFallbackButton(name, handle, count = null) {
                const btn = document.createElement("button");
                btn.classList.add("yss-btn", "yss-filter-btn");
                btn.textContent = count !== null ? `${name} (${count})` : name;
                btn.dataset.handle = handle;

                if (handle === this.state.activeFilter)
                    btn.classList.add("active");

                btn.addEventListener("click", () => {
                    this.state.activeFilter = handle;
                    this.filter(handle);
                    this.updateActiveButtons();
                    this.saveState();
                }, { passive: true });

                return btn;
            },

            /* ============================================================
               UPDATE ACTIVE BUTTONS
            ============================================================ */

            updateActiveButtons() {
                // Update dropdown if it exists
                if (this.state.filterDropdown) {
                    this.updateFilterDropdown();
                    return;
                }

                // Fallback for old button-based UI
                const filterContainer = this.state.actionBar.querySelector(".yss-filter-buttons-container");
                const container = filterContainer || this.state.actionBar;
                const buttons = container.querySelectorAll(".yss-filter-btn");
                buttons.forEach(btn => {
                    const handle = btn.dataset.handle || btn.closest('[data-handle]')?.dataset.handle;
                    if (handle === this.state.activeFilter) {
                        btn.classList.add("active");
                        // Scroll active button into view
                        if (filterContainer) {
                            btn.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
                        }
                    } else {
                        btn.classList.remove("active");
                    }
                });
            },

            /* ============================================================
               UPDATE ACTIVE BUTTON
            ============================================================ */

            updateActiveButton(active) {
                const buttons = this.state.actionBar.querySelectorAll(".yss-filter-btn");
                buttons.forEach(btn => {
                    btn.classList.remove("active");
                });
                active.classList.add("active");
            },

            /* ============================================================
               FILTER
            ============================================================ */

            filter(handle) {
                this.state.videos.forEach(video => {
                    if (handle === "all" || video.handle === handle)
                        video.element.style.display = "";
                    else
                        video.element.style.display = "none";
                });

                document.querySelectorAll("ytd-item-section-renderer").forEach(section => {
                    const visible = section.querySelector(
                        this.config.selectors.row + ':not([style*="display: none"])'
                    );
                    section.style.display = visible ? "" : "none";
                });

                this.utils.log(`Filtered to: ${handle === 'all' ? 'All' : handle} (${this.getVisibleCount()} visible)`);
            },

            getVisibleCount() {
                let count = 0;
                this.state.videos.forEach(video => {
                    if (video.element.style.display !== 'none') count++;
                });
                return count;
            },

            /* ============================================================
               OBSERVER
            ============================================================ */

            observe() {
                const root = document.querySelector(this.config.selectors.observerRoot);

                if (!root) {
                    this.utils.log('Observer root not found, retrying...', 'warn');
                    setTimeout(() => this.observe(), 1000);
                    return;
                }

                // Also watch for YouTube native filter changes (chip bar clicks)
                const chipBar = document.querySelector('chip-bar-view-model, .ytChipBarViewModelHost');
                if (chipBar) {
                    const chipObserver = new MutationObserver(() => {
                        // When YouTube filter changes, rescan current view
                        requestAnimationFrame(() => {
                            this.scanRows();
                            if (this.state.topbarInitialized) {
                                this.createFilterUI();
                                this.filter(this.state.activeFilter);
                            }
                        });
                    });
                    chipObserver.observe(chipBar, { childList: true, subtree: true, attributes: true });
                    this.state.chipObserver = chipObserver;
                }

                const observer = new MutationObserver(mutations => {
                    let changed = false;

                    for (const mutation of mutations) {
                        for (const node of mutation.addedNodes) {
                            if (node.nodeType !== 1) continue;

                            if (node.matches?.(this.config.selectors.row)) {
                                requestAnimationFrame(() => {
                                    this.processRow(node);
                                });
                                changed = true;
                            }

                            node.querySelectorAll?.(this.config.selectors.row).forEach(row => {
                                requestAnimationFrame(() => {
                                    this.processRow(row);
                                });
                                changed = true;
                            });
                        }
                    }

                    if (changed) {
                        requestAnimationFrame(() => {
                            if (this.state.topbarInitialized) {
                                this.createFilterUI();
                                this.filter(this.state.activeFilter);
                            }
                            this.saveState();
                        });
                    }
                });

                observer.observe(root, {
                    childList: true,
                    subtree: true
                });

                this.state.observer = observer;
                this.utils.log('Observer started');
            },

            /* ============================================================
               PERSISTENT STATE
            ============================================================ */

            saveState() {
                try {
                    const state = {
                        selected: Array.from(this.state.selected),
                        activeFilter: this.state.activeFilter,
                        channels: Array.from(this.state.channels.entries()).map(([k, v]) => [k, v]),
                        timestamp: Date.now()
                    };
                    GM_setValue(this.config.storageKeys.selected, JSON.stringify(state.selected));
                    GM_setValue(this.config.storageKeys.activeFilter, state.activeFilter);
                    GM_setValue(this.config.storageKeys.channels, JSON.stringify(state.channels));
                } catch (e) {
                    this.utils.log(`Error saving state: ${e.message}`, 'error');
                }
            },

            loadState() {
                try {
                    const selected = JSON.parse(GM_getValue(this.config.storageKeys.selected, '[]'));
                    this.state.selected = new Set(selected);

                    const activeFilter = GM_getValue(this.config.storageKeys.activeFilter, 'all');
                    this.state.activeFilter = activeFilter;

                    // Restore selected checkboxes
                    selected.forEach(videoId => {
                        const video = this.state.videos.get(videoId);
                        if (video) {
                            const checkbox = video.element.querySelector('.yth-checkbox');
                            if (checkbox) {
                                checkbox.checked = true;
                                video.element.classList.add('yth-selected');
                            }
                        }
                    });

                    this.updateSelectionCount();
                } catch (e) {
                    this.utils.log(`Error loading state: ${e.message}`, 'error');
                }
            },

            /* ============================================================
               DESTROY
            ============================================================ */

            destroy() {
                if (this.state.observer)
                    this.state.observer.disconnect();

                if (this.state.chipObserver)
                    this.state.chipObserver.disconnect();

                if (this.state.dropdownCloseHandler) {
                    document.removeEventListener('click', this.state.dropdownCloseHandler);
                }

                if (this.state.toolbar)
                    this.state.toolbar.remove();

                if (this.state.bottomActionBar)
                    this.state.bottomActionBar.remove();

                this.state.initialized = false;
                this.state.topbarInitialized = false;

                window.YT_HISTORY_MANAGER = null;

                if (typeof toastInfo === 'function') {
                    toastInfo('History Manager closed');
                }
            },

            /* ============================================================
               EXPORT METHODS
            ============================================================ */

            export() {
                return [...this.state.videos.values()]
                    .map(v => ({
                        id: v.id,
                        title: v.title,
                        channel: v.channelName,
                        handle: v.handle,
                        thumbnail: v.thumbnail,
                        duration: v.duration,
                        url: v.url
                    }));
            },

            exportJSON(selectedOnly = false) {
                const videos = selectedOnly ? this.getSelected() : [...this.state.videos.values()];
                const data = videos.map(v => ({
                    id: v.id,
                    title: v.title,
                    channel: v.channelName,
                    handle: v.handle,
                    thumbnail: v.thumbnail,
                    duration: v.duration,
                    url: v.url
                }));

                const json = JSON.stringify(data, null, 2);
                const blob = new Blob([json], { type: 'application/json' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = `youtube-history-${selectedOnly ? 'selected' : 'all'}-${Date.now()}.json`;
                document.body.appendChild(a);
                a.click();
                document.body.removeChild(a);
                URL.revokeObjectURL(url);

                GM_setValue(this.config.storageKeys.lastExport, Date.now());

                if (typeof toastSuccess === 'function') {
                    toastSuccess(`Exported ${data.length} videos to JSON`);
                }
                this.utils.log(`Exported ${data.length} videos to JSON`);
            },

            createPlaylistFromSelected() {
                const selected = this.getSelected();
                if (selected.length === 0) {
                    if (typeof toastError === 'function') {
                        toastError('No videos selected');
                    }
                    return;
                }

                // Create playlist URL with video IDs
                const videoIds = selected.map(v => v.id).join(',');
                const playlistUrl = `https://www.youtube.com/watch_videos?video_ids=${videoIds}`;

                // Open in new tab
                window.open(playlistUrl, '_blank');

                if (typeof toastSuccess === 'function') {
                    toastSuccess(`Opening playlist with ${selected.length} videos`);
                }
                this.utils.log(`Created playlist with ${selected.length} videos`);
            },

            exportCSV(selectedOnly = false) {
                const videos = selectedOnly ? this.getSelected() : [...this.state.videos.values()];

                const escapeCSV = (text) => {
                    if (text == null) return '';
                    const str = String(text);
                    if (str.includes(',') || str.includes('"') || str.includes('\n')) {
                        return `"${str.replace(/"/g, '""')}"`;
                    }
                    return str;
                };

                const formatDuration = (seconds) => {
                    if (!seconds) return '';
                    const h = Math.floor(seconds / 3600);
                    const m = Math.floor((seconds % 3600) / 60);
                    const s = seconds % 60;
                    if (h > 0) return `${h}:${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`;
                    return `${m}:${String(s).padStart(2, '0')}`;
                };

                const header = ['Title', 'Channel', 'Video ID', 'URL', 'Duration', 'Thumbnail'].map(escapeCSV).join(',');
                const rows = videos.map(v => [
                    v.title || '',
                    v.channelName || '',
                    v.id || '',
                    v.url || '',
                    formatDuration(v.duration),
                    v.thumbnail || ''
                ].map(escapeCSV).join(','));

                const csv = '\uFEFF' + header + '\n' + rows.join('\n');
                const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = `youtube-history-${selectedOnly ? 'selected' : 'all'}-${Date.now()}.csv`;
                document.body.appendChild(a);
                a.click();
                document.body.removeChild(a);
                URL.revokeObjectURL(url);

                GM_setValue(this.config.storageKeys.lastExport, Date.now());

                if (typeof toastSuccess === 'function') {
                    toastSuccess(`Exported ${videos.length} videos to CSV`);
                }
                this.utils.log(`Exported ${videos.length} videos to CSV`);
            },

            /* ============================================================
               INIT
            ============================================================ */

            init() {

                if (this.state.initialized)
                    return;

                if (location.pathname !== "/feed/history")
                    return;

                this.utils.log('Initializing YT_HISTORY_MANAGER...');

                // Check if body class is present (required for styling)
                if (!document.body.classList.contains('yss-custom-yt-frontend')) {
                    this.utils.log('Waiting for body class...', 'warn');
                    setTimeout(() => this.init(), 500);
                    return;
                }

                // DO NOT scan rows on init - defer to when toggle button is clicked
                // This prevents performance issues on page load
                // Scan will happen when user clicks toggle button

                // Load persisted state
                this.loadState();

                // DO NOT auto-initialize topbar - wait for toggle button click
                // Topbar will be initialized when user clicks the toggle button

                // Start observer (lightweight - just watches for changes)
                this.observe();

                this.state.initialized = true;

                this.utils.log('YT_HISTORY_MANAGER initialized. Click toggle button to scan videos.');

            },

            /* ============================================================
               INITIALIZE TOPBAR
            ============================================================ */

            initializeTopbar() {
                if (this.state.topbarInitialized) return;

                this.utils.log('Initializing topbar...');

                this.createToolbar();

                this.createActionBar();

                this.createFilterUI();

                // Apply current filter
                this.filter(this.state.activeFilter);

                this.state.topbarInitialized = true;

                this.utils.log('Topbar initialized');
            }

        };

        /* ============================================================
           EXPORT GLOBAL
        ============================================================ */

        window.YT_HISTORY_MANAGER = YT_HISTORY_MANAGER;

        /* ============================================================
           START
        ============================================================ */

        // Initialize after a short delay to ensure body class is set
        function startHistoryManager() {
            if (document.body.classList.contains('yss-custom-yt-frontend')) {
                YT_HISTORY_MANAGER.init();
            } else {
                setTimeout(startHistoryManager, 100);
            }
        }

        /* if (location.pathname === "/feed/history") {
            startHistoryManager();
        } */

    })(); // Youtube History Management Singleton Protection



