    /* 3.  Replace routine (safe for event listeners) ---------------------------- */
    const replaceEmoji = node => {
        if (node.nodeType === Node.TEXT_NODE) {
            // Safety check: ensure node is still in the DOM before processing
            if (!node.parentNode || !node.isConnected) {
                return;
            }

            let txt = node.textContent;
            let changed = false;

            for (const [emoji, iconClass] of Object.entries(emojiMap)) {
                if (txt.includes(emoji)) {
                    txt = txt.split(emoji).join('');   // remove emoji
                    changed = true;
                }
            }
            if (!changed) return;

            // Double-check parent still exists before building fragment
            if (!node.parentNode || !node.isConnected) {
                return;
            }

            /* build a wrapper span with icons + leftover text */
            // Use a span wrapper to avoid Trusted Types issues with replaceChild
            const wrapper = document.createElement('span');
            wrapper.style.display = 'inline'; // Preserve inline behavior
            let lastIdx = 0;
            const textContent = node.textContent;

            // Use replace with a function to build the content
            textContent.replace(
                new RegExp(Object.keys(emojiMap).join('|'), 'g'),
                (match, offset) => {
                    /* text before emoji */
                    if (offset > lastIdx) {
                        const textBefore = textContent.slice(lastIdx, offset);
                        if (textBefore) {
                            // Use textContent for text parts to avoid Trusted Types issues
                            const textSpan = document.createElement('span');
                            textSpan.textContent = textBefore;
                            wrapper.appendChild(textSpan);
                        }
                    }

                    /* icon */
                    const i = document.createElement('i');
                    i.className = emojiMap[match];
                    i.classList.add('yss-icon-added');
                    wrapper.appendChild(i);

                    lastIdx = offset + match.length;
                }
            );

            /* text after last emoji */
            if (lastIdx < textContent.length) {
                const textAfter = textContent.slice(lastIdx);
                if (textAfter) {
                    const textSpan = document.createElement('span');
                    textSpan.textContent = textAfter;
                    wrapper.appendChild(textSpan);
                }
            }

            // Final safety check before replacing
            if (node.parentNode && node.isConnected) {
                try {
                    // Replace text node with wrapper span
                    // Use insertBefore + removeChild as fallback if replaceChild is blocked
                    try {
                        node.parentNode.replaceChild(wrapper, node);
                    } catch (replaceError) {
                        // If replaceChild fails (Trusted Types), use insertBefore + removeChild
                        if (replaceError.message && replaceError.message.includes('Trusted')) {
                            node.parentNode.insertBefore(wrapper, node);
                            node.parentNode.removeChild(node);
                        } else {
                            throw replaceError;
                        }
                    }
                } catch (e) {
                    // Silently fail if node was removed during processing
                    console.debug('Emoji replacement skipped:', e.message || 'node was removed during processing');
                }
            }
            return;
        }

        /* walk children, but skip <script>, <style>, <i> already FA icons */
        if (node.nodeType === Node.ELEMENT_NODE &&
            !['SCRIPT', 'STYLE', 'I', 'SVG', 'PATH'].includes(node.tagName)) {
            // Create a snapshot of childNodes to avoid issues with live NodeList
            const children = Array.from(node.childNodes);
            children.forEach(replaceEmoji);
        }
    };




    // ✅ SECURITY FIX: Check if ToS warning has been shown
    function checkAndShowToSWarning() {
        const TOS_WARNING_KEY = 'yss:tos_warning_shown';
        const hasSeenWarning = YSS.storage.get(TOS_WARNING_KEY, false);

        if (!hasSeenWarning) {
            const modal = new YSSModalBuilder('⚠️ Important Warning - Terms of Service', {
                id: "yss-terms-of-service",
                maxWidth: '600px',
                showCloseButton: true,
                closeOnOverlayClick: false
            });

            const contentDiv = document.createElement('div');
            contentDiv.classList.add('yss-modal-instructions');
            contentDiv.style.cssText = 'font-size: 1.5rem; border: none; border-radius: 0px; margin: calc(var(--yss-spacing-xl)*-1); display: flex; cursor: default; color: white; flex-direction: column; align-items: stretch; overflow: hidden; gap: 0;';

            const warningText = document.createTextNode('This script performs automated actions on YouTube that may violate YouTube\'s Terms of Service.');
            contentDiv.appendChild(warningText);
            contentDiv.appendChild(document.createElement('br'));
            contentDiv.appendChild(document.createElement('br'));

            const risksTitle = document.createTextNode('Risks include:');
            contentDiv.appendChild(risksTitle);

            const ul = document.createElement('ul');
            const risks = [
                'Account termination or suspension',
                'IP address blocking',
                'Legal action by YouTube',
                'Loss of channel access'
            ];
            risks.forEach(risk => {
                const li = document.createElement('li');
                li.textContent = risk;
                ul.appendChild(li);
            });
            contentDiv.appendChild(ul);

            contentDiv.appendChild(document.createElement('br'));
            const acknowledgeText = document.createTextNode('By continuing, you acknowledge these risks and agree to use this script at your own discretion.');
            contentDiv.appendChild(acknowledgeText);
            contentDiv.appendChild(document.createElement('br'));
            contentDiv.appendChild(document.createElement('br'));
            const safetyText = document.createTextNode('The script includes safety features like human-like delays and rate limiting, but cannot guarantee compliance.');
            contentDiv.appendChild(safetyText);

            modal.setContent(contentDiv);

            /* const buttonConfigs = {
                acknowledge: {
                    text: 'I Understand and Accept Risks',
                    classes: ['yss-btn', 'yss-btn-primary'],
                    position: 'right',
                    onClick: () => {
                        YSS.storage.set(TOS_WARNING_KEY, true);
                        modal.close();
                    }
                },
                cancel: {
                    text: 'Cancel',
                    classes: ['yss-btn', 'yss-btn-clear'],
                    position: 'left',
                    onClick: () => {
                        modal.close();
                        log('[ToS] User declined. Script functionality may be limited.', 'warn');
                    }
                }
            };
            setupModalButtons(modal, buttonConfigs); */

            const buttonConfigs = {
                acknowledge: {
                    text: 'I Understand and Accept Risks',
                    classes: ['yss-btn', 'yss-btn-primary'],
                    position: 'right',
                    handlers: {
                        onclick: () => {
                            YSS.storage.set(TOS_WARNING_KEY, true);
                            modal.close();
                        }
                    }
                },
                cancel: {
                    text: 'Cancel',
                    classes: ['yss-btn', 'yss-btn-clear'],
                    position: 'left',
                    handlers: {
                        onclick: () => {
                            modal.close();
                            log('[ToS] User declined. Script functionality may be limited.', 'warn');
                        }
                    }
                }
            };

            setupModalButtons(modal, buttonConfigs);

            modal.show();
        }
    }

    function initialize() {
        // Inject FontAwesome CSS
        injectFontAwesome();

        // ✅ SECURITY FIX: Show ToS warning on first run
        checkAndShowToSWarning();



        //new TooltipManager();
        tooltipManagerInstance = new TooltipManager();
        lightboxManagerInstance = new LightboxManager();


        applyConditionalDisplay();


        // --- DEBUG: Test sync system ---
        console.log('YSS: Initializing...');

        if (transcriptDownloaderState.autoFetch && window.location.href.includes('/watch?v=')) {
            log('[TranscriptDL] Auto-Fetch is enabled. Fetching transcript for current video...', 'info');
            // Use a small delay to ensure the page is ready
            setTimeout(onFetchTranscriptClick, 2000);
        }



        // --- Step 1: Always ensure the UI is created and updated ---
        // Role-based initialization
        const isFeedPage = window.location.hostname === 'www.youtube.com' &&
            window.location.pathname.startsWith('/feed/');

        if (window.location.hostname.includes('studio.youtube.com') ||
            (window.location.href.startsWith('https://www.youtube.com/') && !isFeedPage)) {
            // We are on YouTube Studio or YouTube (but not feed): Set up the full UI panel and listen for commands.
            if (!document.getElementById('yss-panel')) {
                createPanelUI();
            }
            observeUrlChanges();
            updateButtonStatesBasedOnURL();
            initializeStudioBridge(); // Activate listener for sync commands
        } else if (window.location.href.includes('satsea.io/video-calendar') || window.location.href.includes('video-calendar')) { // <-- CHANGE DOMAIN HERE TOO if needed
            initializeCalendarBridge();
        }
        // Note: Feed pages (youtube.com/feed/*) do NOT create panel UI - only History Manager toolbar
        /*  // Create the panel if it doesn't exist
         if (!document.getElementById('yss-panel')) {
             createPanelUI();
         } */
        const iconsOnlyEnabled = GM_getValue(GM_KEYS.iconsOnlyEnabled, false);
        if (iconsOnlyEnabled) {
            const modalObserver = new MutationObserver((mutationsList) => {
                for (const mutation of mutationsList) {
                    if (mutation.type === 'childList') {
                        mutation.addedNodes.forEach(node => {
                            // Check if the added node is an element and looks like one of our modals
                            if (node.nodeType === 1 && node.matches && (node.matches('.yss-modal-overlay') || node.querySelector('.yss-modal-content'))) {
                                const modalContent = node.querySelector ? node.querySelector('.yss-modal-content') : node;
                                if (modalContent && !modalContent.classList.contains('yss-buttons-notext')) {
                                    modalContent.classList.add('yss-buttons-notext');
                                    log('Applied icon-only mode to a dynamically added modal.');
                                }
                            }
                        });
                    }
                }
            });

            modalObserver.observe(document.body, {
                childList: true,
                subtree: true
            });

        }
        scanForPasswordInputs(document.body);

        // This observer watches for any new elements added to the page (like modals).
        // When a new element appears, it scans it for password inputs.
        const passwordObserver = new MutationObserver((mutationsList) => {
            for (const mutation of mutationsList) {
                if (mutation.type === 'childList') {
                    mutation.addedNodes.forEach(node => {
                        // We only care about actual HTML elements, not text nodes, etc.
                        if (node.nodeType === Node.ELEMENT_NODE) {
                            scanForPasswordInputs(node);
                        }
                    });
                }
            }
        });

        // Start observing the entire document for changes.
        passwordObserver.observe(document.body, { childList: true, subtree: true });

        // --- Mutation Observer Setup ---
        // Place this within your main application initialization logic

        const rangeProgressObserver = new MutationObserver(mutationsList => {
            for (const mutation of mutationsList) {
                if (mutation.type === 'childList') {
                    mutation.addedNodes.forEach(node => {
                        if (node.nodeType === 1) { // Only process element nodes
                            scanForRangeSlidersProgress(node);
                        }
                    });
                }
            }
        });

        rangeProgressObserver.observe(document.body, { childList: true, subtree: true });
        // Call this once when your script initializes
        initModalClassObserver();

        // Always observe URL changes
        observeUrlChanges();

        // Always update the button states based on the current URL
        // This will correctly enable/disable buttons but won't interfere with running processes
        updateButtonStatesBasedOnURL();

        // Load persistent log
        loadPersistentLog();

        // Load processed videos ONLY on YouTube Studio pages
        if (window.location.hostname.includes('studio.youtube.com')) {
            loadProcessedVideos();
            // Update progress counter on initialization (Studio only)
            updateProgressCounter();
        }

        // Load last pre-fetch data from GM storage
        loadLastPrefetchData();

        /* 4.  Kick-off when DOM is ready and FA font is actually loaded ------------- */
        const go = () => {
            if (!document.fonts.check('1em "Font Awesome 6 Free"')) {
                document.fonts.load('1em "Font Awesome 6 Free"').then(go);
                return;
            }
            replaceEmoji(document.body);

            /* optional: watch for future emoji inserted by the page */
            const obs = new MutationObserver(muts => {
                muts.forEach(m => {
                    // Filter out nodes that are already removed or not connected
                    m.addedNodes.forEach(node => {
                        // Only process nodes that are still in the DOM
                        // For text nodes, check parentNode; for element nodes, check isConnected
                        if (node && (
                            (node.nodeType === Node.TEXT_NODE && node.parentNode) ||
                            (node.nodeType === Node.ELEMENT_NODE && node.isConnected)
                        )) {
                            replaceEmoji(node);
                        }
                    });
                });
            });
            obs.observe(document.body, { childList: true, subtree: true });
        };

        if (document.readyState === 'loading')
            document.addEventListener('DOMContentLoaded', go);
        else
            go();

        // Ensure button text is correct on initialization
        if (disableAllNotifsBtn && !allNotifsDisablerState.isRunning) {
            disableAllNotifsBtn.smartButton.setText(' Disable Notifs');
            disableAllNotifsBtn.classList.remove('yss-btn-stop');
            disableAllNotifsBtn.classList.remove('yss-btn-stop');
            disableAllNotifsBtn.smartButton.setIcon('fa-solid fa-bell-slash');
        }

        // Check for auto-start processing on edit pages
        autoStartProcessing();

        // Always check for notification checkbox on video edit pages (if enabled) - ONLY on Studio
        if (window.location.hostname.includes('studio.youtube.com')) {
            const autoCheckEnabled = GM_getValue('yss_auto_check_enabled', false); // Default to enabled
            if (autoCheckEnabled && window.location.pathname.includes('/video/') && window.location.pathname.includes('/edit')) {
                log("[AutoCheck] On video edit page. Starting automatic notification check...", "info");
                // Small delay to ensure page is loaded
                setTimeout(() => {
                    checkNotificationCheckboxOnEditPage();
                }, 3000);
            }
        }


        // --- Step 2: Check for and continue any active automation tasks (ONLY on Studio) ---
        if (window.location.hostname.includes('studio.youtube.com')) {
            const currentUrl = window.location.href;
            const activeQueue = JSON.parse(GM_getValue(allNotifsDisablerState.storageKey, 'null'));

            if (activeQueue && activeQueue.length > 0 && allNotifsDisablerState.isRunning) {
                // If a queue exists with videos AND we're actually running, we are in the middle of the "Disable Notifs" process.
                if (disableAllNotifsBtn) {
                    if (disableAllNotifsBtn.smartButton) disableAllNotifsBtn.smartButton.setText('Stop');
                    disableAllNotifsBtn.classList.add('yss-btn-stop');
                }

                // Check if we're on an edit page and need to process it
                if (currentUrl.includes('/video/') && currentUrl.includes('/edit')) {
                    log("[AllNotifs] On edit page with active queue, starting processing...", "info");
                    // Small delay to ensure page is loaded
                    setTimeout(() => {
                        handleVideoEditPage();
                    }, 2000);
                }
            }
        }

        // Auto-start processing is disabled - user must manually trigger
        // autoStartProcessing();
        // --- Uploader Initialization ---
        // Check if this tab needs to continue an upload process
        initializeUploaderOnLoad();
    }


    console.log('YouTube Automation Panel Script Loaded. Waiting for page elements...');

    // Make downloader functions globally available
    window.clearCorruptedDownloaderData = clearCorruptedDownloaderData;
    window.showImportedFilesModal = showImportedFilesModal;
    window.loadImportedFilesFromStorage = loadImportedFilesFromStorage;
    window.clearImportedFilesFromStorage = clearImportedFilesFromStorage;
    window.debugDownloaderStorage = debugDownloaderStorage;
    window.clearPrefetchData = () => {
        bulkDownloaderState.lastPrefetchData = null;
        log("[Downloader] Pre-fetch data cleared manually", 'info');
        return true;
    };
    window.showPrefetchData = () => {
        if (hasPrefetchData()) {
            // Ensure importedFiles is always an array, even if it's undefined in the data
            const importedFiles = bulkDownloaderState.lastPrefetchData.importedFiles || [];
            showVideoComparisonModal(bulkDownloaderState.lastPrefetchData.videos, importedFiles);
        } else {
            alert('No pre-fetch data available.');
        }
    };




    // =================================================================================
    //       SECTION EXTRA: COMMUNICATION & SYNC LOGIC (THE NEW BRIDGE)
    // =================================================================================

    window.YSS_USERSCRIPT_PRESENT = true;
    window.dispatchEvent(new Event('yss_userscript_present'));

    const SYNC_COMMAND_KEY = 'YSS_SYNC_COMMAND';
    const SYNC_STATUS_KEY = 'YSS_SYNC_STATUS';
    const SYNC_DATA_KEY = 'YSS_SYNC_DATA';

    // This function runs ONLY on the Calendar page
    function initializeCalendarBridge() {
        console.log('YSS: Calendar Bridge Initialized. Ready for sync requests.');
        console.log('YSS: GM_setValue available:', typeof GM_setValue !== 'undefined');
        console.log('YSS: GM_getValue available:', typeof GM_getValue !== 'undefined');
        console.log('YSS: Current URL:', window.location.href);
        console.log('YSS: Is calendar page:', window.location.href.includes('satsea.io/video-calendar') || window.location.href.includes('video-calendar'));

        // 1. Listen for a request from the calendar page's button
        document.addEventListener('yss_request_scrape', () => {
            console.log('YSS: Received scrape request from page. Sending command...');
            // Tell the Studio tab to start, including which options to use (e.g., scrape time)
            GM_setValue(SYNC_COMMAND_KEY, {
                command: 'start',
                scrapeTime: true,
                timestamp: Date.now()
            });
            onCsvScraperStartStopClick(true);
        });

        GM_addValueChangeListener(SYNC_STATUS_KEY, (name, oldValue, newValue, remote) => {
            if (remote && newValue) {
                console.log('YSS: Received remote status update:', newValue);
                document.dispatchEvent(new CustomEvent('yss_status_update', {
                    detail: newValue
                }));
            }
        });

        // 3. Listen for the final data FROM the Studio tab
        GM_addValueChangeListener(SYNC_DATA_KEY, (name, oldValue, newValue, remote) => {
            if (remote && newValue && newValue.csvData) {
                console.log('YSS: Received final CSV data from Studio tab.');
                document.dispatchEvent(new CustomEvent('yss_data_ready', {
                    detail: newValue
                }));

                // Clean up the data key to prevent re-triggering on reload
                setTimeout(() => GM_setValue(SYNC_DATA_KEY, null), 500);
            }
        });


    }

    // This function runs ONLY on the YouTube Studio page
    function initializeStudioBridge() {
        // Studio Bridge initialized silently

        // Listen for the 'start' command from the calendar page
        GM_addValueChangeListener(SYNC_COMMAND_KEY, (name, oldValue, newValue, remote) => {
            if (remote && newValue && newValue.command === 'start') {
                console.log('YSS: Received "start" command from calendar page.');

                // Acknowledge the command
                GM_setValue(SYNC_STATUS_KEY, {
                    status: 'ack',
                    message: 'Command received. Starting scraper...'
                });

                // Find the panel UI elements
                const csvScrapeBtn = document.getElementById('yss-csv-scrape-btn');
                const csvTimeCb = document.getElementById('yss-csv-time-cb');
                if (!csvScrapeBtn || !csvTimeCb) {
                    console.error('YSS: Could not find UI elements to start scraper.');
                    GM_setValue(SYNC_STATUS_KEY, {
                        status: 'error',
                        message: 'Error: Could not find scraper UI on Studio page.'
                    });
                    return;
                }

                // Configure the scraper based on the command
                /*csvTimeCb.checked = newValue.scrapeTime === true;
                csvScraperState.scrapeTimeEnabled = newValue.scrapeTime === true;*/

                // Trigger the scraper process in 'sync' mode
                onCsvScraperStartStopClick(true); // Pass true for 'isSyncMode'
            }
        });


    }

